--
-- Name: _configurator_can_access_product("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."_configurator_can_access_product"("p_product_id" "uuid", "p_organization_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_uid uuid := auth.uid();
  v_visible boolean := false;
  v_product_in_org boolean := false;
BEGIN
  -- fail-closed: sem sessÃ£o
  IF v_uid IS NULL THEN
    RETURN false;
  END IF;

  -- inputs obrigatÃ³rios
  IF p_product_id IS NULL OR p_organization_id IS NULL THEN
    RETURN false;
  END IF;

  -- system admin bypass
  IF public.is_system_admin_user(v_uid) THEN
    -- ainda assim exigimos que o produto exista e esteja ligado Ã  org
    SELECT EXISTS (
      SELECT 1 FROM public.product_organizations
      WHERE product_id = p_product_id AND organization_id = p_organization_id
      UNION
      SELECT 1 FROM public.products
      WHERE id = p_product_id AND organization_id = p_organization_id
    ) INTO v_product_in_org;
    RETURN v_product_in_org;
  END IF;

  -- org tem de estar entre as visÃ­veis
  SELECT EXISTS (
    SELECT 1 FROM public.get_user_visible_org_ids(v_uid) g(id)
    WHERE g.id = p_organization_id
  ) INTO v_visible;

  IF NOT v_visible THEN
    RETURN false;
  END IF;

  -- produto tem de estar visÃ­vel na org via product_organizations OU products.organization_id
  SELECT EXISTS (
    SELECT 1 FROM public.product_organizations
    WHERE product_id = p_product_id AND organization_id = p_organization_id
    UNION
    SELECT 1 FROM public.products
    WHERE id = p_product_id AND organization_id = p_organization_id
  ) INTO v_product_in_org;

  RETURN v_product_in_org;
END;
$$;


--
-- Name: anew_entity_org_links_enforce_single_primary(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."anew_entity_org_links_enforce_single_primary"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
begin
  if NEW.is_primary then
    if exists (
      select 1 from public.anew_entity_org_links l
      where l.entity_id = NEW.entity_id and l.is_primary = true
        and (TG_OP = 'INSERT' or l.organization_id <> OLD.organization_id)
    ) then
      raise exception 'entity already has a primary org link';
    end if;
  end if;
  NEW.updated_at := now();
  return NEW;
end;
$$;


--
-- Name: anew_leads_search_text_trigger(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."anew_leads_search_text_trigger"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO ''
    AS $$
BEGIN
  NEW.search_text := (
    SELECT string_agg(value::text, ' ')
    FROM jsonb_each_text(coalesce(NEW.field_values, '{}'::jsonb))
  );
  RETURN NEW;
END;
$$;


--
-- Name: archive_activity("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."archive_activity"("_activity_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  INSERT INTO public.activities_archive
  SELECT *, now(), auth.uid()
  FROM public.activities
  WHERE id = _activity_id;
  
  DELETE FROM public.activities WHERE id = _activity_id;
  
  RETURN true;
EXCEPTION
  WHEN OTHERS THEN
    RETURN false;
END;
$$;


