--
-- Name: bootstrap_org_creator("uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."bootstrap_org_creator"("p_organization_id" "uuid", "p_organization_name" "text") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_auth_uid uuid := auth.uid();
  v_anew_user_id uuid;
  v_registration_origin text;
  v_has_perm boolean;
  v_creator_role_id uuid;
  v_org_admin_role_id uuid;
  v_all_permissions text[];
BEGIN
  IF v_auth_uid IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  SELECT id, registration_origin INTO v_anew_user_id, v_registration_origin
  FROM public.anew_users
  WHERE auth_user_id = v_auth_uid;

  IF v_anew_user_id IS NULL THEN
    RAISE EXCEPTION 'User profile not found';
  END IF;

  IF NOT EXISTS (
    SELECT 1 FROM public.anew_organizations
    WHERE id = p_organization_id
      AND (created_by = v_anew_user_id OR created_by = v_auth_uid)
  ) THEN
    RAISE EXCEPTION 'Not the creator of this organization';
  END IF;

  UPDATE public.anew_organizations
  SET created_by = v_anew_user_id
  WHERE id = p_organization_id
    AND created_by = v_auth_uid;

  v_has_perm := public.has_anew_permission(v_auth_uid, 'organizations.manage');

  IF v_registration_origin != 'self_registration' AND NOT v_has_perm THEN
    RAISE EXCEPTION 'Not authorized to bootstrap organization';
  END IF;

  SELECT array_agg(code) INTO v_all_permissions FROM public.anew_permissions;

  IF v_registration_origin = 'self_registration' THEN
    SELECT id INTO v_creator_role_id FROM public.anew_roles WHERE code = 'super_admin' AND organization_id IS NULL;
  END IF;

  INSERT INTO public.anew_roles (code, name, description, organization_id, is_system, is_default, can_sign_contracts, created_by)
  VALUES ('org_admin', 'Administrador', 'Administrador com todas as permissÃµes', p_organization_id, false, false, true, v_anew_user_id)
  ON CONFLICT DO NOTHING
  RETURNING id INTO v_org_admin_role_id;

  IF v_org_admin_role_id IS NULL THEN
    SELECT id INTO v_org_admin_role_id FROM public.anew_roles
    WHERE code = 'org_admin' AND organization_id = p_organization_id;
  END IF;

  INSERT INTO public.anew_roles (code, name, description, organization_id, is_system, is_default, can_sign_contracts, created_by)
  VALUES ('worker', 'Colaborador', 'Colaborador com permissÃµes bÃ¡sicas', p_organization_id, false, true, false, v_anew_user_id)
  ON CONFLICT DO NOTHING;

  INSERT INTO public.anew_roles (code, name, description, organization_id, is_system, is_default, can_sign_contracts, created_by)
  VALUES ('viewer', 'Visualizador', 'Apenas visualizaÃ§Ã£o', p_organization_id, false, false, false, v_anew_user_id)
  ON CONFLICT DO NOTHING;

  IF v_all_permissions IS NOT NULL AND v_org_admin_role_id IS NOT NULL THEN
    INSERT INTO public.anew_role_permissions (role_id, permission_code, created_by)
    SELECT v_org_admin_role_id, unnest(v_all_permissions), v_anew_user_id
    ON CONFLICT DO NOTHING;
  END IF;

  IF v_creator_role_id IS NULL THEN
    v_creator_role_id := v_org_admin_role_id;
  END IF;

  INSERT INTO public.anew_memberships (
    user_id, organization_id, role_id, status, relationship_type, join_method, accepted_at, created_by
  )
  VALUES (
    v_anew_user_id, p_organization_id, v_creator_role_id, 'active', 'MEMBER', 'created_org', now(), v_anew_user_id
  )
  ON CONFLICT DO NOTHING;

  RETURN jsonb_build_object('success', true, 'role_id', v_creator_role_id);
END;
$$;


--
-- Name: calculate_bundle_original_price("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."calculate_bundle_original_price"("p_bundle_id" "uuid") RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  total NUMERIC := 0;
  component RECORD;
  choice_group RECORD;
  item_price NUMERIC;
  min_choice_price NUMERIC;
  choice_component RECORD;
BEGIN
  -- Sum all required non-choice-group components (retail only)
  FOR component IN
    SELECT bc.product_id, bc.service_id, bc.quantity
    FROM bundle_components bc
    WHERE bc.bundle_id = p_bundle_id
      AND bc.is_optional = false
      AND bc.choice_group_id IS NULL
  LOOP
    IF component.product_id IS NOT NULL THEN
      SELECT pp.price INTO item_price
      FROM product_prices pp
      WHERE pp.product_id = component.product_id
        AND pp.price_type = 'retail'
        AND (pp.valid_from IS NULL OR pp.valid_from <= NOW())
        AND (pp.valid_to IS NULL OR pp.valid_to >= NOW())
      ORDER BY pp.created_at DESC
      LIMIT 1;
    ELSE
      SELECT sp.price INTO item_price
      FROM service_prices sp
      WHERE sp.service_id = component.service_id
        AND sp.price_type = 'retail'
        AND (sp.valid_from IS NULL OR sp.valid_from <= NOW())
        AND (sp.valid_to IS NULL OR sp.valid_to >= NOW())
      ORDER BY sp.created_at DESC
      LIMIT 1;
    END IF;

    total := total + COALESCE(item_price, 0) * COALESCE(component.quantity, 1);
  END LOOP;

  -- Add the cheapest retail option from each required choice group
  FOR choice_group IN
    SELECT bcg.id, bcg.min_selections
    FROM bundle_choice_groups bcg
    WHERE bcg.bundle_id = p_bundle_id
      AND bcg.is_required = true
      AND bcg.min_selections > 0
  LOOP
    min_choice_price := NULL;

    FOR choice_component IN
      SELECT bc.product_id, bc.service_id, bc.quantity
      FROM bundle_components bc
      WHERE bc.choice_group_id = choice_group.id
        AND bc.is_optional = false
    LOOP
      item_price := 0;

      IF choice_component.product_id IS NOT NULL THEN
        SELECT pp.price INTO item_price
        FROM product_prices pp
        WHERE pp.product_id = choice_component.product_id
          AND pp.price_type = 'retail'
          AND (pp.valid_from IS NULL OR pp.valid_from <= NOW())
          AND (pp.valid_to IS NULL OR pp.valid_to >= NOW())
        ORDER BY pp.created_at DESC
        LIMIT 1;
      ELSIF choice_component.service_id IS NOT NULL THEN
        SELECT sp.price INTO item_price
        FROM service_prices sp
        WHERE sp.service_id = choice_component.service_id
          AND sp.price_type = 'retail'
          AND (sp.valid_from IS NULL OR sp.valid_from <= NOW())
          AND (sp.valid_to IS NULL OR sp.valid_to >= NOW())
        ORDER BY sp.created_at DESC
        LIMIT 1;
      END IF;

      item_price := COALESCE(item_price, 0) * COALESCE(choice_component.quantity, 1);

      IF min_choice_price IS NULL OR item_price < min_choice_price THEN
        min_choice_price := item_price;
      END IF;
    END LOOP;

    IF min_choice_price IS NOT NULL THEN
      total := total + min_choice_price * choice_group.min_selections;
    END IF;
  END LOOP;

  RETURN total;
END;
$$;


--
-- Name: calculate_distance_km(numeric, numeric, numeric, numeric); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."calculate_distance_km"("lat1" numeric, "lng1" numeric, "lat2" numeric, "lng2" numeric) RETURNS numeric
    LANGUAGE "plpgsql" IMMUTABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  R decimal := 6371; -- Earth radius in km
  dlat decimal;
  dlng decimal;
  a decimal;
  c decimal;
BEGIN
  dlat := radians(lat2 - lat1);
  dlng := radians(lng2 - lng1);
  a := sin(dlat/2) * sin(dlat/2) + cos(radians(lat1)) * cos(radians(lat2)) * sin(dlng/2) * sin(dlng/2);
  c := 2 * atan2(sqrt(a), sqrt(1-a));
  RETURN R * c;
END;
$$;


--
-- Name: calculate_product_margin("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."calculate_product_margin"("p_product_id" "uuid") RETURNS TABLE("margin_percentage" numeric, "purchase_price" numeric, "retail_price" numeric, "margin_amount" numeric)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  WITH prices AS (
    SELECT 
      MAX(CASE WHEN price_type = 'purchase' THEN price END) as cost,
      MAX(CASE WHEN price_type = 'retail' THEN price END) as sale
    FROM product_prices
    WHERE product_id = p_product_id
      AND (valid_from IS NULL OR valid_from <= NOW())
      AND (valid_to IS NULL OR valid_to >= NOW())
  )
  SELECT 
    CASE 
      WHEN sale > 0 AND cost IS NOT NULL THEN 
        ROUND(((sale - cost) / sale * 100)::numeric, 2)
      ELSE 0
    END as margin_percentage,
    cost as purchase_price,
    sale as retail_price,
    CASE 
      WHEN sale IS NOT NULL AND cost IS NOT NULL THEN 
        ROUND((sale - cost)::numeric, 2)
      ELSE 0
    END as margin_amount
  FROM prices;
END;
$$;


