--
-- Name: can_see_entity("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."can_see_entity"("p_entity_id" "uuid", "p_auth_uid" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_visible uuid[];
  v_business_uid uuid;
begin
  if p_entity_id is null or p_auth_uid is null then return false; end if;
  select array(select public.get_user_visible_org_ids(p_auth_uid)) into v_visible;
  select id into v_business_uid from public.anew_users where auth_user_id = p_auth_uid limit 1;

  if v_business_uid is not null and exists (
    select 1 from public.anew_entities e where e.id = p_entity_id and e.created_by = v_business_uid
  ) then return true; end if;

  if exists (select 1 from public.anew_entity_org_links l
             where l.entity_id = p_entity_id and l.organization_id = ANY(v_visible)) then return true; end if;
  if exists (select 1 from public.anew_leads x
             where x.entity_id = p_entity_id and x.organization_id = ANY(v_visible)) then return true; end if;
  if exists (select 1 from public.anew_contacts x
             where x.entity_id = p_entity_id and x.organization_id = ANY(v_visible)) then return true; end if;
  if exists (select 1 from public.anew_clients x
             where x.entity_id = p_entity_id and x.organization_id = ANY(v_visible)) then return true; end if;
  if exists (select 1 from public.quotes x
             where x.entity_id = p_entity_id and x.organization_id = ANY(v_visible)) then return true; end if;
  if exists (select 1 from public.deals x
             where x.entity_id = p_entity_id and x.organization_id = ANY(v_visible)) then return true; end if;
  return false;
end;
$$;


