  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: check_schedule_conflict("uuid", timestamp with time zone, timestamp with time zone, "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."check_schedule_conflict"("p_resource_id" "uuid", "p_start" timestamp with time zone, "p_end" timestamp with time zone, "p_exclude_item_id" "uuid" DEFAULT NULL::"uuid") RETURNS boolean
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN EXISTS (
    SELECT 1 FROM public.schedule_items si
    JOIN public.schedule_item_assignees sia ON sia.item_id = si.id
    WHERE sia.resource_id = p_resource_id
      AND si.status NOT IN ('cancelled')
      AND (p_exclude_item_id IS NULL OR si.id != p_exclude_item_id)
      AND si.start_datetime < p_end
      AND si.end_datetime > p_start
  );
END;
$$;


--
-- Name: cleanup_duplicate_notifications(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."cleanup_duplicate_notifications"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count integer;
BEGIN
  WITH ranked AS (
    SELECT id,
           ROW_NUMBER() OVER (
             PARTITION BY type, entity_id, user_id
             ORDER BY created_at DESC
           ) as rn
    FROM notifications
    WHERE is_resolved = false AND is_dismissed = false
  )
  UPDATE notifications
  SET is_resolved = true, resolved_at = now(), resolved_reason = 'duplicate'
  WHERE id IN (SELECT id FROM ranked WHERE rn > 1);

  GET DIAGNOSTICS v_count = ROW_COUNT;
  RETURN v_count;
END;
$$;


--
-- Name: cleanup_orphan_notifications(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."cleanup_orphan_notifications"() RETURNS integer
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_count integer := 0;
  v_partial integer;
BEGIN
  -- ============================================================
  -- ACTION NOTIFICATIONS (action_overdue / action_due_today)
  -- These store anew_entities.id in entity_id, so we must look up
  -- via the entity_id column in CRM tables, scoped by org.
  -- Mark as orphan only if entity doesn't exist in ANY of the 3 tables for that org.
  -- ============================================================

  -- Action notifications for leads
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'lead'
    AND type IN ('action_overdue', 'action_due_today')
    AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM anew_leads
      WHERE anew_leads.entity_id = notifications.entity_id
        AND anew_leads.organization_id = notifications.organization_id
        AND anew_leads.status NOT IN ('converted', 'archived')
    );
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Action notifications for contacts
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'contact'
    AND type IN ('action_overdue', 'action_due_today')
    AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM anew_contacts
      WHERE anew_contacts.entity_id = notifications.entity_id
        AND anew_contacts.organization_id = notifications.organization_id
        AND anew_contacts.status != 'inactive'
    );
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Action notifications for clients
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'client'
    AND type IN ('action_overdue', 'action_due_today')
    AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM anew_clients
      WHERE anew_clients.entity_id = notifications.entity_id
        AND anew_clients.organization_id = notifications.organization_id
        AND anew_clients.status != 'inactive'
    );
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- ============================================================
  -- DAILY / DIRECT NOTIFICATIONS (lead_no_contact, contact_no_contact, etc.)
  -- These store the CRM table PK in entity_id, so we look up by id + org.
  -- ============================================================

  -- Leads (non-action)
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'lead'
    AND type NOT IN ('action_overdue', 'action_due_today')
    AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM anew_leads
      WHERE anew_leads.id = notifications.entity_id
        AND anew_leads.organization_id = notifications.organization_id
    );
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Contacts (non-action)
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'contact'
    AND type NOT IN ('action_overdue', 'action_due_today')
    AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM anew_contacts
      WHERE anew_contacts.id = notifications.entity_id
        AND anew_contacts.organization_id = notifications.organization_id
    );
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Clients (non-action)
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'client'
    AND type NOT IN ('action_overdue', 'action_due_today')
    AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (
      SELECT 1 FROM anew_clients
      WHERE anew_clients.id = notifications.entity_id
        AND anew_clients.organization_id = notifications.organization_id
    );
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- ============================================================
  -- PROPOSALS, CONTRACTS, QUOTES, DEALS â€” unchanged logic
  -- ============================================================

  -- Proposals
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'proposal' AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM proposals WHERE id = notifications.entity_id);
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Contracts
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'contract' AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM client_contracts WHERE id = notifications.entity_id);
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Quotes
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'quote' AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM quotes WHERE id = notifications.entity_id);
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Deals
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'entity_deleted'
  WHERE entity_type = 'deal' AND is_resolved = false
    AND entity_id IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM deals WHERE id = notifications.entity_id);
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  -- Action notifications referencing deleted interactions
  UPDATE notifications SET is_resolved = true, resolved_at = now(), resolved_reason = 'interaction_deleted'
  WHERE type IN ('action_overdue', 'action_due_today') AND is_resolved = false
    AND action_config->>'interaction_id' IS NOT NULL
    AND NOT EXISTS (SELECT 1 FROM entity_interactions WHERE id = (notifications.action_config->>'interaction_id')::uuid);
  GET DIAGNOSTICS v_partial = ROW_COUNT;
  v_count := v_count + v_partial;

  RETURN v_count;
END;
$$;


--
-- Name: clone_template_roles_for_company(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."clone_template_roles_for_company"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  template_role RECORD;
  new_role_id UUID;
BEGIN
  FOR template_role IN 
    SELECT r.id, r.nome, r.descricao, r.allowed_user_types, r.template_key
    FROM roles r
    WHERE r.is_template = TRUE 
      AND r.empresa_id IS NULL 
      AND r.tenant_id IS NULL 
      AND r.nome NOT IN ('SystemAdmin', 'TenantAdmin')
  LOOP
    INSERT INTO roles (
      nome, descricao, tipo, estado, empresa_id, tenant_id,
      allowed_user_types, is_template, template_id, template_key, created_by
    )
    VALUES (
      template_role.nome, template_role.descricao, 'company', 'ativo',
      NEW.id, NEW.tenant_id, template_role.allowed_user_types,
      FALSE, template_role.id, template_role.template_key, NEW.created_by
    )
    RETURNING id INTO new_role_id;
    
    INSERT INTO role_permissions (role_id, permission_id)
    SELECT new_role_id, rp.permission_id
    FROM role_permissions rp
    WHERE rp.role_id = template_role.id;
  END LOOP;
  
  IF NEW.tenant_id IS NOT NULL THEN
    FOR template_role IN 
      SELECT r.id, r.nome, r.descricao, r.allowed_user_types, r.template_key
      FROM roles r
      WHERE r.is_template = TRUE 
        AND r.empresa_id IS NULL 
        AND r.tenant_id = NEW.tenant_id
        AND r.nome != 'TenantAdmin'
    LOOP
      INSERT INTO roles (
        nome, descricao, tipo, estado, empresa_id, tenant_id,
        allowed_user_types, is_template, template_id, template_key, created_by
      )
      VALUES (
        template_role.nome, template_role.descricao, 'company', 'ativo',
        NEW.id, NEW.tenant_id, template_role.allowed_user_types,
        FALSE, template_role.id, template_role.template_key, NEW.created_by
      )
      RETURNING id INTO new_role_id;
      
      INSERT INTO role_permissions (role_id, permission_id)
      SELECT new_role_id, rp.permission_id
      FROM role_permissions rp
      WHERE rp.role_id = template_role.id;
    END LOOP;
  END IF;
  
  RETURN NEW;
END;
$$;


--
-- Name: create_company_base_roles("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."create_company_base_roles"("_company_id" "uuid", "_created_by" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  base_role RECORD;
  new_role_id UUID;
  existing_count INTEGER;
BEGIN
  -- Check if this company already has base roles (prevent duplicates)
  SELECT COUNT(*) INTO existing_count
  FROM roles r
  WHERE r.empresa_id = _company_id
    AND r.nome IN ('CompanyAdmin', 'BusinessUnitAdmin', 'BusinessAreaAdmin', 'Worker', 'Sales_Full', 'Viewer_Global');
  
  -- If company already has base roles, skip creation
  IF existing_count > 0 THEN
    RETURN;
  END IF;

  -- Define base roles to create for each company
  -- These are copied from the global template roles (roles without empresa_id and tenant_id)
  FOR base_role IN 
    SELECT r.id, r.nome, r.descricao, r.allowed_user_types
    FROM roles r
    WHERE r.empresa_id IS NULL 
      AND r.tenant_id IS NULL
      AND r.nome IN ('CompanyAdmin', 'BusinessUnitAdmin', 'BusinessAreaAdmin', 'Worker', 'Sales_Full', 'Viewer_Global')
  LOOP
    -- Create company-scoped version of this role (independent copy)
    INSERT INTO roles (nome, descricao, empresa_id, allowed_user_types)
    VALUES (
      base_role.nome,
      base_role.descricao,
      _company_id,
      base_role.allowed_user_types
    )
    RETURNING id INTO new_role_id;
    
    -- Copy all permissions from base role to the new company-scoped role
    -- Each company's role has its own independent permissions that can be customized
    INSERT INTO role_permissions (role_id, permission_id)
    SELECT new_role_id, rp.permission_id
    FROM role_permissions rp
    WHERE rp.role_id = base_role.id;
  END LOOP;
END;
$$;


--
-- Name: create_entity_with_contacts_and_roles("uuid", "jsonb", "jsonb", "jsonb", "jsonb", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."create_entity_with_contacts_and_roles"("p_organization_id" "uuid", "p_entity" "jsonb", "p_emails" "jsonb" DEFAULT '[]'::"jsonb", "p_phones" "jsonb" DEFAULT '[]'::"jsonb", "p_addresses" "jsonb" DEFAULT '[]'::"jsonb", "p_roles" "jsonb" DEFAULT '[]'::"jsonb", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entity_id uuid;
  v_email jsonb;
  v_phone jsonb;
  v_address jsonb;
  v_role jsonb;
  v_address_id uuid;
  v_address_key text;
  v_street text;
  v_postal text;
  v_city text;
BEGIN
  IF p_entity IS NULL OR p_entity = 'null'::jsonb THEN
    RAISE EXCEPTION 'p_entity is required';
  END IF;

  -- 1. Create the entity (cross-org, no organization_id column on this table)
  INSERT INTO public.anew_entities (
    type,
    status,
    display_name,
    first_name,
    last_name,
    created_by
  )
  VALUES (
    COALESCE(p_entity->>'type', 'person'),
    COALESCE(p_entity->>'status', 'active'),
    COALESCE(p_entity->>'display_name', 'Entity'),
    NULLIF(p_entity->>'first_name', ''),
    NULLIF(p_entity->>'last_name', ''),
    p_created_by
  )
  RETURNING id INTO v_entity_id;

  -- 2. Emails
  FOR v_email IN SELECT * FROM jsonb_array_elements(COALESCE(p_emails, '[]'::jsonb))
  LOOP
    IF COALESCE(v_email->>'email', '') <> '' THEN
      INSERT INTO public.anew_entity_emails (
        entity_id, email, email_type, is_primary, created_by
      ) VALUES (
        v_entity_id,
        lower(trim(v_email->>'email')),
        COALESCE(v_email->>'email_type', 'personal'),
        COALESCE((v_email->>'is_primary')::boolean, false),
        p_created_by
      );
    END IF;
  END LOOP;

  -- 3. Phones
  FOR v_phone IN SELECT * FROM jsonb_array_elements(COALESCE(p_phones, '[]'::jsonb))
  LOOP
    IF COALESCE(v_phone->>'phone_number', '') <> '' THEN
      INSERT INTO public.anew_entity_phones (
        entity_id, phone_number, phone_type, is_primary, created_by
      ) VALUES (
        v_entity_id,
        trim(v_phone->>'phone_number'),
        COALESCE(v_phone->>'phone_type', 'mobile'),
        COALESCE((v_phone->>'is_primary')::boolean, false),
        p_created_by
      );
    END IF;
  END LOOP;

  -- 4. Addresses
  FOR v_address IN SELECT * FROM jsonb_array_elements(COALESCE(p_addresses, '[]'::jsonb))
  LOOP
    v_street := NULLIF(trim(COALESCE(v_address->>'street', '')), '');
    v_postal := NULLIF(trim(COALESCE(v_address->>'postal_code', '')), '');
    v_city   := NULLIF(trim(COALESCE(v_address->>'city', '')), '');

    -- Defensive: skip placeholder/empty addresses inside the RPC too.
    IF v_street IS NULL OR v_postal IS NULL THEN
      CONTINUE;
    END IF;

    v_address_key := lower(concat_ws('|', v_street, v_postal, COALESCE(v_city, '')));

    INSERT INTO public.anew_addresses (
      address_key, street, number, postal_code, city, district, country, created_by
    ) VALUES (
      v_address_key,
      v_street,
      COALESCE(v_address->>'number', ''),
      v_postal,
      COALESCE(v_city, ''),
      v_address->>'district',
      COALESCE(v_address->>'country', 'PT'),
      p_created_by
    )
    RETURNING id INTO v_address_id;

    INSERT INTO public.anew_entity_addresses (
      entity_id, address_id, address_type, is_primary, created_by
    ) VALUES (
      v_entity_id,
      v_address_id,
      COALESCE(v_address->>'address_type', 'primary'),
      COALESCE((v_address->>'is_primary')::boolean, true),
      p_created_by
    );
  END LOOP;

  -- 5. Roles (require organization_id)
  IF p_organization_id IS NOT NULL THEN
    FOR v_role IN SELECT * FROM jsonb_array_elements(COALESCE(p_roles, '[]'::jsonb))
    LOOP
      IF COALESCE(v_role->>'role', '') <> '' THEN
        INSERT INTO public.anew_entity_roles (
          organization_id, entity_id, role, status,
          source_type, source_id, created_by
        ) VALUES (
          p_organization_id,
          v_entity_id,
          v_role->>'role',
          COALESCE(v_role->>'status', 'active'),
          v_role->>'source_type',
          NULLIF(v_role->>'source_id', '')::uuid,
          p_created_by
        )
        ON CONFLICT (organization_id, entity_id, role) DO NOTHING;
      END IF;
    END LOOP;
  END IF;

  RETURN v_entity_id;
END;
$$;


--
-- Name: create_initial_organization("text", "text", "text", "text", "text", "text", boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."create_initial_organization"("p_name" "text", "p_type" "text", "p_description" "text" DEFAULT NULL::"text", "p_status" "text" DEFAULT 'active'::"text", "p_sector" "text" DEFAULT NULL::"text", "p_phone" "text" DEFAULT NULL::"text", "p_is_fiscal" boolean DEFAULT false) RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_auth_uid uuid := auth.uid();
  v_business_user_id uuid;
  v_organization_id uuid := gen_random_uuid();
  v_entity_id uuid := gen_random_uuid();
  v_super_admin_role_id uuid;
BEGIN
  IF v_auth_uid IS NULL THEN
    RAISE EXCEPTION 'Not authenticated';
  END IF;

  IF nullif(btrim(p_name), '') IS NULL OR nullif(btrim(p_type), '') IS NULL THEN
    RAISE EXCEPTION 'Organization name and type are required';
  END IF;

  SELECT u.id
  INTO v_business_user_id
  FROM public.anew_users u
  WHERE u.auth_user_id = v_auth_uid
    AND u.registration_origin = 'self_registration'
    AND u.status = 'active';

  IF v_business_user_id IS NULL THEN
    RAISE EXCEPTION 'Only active self-registered users can create their first organization';
  END IF;

  PERFORM pg_advisory_xact_lock(hashtextextended(v_business_user_id::text, 0));

  IF EXISTS (
    SELECT 1
    FROM public.anew_memberships m
    WHERE m.user_id = v_business_user_id
      AND m.status = 'active'
  ) THEN
    RAISE EXCEPTION 'User already has an active organization membership';
  END IF;

  -- Serialize global role creation because anew_roles has no uniqueness constraint.
  PERFORM pg_advisory_xact_lock(hashtextextended('global-role:super_admin', 0));

  SELECT ar.id
  INTO v_super_admin_role_id
  FROM public.anew_roles ar
  WHERE ar.code = 'super_admin'
    AND ar.organization_id IS NULL
    AND ar.is_system = true
  LIMIT 1;

  IF v_super_admin_role_id IS NULL THEN
    INSERT INTO public.anew_roles (
      code,
      name,
      description,
      organization_id,
      is_system,
      is_default,
      can_sign_contracts,
      created_by
    )
    VALUES (
      'super_admin',
      'Super Admin',
      'Dono da organizaÃ§Ã£o - acesso total nas suas organizaÃ§Ãµes',
      NULL,
      true,
      false,
      true,
      v_business_user_id
    )
    RETURNING id INTO v_super_admin_role_id;
  END IF;

  INSERT INTO public.anew_entities (
    id, display_name, type, status, created_by
  )
  VALUES (
    v_entity_id, btrim(p_name), 'organization', 'active', v_business_user_id
  );

  INSERT INTO public.anew_organizations (
    id, name, type, description, status, sector, phone, is_fiscal, entity_id, created_by
  )
  VALUES (
    v_organization_id,
    btrim(p_name),
    btrim(p_type),
    nullif(btrim(p_description), ''),
    coalesce(nullif(btrim(p_status), ''), 'active'),
    nullif(btrim(p_sector), ''),
    nullif(btrim(p_phone), ''),
    coalesce(p_is_fiscal, false),
    v_entity_id,
    v_business_user_id
  );

  PERFORM public.bootstrap_org_creator(v_organization_id, btrim(p_name));

  IF NOT EXISTS (
    SELECT 1
    FROM public.anew_memberships m
    JOIN public.anew_roles ar ON ar.id = m.role_id
    WHERE m.user_id = v_business_user_id
      AND m.organization_id = v_organization_id
      AND m.status = 'active'
      AND ar.code = 'super_admin'
  ) THEN
    RAISE EXCEPTION 'Organization bootstrap did not assign super_admin membership';
  END IF;

  RETURN jsonb_build_object(
    'organization_id', v_organization_id,
    'entity_id', v_entity_id
  );
END;
$$;


--
-- Name: create_lead_entity_for_org("uuid", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."create_lead_entity_for_org"("p_organization_id" "uuid", "p_display_name" "text", "p_first_name" "text" DEFAULT NULL::"text", "p_last_name" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_auth_uid uuid := auth.uid();
  v_anew_user_id uuid;
  v_entity_id uuid;
  v_display_name text := NULLIF(BTRIM(p_display_name), '');
BEGIN
  IF v_auth_uid IS NULL THEN
    RAISE EXCEPTION 'Utilizador nÃ£o autenticado';
  END IF;

  IF p_organization_id IS NULL THEN
    RAISE EXCEPTION 'OrganizaÃ§Ã£o obrigatÃ³ria';
  END IF;

  IF v_display_name IS NULL THEN
    RAISE EXCEPTION 'Nome da entidade obrigatÃ³rio';
  END IF;

  SELECT id
    INTO v_anew_user_id
  FROM public.anew_users
  WHERE auth_user_id = v_auth_uid
  LIMIT 1;

  IF v_anew_user_id IS NULL THEN
    RAISE EXCEPTION 'Perfil de utilizador nÃ£o encontrado';
  END IF;

  IF NOT EXISTS (
    SELECT 1
    FROM public.get_user_visible_org_ids(v_auth_uid) AS visible(organization_id)
    WHERE visible.organization_id = p_organization_id
  ) THEN
    RAISE EXCEPTION 'Sem acesso Ã  organizaÃ§Ã£o selecionada';
  END IF;

  INSERT INTO public.anew_entities (
    type,
    status,
    display_name,
    created_by,
    first_name,
    last_name
  ) VALUES (
    'person',
    'active',
    v_display_name,
    v_anew_user_id,
    NULLIF(BTRIM(p_first_name), ''),
    NULLIF(BTRIM(p_last_name), '')
  )
  RETURNING id INTO v_entity_id;

  INSERT INTO public.anew_entity_org_links (entity_id, organization_id, is_primary)
  VALUES (v_entity_id, p_organization_id, true)
  ON CONFLICT (entity_id, organization_id) DO NOTHING;

  RETURN v_entity_id;
END;
$$;


--
-- Name: create_tenant_base_roles("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."create_tenant_base_roles"("_tenant_id" "uuid", "_created_by" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  template_role RECORD;
  new_role_id UUID;
BEGIN
  -- Clone TenantAdmin template for this tenant
  FOR template_role IN 
    SELECT r.id, r.nome, r.descricao, r.allowed_user_types, r.template_key
    FROM roles r
    WHERE r.is_template = true
      AND r.empresa_id IS NULL 
      AND r.tenant_id IS NULL
      AND r.nome = 'TenantAdmin'
  LOOP
    -- Check if already exists for this tenant
    IF NOT EXISTS (
      SELECT 1 FROM roles 
      WHERE nome = template_role.nome 
        AND tenant_id = _tenant_id 
        AND empresa_id IS NULL
        AND is_template = false
    ) THEN
      -- Create tenant-scoped version of this role
      INSERT INTO roles (nome, descricao, tenant_id, empresa_id, allowed_user_types, is_template, template_id, template_key, created_by)
      VALUES (
        template_role.nome,
        template_role.descricao,
        _tenant_id,
        NULL,
        template_role.allowed_user_types,
        false,
        template_role.id,
        template_role.template_key,
        _created_by
      )
      RETURNING id INTO new_role_id;
      
      -- Copy all permissions from template
      INSERT INTO role_permissions (role_id, permission_id)
      SELECT new_role_id, rp.permission_id
      FROM role_permissions rp
      WHERE rp.role_id = template_role.id;
    END IF;
  END LOOP;
END;
$$;


--
-- Name: current_business_user_id(); Type: FUNCTION; Schema: public; Owner: -
