  LIMIT 1
$$;


--
-- Name: delete_organization_subtree("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."delete_organization_subtree"("p_root_org_id" "uuid") RETURNS "uuid"[]
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_ids uuid[];
BEGIN
  IF p_root_org_id IS NULL THEN
    RAISE EXCEPTION 'root_org_id is required';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.anew_organizations WHERE id = p_root_org_id) THEN
    RAISE EXCEPTION 'Organization does not exist';
  END IF;

  WITH RECURSIVE subtree AS (
    SELECT p_root_org_id AS org_id
    UNION
    SELECT h.child_org_id
    FROM public.anew_hierarchy h
    JOIN subtree s ON h.parent_org_id = s.org_id
  )
  SELECT array_agg(org_id) INTO v_ids FROM subtree;

  DELETE FROM public.anew_hierarchy
  WHERE parent_org_id = ANY(v_ids)
     OR child_org_id = ANY(v_ids);

  DELETE FROM public.anew_organizations
  WHERE id = ANY(v_ids);

  RETURN v_ids;
END;
$$;


--
-- Name: documents_cleanup_on_entity_delete(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."documents_cleanup_on_entity_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_type TEXT := TG_ARGV[0];
BEGIN
  DELETE FROM public.documents
   WHERE entity_type = v_type AND entity_id = OLD.id;
  RETURN OLD;
END;
$$;


--
-- Name: documents_validate_entity(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."documents_validate_entity"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_org UUID;
BEGIN
  IF NEW.entity_type = 'contract' THEN
    SELECT organization_id INTO v_org FROM public.client_contracts WHERE id = NEW.entity_id;
  ELSIF NEW.entity_type = 'proposal' THEN
    SELECT organization_id INTO v_org FROM public.proposals WHERE id = NEW.entity_id;
  ELSIF NEW.entity_type = 'quote' THEN
    SELECT organization_id INTO v_org FROM public.quotes WHERE id = NEW.entity_id;
  ELSE
    RAISE EXCEPTION 'documents: entity_type invÃ¡lido %', NEW.entity_type;
  END IF;

  IF v_org IS NULL THEN
    RAISE EXCEPTION 'documents: % % nÃ£o existe', NEW.entity_type, NEW.entity_id;
  END IF;

  IF v_org <> NEW.organization_id THEN
    RAISE EXCEPTION 'documents: organization_id (%) nÃ£o corresponde Ã  entidade (%)',
      NEW.organization_id, v_org;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: duplicate_proposal("uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."duplicate_proposal"("source_proposal_id" "uuid", "new_title" "text" DEFAULT NULL::"text") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  new_proposal_id uuid;
  source_proposal public.proposals%ROWTYPE;
  default_stage_id uuid;
  v_business_user_id uuid;
BEGIN
  v_business_user_id := public.current_business_user_id();
  IF v_business_user_id IS NULL THEN
    RAISE EXCEPTION 'Business user not found for current auth user';
  END IF;

  SELECT * INTO source_proposal
  FROM public.proposals
  WHERE id = source_proposal_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Proposal not found';
  END IF;

  SELECT id INTO default_stage_id
  FROM public.proposal_workflow_stages
  WHERE (company_id = source_proposal.organization_id OR company_id IS NULL)
    AND is_active = true
  ORDER BY company_id NULLS LAST, stage_order
  LIMIT 1;

  INSERT INTO public.proposals (
    deal_id, title, description, value, status, valid_until,
    document_url, notes, created_by, company_id, client_id,
    organization_id, root_organization_id, entity_id,
    currency, stage_id, request_date
  )
  VALUES (
    source_proposal.deal_id,
    COALESCE(new_title, source_proposal.title || ' (CÃ³pia)'),
    source_proposal.description,
    source_proposal.value,
    'draft',
    source_proposal.valid_until,
    NULL,
    source_proposal.notes,
    v_business_user_id,
    source_proposal.company_id,
    source_proposal.client_id,
    source_proposal.organization_id,
    source_proposal.root_organization_id,
    source_proposal.entity_id,
    source_proposal.currency,
    default_stage_id,
    NULL
  )
  RETURNING id INTO new_proposal_id;

  INSERT INTO public.entity_change_log (entity_type, entity_id, company_id, action, changed_by, metadata)
  VALUES ('proposal', new_proposal_id, source_proposal.organization_id, 'duplicate', v_business_user_id,
    jsonb_build_object('source_id', source_proposal_id));

  RETURN new_proposal_id;
END;
$$;


--
-- Name: duplicate_quote("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."duplicate_quote"("source_quote_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  new_quote_id UUID;
  source_quote quotes%ROWTYPE;
  new_quote_number TEXT;
BEGIN
  -- Buscar orÃ§amento original
  SELECT * INTO source_quote FROM quotes WHERE id = source_quote_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Quote not found';
  END IF;
  
  -- Gerar novo nÃºmero de orÃ§amento
  SELECT 'ORC-' || TO_CHAR(NOW(), 'YYYYMMDD') || '-' || 
    LPAD((COALESCE(MAX(SUBSTRING(quote_number FROM '[0-9]+$')::INT), 0) + 1)::TEXT, 4, '0')
  INTO new_quote_number
  FROM quotes
  WHERE company_id = source_quote.company_id
    AND quote_number LIKE 'ORC-' || TO_CHAR(NOW(), 'YYYYMMDD') || '%';
  
  -- Criar novo orÃ§amento
  INSERT INTO quotes (
    cliente_id, company_id, business_unit_id, obra_endereco, obra_notas,
    modelo_base, desconto_global_percent, moeda, estado, created_by,
    quote_number, validade_dias, proposal_id, request_date
  )
  VALUES (
    source_quote.cliente_id,
    source_quote.company_id,
    source_quote.business_unit_id,
    source_quote.obra_endereco,
    source_quote.obra_notas,
    source_quote.modelo_base,
    source_quote.desconto_global_percent,
    source_quote.moeda,
    'rascunho',
    auth.uid(),
    new_quote_number,
    source_quote.validade_dias,
    source_quote.proposal_id,
    NULL -- Nova data de pedido
  )
  RETURNING id INTO new_quote_id;
  
  -- Copiar linhas do orÃ§amento
  INSERT INTO quote_lines (
    quote_id, produto_id, service_id, descricao_snapshot, qty, 
    preco_unitario_original, preco_unitario_final, desconto_percent,
    iva_percent, total_sem_iva, total_com_iva, ordem, unit_of_measure,
    product_attributes
  )
  SELECT 
    new_quote_id, produto_id, service_id, descricao_snapshot, qty,
    preco_unitario_original, preco_unitario_final, desconto_percent,
    iva_percent, total_sem_iva, total_com_iva, ordem, unit_of_measure,
    product_attributes
  FROM quote_lines
  WHERE quote_id = source_quote_id;
  
  -- Copiar taxas do orÃ§amento
  INSERT INTO quote_fees (
    quote_id, fee_type_id, name, description, calculation_type,
    percentage, fixed_amount, calculated_amount, is_included_in_total,
    sort_order
  )
  SELECT 
    new_quote_id, fee_type_id, name, description, calculation_type,
    percentage, fixed_amount, calculated_amount, is_included_in_total,
    sort_order
  FROM quote_fees
  WHERE quote_id = source_quote_id;
  
  -- Registar no log de alteraÃ§Ãµes
  INSERT INTO entity_change_log (entity_type, entity_id, company_id, action, changed_by, metadata)
  VALUES ('quote', new_quote_id, source_quote.company_id, 'duplicate', auth.uid(), 
    jsonb_build_object('source_id', source_quote_id));
  
  RETURN new_quote_id;
END;
$_$;


--
-- Name: ensure_entity_org_link("uuid", "uuid", boolean); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."ensure_entity_org_link"("p_entity_id" "uuid", "p_organization_id" "uuid", "p_is_primary" boolean DEFAULT false) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF p_entity_id IS NULL OR p_organization_id IS NULL THEN
    RAISE EXCEPTION 'entity_id and organization_id are required';
  END IF;

  -- Caller must have the target org within their visible scope.
  -- get_user_visible_org_ids already covers:
  --   * system_admin (returns all orgs)
  --   * direct memberships
  --   * hierarchy (ancestors + descendants)
  --   * cross-org associations
  IF NOT EXISTS (
    SELECT 1 FROM public.get_user_visible_org_ids(auth.uid()) v
    WHERE v = p_organization_id
  ) THEN
    RAISE EXCEPTION 'organization not in user scope';
  END IF;

  INSERT INTO anew_entity_org_links (entity_id, organization_id, is_primary)
  VALUES (p_entity_id, p_organization_id, COALESCE(p_is_primary, false))
  ON CONFLICT (entity_id, organization_id) DO NOTHING;
END;
$$;


--
-- Name: ensure_organization_entity_identity(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."ensure_organization_entity_identity"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_vat text;
  v_country text;
  v_fiscal_entity_id uuid;
  v_entity_id uuid;
BEGIN
  IF NEW.entity_id IS NOT NULL THEN
    RETURN NEW;
  END IF;

  v_vat := NULLIF(BTRIM(COALESCE(NEW.metadata->>'vat', NEW.metadata->>'nif')), '');
  v_country := COALESCE(NULLIF(BTRIM(NEW.metadata->>'country'), ''), 'PT');

  IF v_vat IS NOT NULL THEN
    SELECT fe.id
    INTO v_fiscal_entity_id
    FROM public.fiscal_entities fe
    WHERE fe.nif = v_vat
      AND fe.country_code = v_country
    LIMIT 1;

    IF v_fiscal_entity_id IS NOT NULL THEN
      SELECT ef.entity_id
      INTO v_entity_id
      FROM public.anew_entity_fiscal_entities ef
      WHERE ef.fiscal_entity_id = v_fiscal_entity_id
      LIMIT 1;
    END IF;
  END IF;

  IF v_entity_id IS NULL THEN
    INSERT INTO public.anew_entities (display_name, type, status, created_by)
    VALUES (NEW.name, 'organization', COALESCE(NEW.status, 'active'), NEW.created_by)
    RETURNING id INTO v_entity_id;
  END IF;

  NEW.entity_id := v_entity_id;
  RETURN NEW;
END;
$$;


--
-- Name: ensure_single_default_smtp(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."ensure_single_default_smtp"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.is_default = true THEN
    UPDATE public.user_smtp_settings
    SET is_default = false
    WHERE user_id = NEW.user_id
      AND id != NEW.id
      AND is_default = true;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: ensure_single_default_source(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."ensure_single_default_source"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.is_default = true THEN
    UPDATE public.campaign_sources 
    SET is_default = false 
    WHERE campaign_id = NEW.campaign_id 
      AND id != NEW.id 
      AND is_default = true;
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: find_entity_matches("uuid", "text", "text", "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."find_entity_matches"("p_org_id" "uuid", "p_email" "text" DEFAULT NULL::"text", "p_phone" "text" DEFAULT NULL::"text", "p_nif" "text" DEFAULT NULL::"text", "p_country_code" "text" DEFAULT 'PT'::"text") RETURNS TABLE("entity_id" "uuid", "scope" "text", "primary_org_id" "uuid", "primary_org_name" "text", "owner_org_accessible" boolean, "match_field" "text", "display_name" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_email text := nullif(btrim(lower(p_email)), '');
  v_nif text := nullif(btrim(p_nif), '');
  v_phone_digits text := nullif(regexp_replace(coalesce(p_phone,''), '[^0-9]', '', 'g'), '');
  v_country text := coalesce(nullif(btrim(p_country_code), ''), 'PT');
  v_visible uuid[];
  v_group uuid[];
begin
  if p_org_id is null then return; end if;
  if v_email is null and v_nif is null and (v_phone_digits is null or length(v_phone_digits) < 7) then
    return;
  end if;

  select array(select public.get_user_visible_org_ids(auth.uid())) into v_visible;
  select array(select public.get_org_group_ids(p_org_id)) into v_group;

  return query
  with candidates as (
    -- email match
    select ee.entity_id, 'email'::text as match_field
    from public.anew_entity_emails ee
    where v_email is not null and lower(ee.email) = v_email
    union
    -- nif match
    select aef.entity_id, 'nif'::text
    from public.anew_entity_fiscal_entities aef
    join public.fiscal_entities fe on fe.id = aef.fiscal_entity_id
    where v_nif is not null and fe.nif = v_nif and fe.country_code = v_country
    union
    -- phone match (suffix, min 7 digits)
    select ep.entity_id, 'phone'::text
    from public.anew_entity_phones ep
    where v_phone_digits is not null
      and length(regexp_replace(coalesce(ep.phone_number,''), '[^0-9]', '', 'g')) >= 7
      and (
        regexp_replace(coalesce(ep.phone_number,''), '[^0-9]', '', 'g') like '%' || v_phone_digits
        or v_phone_digits like '%' || regexp_replace(coalesce(ep.phone_number,''), '[^0-9]', '', 'g')
      )
  ),
  primaries as (
    select l.entity_id, l.organization_id as primary_org_id
    from public.anew_entity_org_links l
    where l.is_primary = true
  ),
  enriched as (
    select
      c.entity_id,
      c.match_field,
      p.primary_org_id,
      case
        when exists (select 1 from public.anew_entity_org_links l2
                     where l2.entity_id = c.entity_id and l2.organization_id = p_org_id)
          then 'same_org'
        when p.primary_org_id = ANY(v_group) and p.primary_org_id = ANY(v_visible)
          then 'group'
        else null
      end as scope
    from candidates c
    left join primaries p on p.entity_id = c.entity_id
  ),
  ranked as (
    select
      e.entity_id,
      e.scope,
      e.primary_org_id,
      e.match_field,
      row_number() over (
        partition by e.entity_id
        order by case e.scope when 'same_org' then 1 when 'group' then 2 else 3 end
      ) as rn
    from enriched e
    where e.scope is not null
  )
  select
    r.entity_id,
    r.scope,
    r.primary_org_id,
    org.name as primary_org_name,
    (r.primary_org_id = ANY(v_visible)) as owner_org_accessible,
    r.match_field,
    ent.display_name
  from ranked r
  left join public.anew_organizations org on org.id = r.primary_org_id
  left join public.anew_entities ent on ent.id = r.entity_id
  where r.rn = 1
  limit 50;
end;
$$;


--
-- Name: find_nearest_resources("uuid", "text", "date", integer, integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."find_nearest_resources"("p_board_id" "uuid", "p_target_postal_code" "text", "p_target_date" "date", "p_duration_minutes" integer DEFAULT 60, "p_limit" integer DEFAULT 10) RETURNS TABLE("resource_id" "uuid", "resource_name" "text", "resource_type" "text", "distance_km" numeric, "available_slots" "jsonb", "priority" integer)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_target_lat decimal;
  v_target_lng decimal;
  v_target_prefix varchar(4);
  v_board_org_id uuid;
BEGIN
  -- Get the organization_id from the board
  SELECT organization_id INTO v_board_org_id
  FROM schedule_boards
  WHERE id = p_board_id
  LIMIT 1;

  -- Extract prefix from target postal code
  v_target_prefix := LEFT(REPLACE(p_target_postal_code, '-', ''), 4);
  
  -- Get coordinates from postal_codes table (avg for the prefix)
  SELECT AVG(latitude), AVG(longitude) INTO v_target_lat, v_target_lng
  FROM postal_codes
  WHERE postal_code = v_target_prefix
    AND latitude IS NOT NULL;
  
  -- Fallback: try first 2 digits (e.g. 1050 -> 10xx)
  IF v_target_lat IS NULL THEN
    SELECT AVG(latitude), AVG(longitude) INTO v_target_lat, v_target_lng
    FROM postal_codes
    WHERE LEFT(postal_code, 2) = LEFT(v_target_prefix, 2)
      AND latitude IS NOT NULL;
  END IF;
  
  IF v_target_lat IS NULL THEN
    RETURN;
  END IF;
  
  RETURN QUERY
  WITH resource_best_distance AS (
    SELECT
      sr.id as res_id,
      sr.name as res_name,
      sr.resource_type as res_type,
      MIN(
        COALESCE(
          calculate_distance_km(
            v_target_lat, v_target_lng,
            pc.latitude,
            pc.longitude
          ),
          999999
        )
      ) as dist_km,
      MAX(COALESCE(rsa.priority, 1)) as res_priority,
      BOOL_OR(
        rsa.max_distance_km IS NOT NULL 
        AND calculate_distance_km(v_target_lat, v_target_lng, pc.latitude, pc.longitude) > rsa.max_distance_km
      ) as exceeds_max_distance
    FROM schedule_resources sr
    LEFT JOIN resource_service_areas rsa ON rsa.resource_id = sr.id AND rsa.is_active = true
    LEFT JOIN LATERAL (
      SELECT AVG(p.latitude) as latitude, AVG(p.longitude) as longitude
      FROM postal_codes p
      WHERE p.postal_code = rsa.postal_code_prefix
        AND p.latitude IS NOT NULL
    ) pc ON true
    WHERE sr.organization_id = v_board_org_id
      AND sr.is_active = true
    GROUP BY sr.id, sr.name, sr.resource_type
  ),
  resource_availability AS (
    SELECT 
      rd.res_id,
      rd.res_name,
      rd.res_type,
      rd.dist_km,
      rd.res_priority,
      rd.exceeds_max_distance,
      (
        SELECT jsonb_agg(jsonb_build_object('start', slot_start, 'end', slot_end))
        FROM get_resource_available_slots(rd.res_id, p_target_date, p_duration_minutes, v_board_org_id)
      ) as slots
    FROM resource_best_distance rd
    WHERE rd.exceeds_max_distance IS NOT TRUE
  )
  SELECT 
    ra.res_id,
    ra.res_name,
    ra.res_type,
    ra.dist_km,
    COALESCE(ra.slots, '[]'::jsonb) as available_slots,
    ra.res_priority
  FROM resource_availability ra
  WHERE ra.slots IS NOT NULL AND jsonb_array_length(ra.slots) > 0
  ORDER BY ra.res_priority DESC, ra.dist_km ASC, jsonb_array_length(ra.slots) DESC
  LIMIT p_limit;
END;
$$;


--
-- Name: fn_channel_revenue_facts(integer, "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."fn_channel_revenue_facts"("p_window_days" integer DEFAULT 90, "p_channel_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("contract_id" "uuid", "channel_id" "uuid", "attributed_revenue" numeric, "contract_date" timestamp with time zone)
    LANGUAGE "sql" STABLE
    SET "search_path" TO 'public'
    AS $$
  WITH params AS (
    SELECT GREATEST(COALESCE(p_window_days, 90), 0) AS w
  ),
  client_touches AS (
    -- universe of converted touches across ALL channels (no p_channel_id filter here)
    SELECT f.converted_to_client_id AS client_id, f.channel_id, f.touch_date
    FROM public.v_channel_lead_facts f
    WHERE f.is_converted
  ),
  contract_join AS (
    SELECT
      cc.id AS contract_id,
      COALESCE(cc.total_value, 0) AS total_value,
      cc.created_at AS contract_date,
      t.channel_id, t.touch_date
    FROM public.client_contracts cc
    JOIN client_touches t ON t.client_id = cc.client_id
    CROSS JOIN params
    WHERE cc.client_id IS NOT NULL
      AND cc.deleted_at IS NULL
      AND cc.status IN ('signed','active','expired')
      AND cc.total_value IS NOT NULL
      AND t.touch_date <= cc.created_at
      AND t.touch_date >= cc.created_at - (params.w || ' days')::interval
  ),
  ranked AS (
    SELECT *, row_number() OVER (
      PARTITION BY contract_id
      ORDER BY touch_date DESC, channel_id DESC
    ) AS rn
    FROM contract_join
  )
  SELECT contract_id, channel_id, total_value, contract_date
  FROM ranked
  WHERE rn = 1
    AND (p_channel_id IS NULL OR channel_id = p_channel_id);
$$;


--
-- Name: fn_pcb_org_consistency(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."fn_pcb_org_consistency"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE parent_org uuid;
BEGIN
  SELECT organization_id INTO parent_org FROM public.product_configuration_templates WHERE id = NEW.template_id;
  IF parent_org IS NULL THEN RAISE EXCEPTION 'Parent template not found for block'; END IF;
  IF NEW.organization_id IS NULL THEN
    NEW.organization_id := parent_org;
  ELSIF NEW.organization_id <> parent_org THEN
    RAISE EXCEPTION 'organization_id mismatch with parent template (got %, expected %)', NEW.organization_id, parent_org;
  END IF;
  RETURN NEW;
END;
$$;


