--
-- Name: generate_client_contract_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."generate_client_contract_number"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  year_part TEXT;
  sequence_num INTEGER;
BEGIN
  year_part := EXTRACT(YEAR FROM CURRENT_DATE)::TEXT;
  
  SELECT COALESCE(MAX(
    CASE 
      WHEN contract_number ~ '^CC-[0-9]{4}-[0-9]+$' 
      THEN (regexp_match(contract_number, '^CC-[0-9]{4}-([0-9]+)$'))[1]::INTEGER
      ELSE 0
    END
  ), 0) + 1
  INTO sequence_num
  FROM client_contracts
  WHERE contract_number LIKE 'CC-' || year_part || '-%';
  
  RETURN 'CC-' || year_part || '-' || LPAD(sequence_num::TEXT, 4, '0');
END;
$_$;


--
-- Name: generate_po_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."generate_po_number"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  year_part TEXT;
  sequence_num INTEGER;
  new_po_number TEXT;
BEGIN
  -- Get current year
  year_part := EXTRACT(YEAR FROM CURRENT_DATE)::TEXT;
  
  -- Get the next sequence number for this year
  SELECT COALESCE(MAX(
    CASE 
      WHEN order_number ~ '^PO-[0-9]{4}-[0-9]+$' 
      THEN (regexp_match(order_number, '^PO-[0-9]{4}-([0-9]+)$'))[1]::INTEGER
      ELSE 0
    END
  ), 0) + 1
  INTO sequence_num
  FROM purchase_orders
  WHERE order_number LIKE 'PO-' || year_part || '-%';
  
  -- Format: PO-YYYY-NNNN (e.g., PO-2025-0001)
  new_po_number := 'PO-' || year_part || '-' || LPAD(sequence_num::TEXT, 4, '0');
  
  RETURN new_po_number;
END;
$_$;


--
-- Name: generate_proposal_token(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."generate_proposal_token"() RETURNS "trigger"
    LANGUAGE "plpgsql"
    AS $$
BEGIN
  IF NEW.public_token IS NULL THEN
    -- Use replace to remove dashes from UUID and take first 32 chars
    NEW.public_token := replace(gen_random_uuid()::text, '-', '');
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: generate_quote_number(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."generate_quote_number"() RETURNS "text"
    LANGUAGE "plpgsql"
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  year_part TEXT;
  sequence_num INTEGER;
  new_quote_number TEXT;
BEGIN
  -- Get current year
  year_part := EXTRACT(YEAR FROM CURRENT_DATE)::TEXT;
  
  -- Get the next sequence number for this year
  SELECT COALESCE(MAX(
    CASE 
      WHEN quote_number ~ '^Q-[0-9]{4}-[0-9]+$' 
      THEN (regexp_match(quote_number, '^Q-[0-9]{4}-([0-9]+)$'))[1]::INTEGER
      ELSE 0
    END
  ), 0) + 1
  INTO sequence_num
  FROM quotes
  WHERE quote_number LIKE 'Q-' || year_part || '-%';
  
  -- Format: Q-YYYY-NNNN (e.g., Q-2025-0001)
  new_quote_number := 'Q-' || year_part || '-' || LPAD(sequence_num::TEXT, 4, '0');
  
  RETURN new_quote_number;
END;
$_$;


