--
-- Name: get_assignable_user_types("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_assignable_user_types"("_admin_user_id" "uuid") RETURNS "text"[]
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  admin_tipo text;
BEGIN
  SELECT tipo INTO admin_tipo FROM profiles WHERE id = _admin_user_id;
  
  CASE admin_tipo
    WHEN 'system_admin' THEN
      RETURN ARRAY['system_admin', 'tenant_admin', 'company_admin', 'business_unit_admin', 'business_area_admin', 'worker_user'];
    WHEN 'tenant_admin' THEN
      RETURN ARRAY['tenant_admin', 'company_admin', 'business_unit_admin', 'business_area_admin', 'worker_user'];
    WHEN 'company_admin' THEN
      RETURN ARRAY['company_admin', 'business_unit_admin', 'business_area_admin', 'worker_user'];
    WHEN 'business_unit_admin' THEN
      RETURN ARRAY[]::text[];
    WHEN 'business_area_admin' THEN
      RETURN ARRAY[]::text[];
    ELSE
      RETURN ARRAY[]::text[];
  END CASE;
END;
$$;


--
-- Name: get_attribute_price_with_context("uuid", "text", "uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_attribute_price_with_context"("p_attribute_id" "uuid", "p_value_option" "text", "p_organization_id" "uuid", "p_product_id" "uuid" DEFAULT NULL::"uuid", "p_context_code" "text" DEFAULT 'retail'::"text") RETURNS numeric
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_context_id UUID;
  v_price NUMERIC;
BEGIN
  SELECT id INTO v_context_id
  FROM price_contexts
  WHERE code = p_context_code
    AND is_active = true
    AND (organization_id IS NULL OR organization_id = p_organization_id)
  ORDER BY organization_id NULLS LAST
  LIMIT 1;

  IF p_context_code = 'purchase' THEN
    SELECT COALESCE(pavp.cost_impact, pavp.price) INTO v_price
    FROM product_attribute_value_prices pavp
    WHERE pavp.attribute_id = p_attribute_id
      AND pavp.value_option = p_value_option
      AND pavp.is_active = true
      AND (pavp.organization_id IS NULL OR pavp.organization_id = p_organization_id)
    ORDER BY
      CASE WHEN pavp.price_context_id = v_context_id THEN 0 ELSE 1 END,
      CASE WHEN pavp.product_id = p_product_id THEN 0 ELSE 1 END,
      pavp.organization_id NULLS LAST
    LIMIT 1;
  ELSE
    SELECT pavp.price INTO v_price
    FROM product_attribute_value_prices pavp
    WHERE pavp.attribute_id = p_attribute_id
      AND pavp.value_option = p_value_option
      AND pavp.is_active = true
      AND (pavp.organization_id IS NULL OR pavp.organization_id = p_organization_id)
    ORDER BY
      CASE WHEN pavp.price_context_id = v_context_id THEN 0 ELSE 1 END,
      CASE WHEN pavp.product_id = p_product_id THEN 0 ELSE 1 END,
      pavp.organization_id NULLS LAST
    LIMIT 1;
  END IF;

  RETURN COALESCE(v_price, 0);
END;
$$;


--
-- Name: get_bundle_available_stock("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_bundle_available_stock"("p_bundle_id" "uuid") RETURNS integer
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  min_available INTEGER := NULL;
  component RECORD;
  component_stock INTEGER;
BEGIN
  -- Only consider required components (not optional, not in choice groups)
  FOR component IN
    SELECT bc.product_id, bc.quantity
    FROM bundle_components bc
    WHERE bc.bundle_id = p_bundle_id
      AND bc.product_id IS NOT NULL
      AND bc.is_optional = false
      AND bc.choice_group_id IS NULL
  LOOP
    SELECT COALESCE(SUM(ps.qty_available - ps.qty_reserved), 0)::INTEGER INTO component_stock
    FROM product_stock ps
    WHERE ps.product_id = component.product_id;
    
    -- Calculate how many bundles can be made with this component
    component_stock := FLOOR(component_stock / component.quantity);
    
    IF min_available IS NULL OR component_stock < min_available THEN
      min_available := component_stock;
    END IF;
  END LOOP;
  
  RETURN COALESCE(min_available, 0);
END;
$$;


--
-- Name: get_category_attribute_options("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_category_attribute_options"("p_category_id" "uuid", "p_attribute_id" "uuid") RETURNS TABLE("value_text" "text", "display_name" "text", "hex_color" "text", "source" "text")
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  v_config category_attribute_palettes%ROWTYPE;
  v_additional jsonb;
  v_excluded jsonb;
  v_parent_id UUID;
BEGIN
  -- Get the category's configuration for this attribute
  SELECT * INTO v_config
  FROM category_attribute_palettes cap
  WHERE cap.category_id = p_category_id AND cap.attribute_id = p_attribute_id;
  
  -- If no config, try parent category before falling back to global
  IF NOT FOUND THEN
    SELECT COALESCE(pc.parent_category_id, pc.parent_id) INTO v_parent_id
    FROM product_categories pc
    WHERE pc.id = p_category_id;

    IF v_parent_id IS NOT NULL THEN
      -- Recurse to parent category
      RETURN QUERY
      SELECT * FROM get_category_attribute_options(v_parent_id, p_attribute_id);
      IF FOUND THEN RETURN; END IF;
    END IF;

    -- Final fallback: return nothing (let caller handle)
    RETURN;
  END IF;
  
  v_additional := COALESCE(v_config.additional_values, '[]'::jsonb);
  v_excluded := COALESCE(v_config.excluded_values, '[]'::jsonb);
  
  -- Return values from base group (if set) minus excluded, plus additional
  IF v_config.base_group_id IS NOT NULL THEN
    RETURN QUERY
    SELECT 
      gv.value_text::TEXT,
      COALESCE(gv.display_name, gv.value_text)::TEXT,
      gv.hex_color::TEXT,
      'base'::TEXT
    FROM attribute_option_group_values gv
    WHERE gv.group_id = v_config.base_group_id
      AND gv.is_active = true
      AND NOT (gv.value_text = ANY(SELECT jsonb_array_elements_text(v_excluded)))
    ORDER BY gv.sort_order, gv.value_text;
  END IF;
  
  -- Add additional values
  RETURN QUERY
  SELECT 
    (av->>'value')::TEXT,
    COALESCE((av->>'display_name')::TEXT, (av->>'value')::TEXT),
    (av->>'hex_color')::TEXT,
    'additional'::TEXT
  FROM jsonb_array_elements(v_additional) av;
END;
$$;


--
-- Name: get_channel_dashboard("uuid", "date", "date", "text", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_channel_dashboard"("p_channel_id" "uuid", "p_date_from" "date" DEFAULT NULL::"date", "p_date_to" "date" DEFAULT NULL::"date", "p_bucket" "text" DEFAULT 'day'::"text", "p_window_days" integer DEFAULT 90) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_from date := COALESCE(p_date_from, (CURRENT_DATE - INTERVAL '90 days')::date);
  v_to   date := COALESCE(p_date_to, CURRENT_DATE);
  v_bucket text := CASE p_bucket
    WHEN 'week'  THEN 'week'
    WHEN 'month' THEN 'month'
    WHEN 'year'  THEN 'year'
    ELSE 'day'
  END;
  v_window int := GREATEST(COALESCE(p_window_days, 90), 0);
  v_channel jsonb;
  v_campaign_id uuid;
  v_spend numeric := 0;
  v_spend_imported numeric := 0;
  v_leads int := 0;
  v_conversions int := 0;
  v_attributed_contracts int := 0;
  v_revenue numeric := 0;
  v_impressions bigint := 0;
  v_clicks bigint := 0;
  v_opens bigint := 0;
  v_bounces bigint := 0;
  v_summary jsonb;
  v_series jsonb;
  v_top_origins jsonb;
  v_unattributed jsonb;
BEGIN
  SELECT jsonb_build_object(
    'id', c.id, 'name', c.name, 'type', c.type,
    'campaign_id', c.campaign_id, 'campaign_name', ca.name,
    'is_active', c.is_active, 'description', c.description
  ), c.campaign_id
  INTO v_channel, v_campaign_id
  FROM channels c JOIN campaigns ca ON ca.id = c.campaign_id
  WHERE c.id = p_channel_id;

  IF v_channel IS NULL THEN
    RETURN jsonb_build_object('error', 'channel_not_found');
  END IF;

  -- Spend canÃ³nico: one-time + recurring expandido a partir de starts_on
  WITH spend_occ AS (
    SELECT cse.id, gs.occ::date AS occurrence_date, cse.amount
    FROM channel_spend_entries cse,
         LATERAL generate_series(
           cse.starts_on::timestamp,
           LEAST(COALESCE(cse.ends_on, v_to), v_to)::timestamp,
           (cse.interval_count || ' ' || cse.interval_unit)::interval
         ) AS gs(occ)
    WHERE cse.channel_id = p_channel_id
      AND cse.entry_type = 'recurring'
      AND cse.interval_count IS NOT NULL
      AND cse.interval_unit IS NOT NULL
      AND cse.starts_on <= v_to
      AND (cse.ends_on IS NULL OR cse.ends_on >= v_from)
      AND gs.occ::date BETWEEN v_from AND v_to
    UNION ALL
    SELECT cse.id, cse.starts_on AS occurrence_date, cse.amount
    FROM channel_spend_entries cse
    WHERE cse.channel_id = p_channel_id
      AND cse.entry_type = 'one_time'
      AND cse.starts_on BETWEEN v_from AND v_to
  )
  SELECT COALESCE(SUM(amount), 0) INTO v_spend FROM spend_occ;

  SELECT
    COUNT(*),
    COUNT(*) FILTER (WHERE f.is_converted)
  INTO v_leads, v_conversions
  FROM v_channel_lead_facts f
  WHERE f.channel_id = p_channel_id
    AND f.touch_date::date BETWEEN v_from AND v_to;

  SELECT
    COALESCE(SUM(attributed_revenue), 0),
    COUNT(*)
  INTO v_revenue, v_attributed_contracts
  FROM fn_channel_revenue_facts(v_window, p_channel_id) r
  WHERE r.contract_date::date BETWEEN v_from AND v_to;

  SELECT
    COALESCE(SUM(impressions), 0),
    COALESCE(SUM(clicks), 0),
    COALESCE(SUM(opens), 0),
    COALESCE(SUM(bounces), 0),
    COALESCE(SUM(spend), 0)
  INTO v_impressions, v_clicks, v_opens, v_bounces, v_spend_imported
  FROM channel_metrics
  WHERE channel_id = p_channel_id
    AND metric_date BETWEEN v_from AND v_to;

  v_summary := jsonb_build_object(
    'leads', v_leads,
    'conversions', v_conversions,
    'attributed_contracts_count', v_attributed_contracts,
    'revenue', v_revenue,
    'spend', v_spend,
    'spend_imported', v_spend_imported,
    'impressions', v_impressions,
    'clicks', v_clicks,
    'opens', v_opens,
    'bounces', v_bounces,
    'roas', CASE WHEN v_spend > 0 AND v_attributed_contracts > 0 THEN v_revenue / v_spend ELSE NULL END,
    'roi',  CASE WHEN v_spend > 0 AND v_attributed_contracts > 0 THEN (v_revenue - v_spend) / v_spend ELSE NULL END,
    'profit', CASE WHEN v_attributed_contracts > 0 THEN v_revenue - v_spend ELSE NULL END,
    'cpl', CASE WHEN v_leads > 0 THEN v_spend / v_leads ELSE NULL END,
    'cac', CASE WHEN v_conversions > 0 THEN v_spend / v_conversions ELSE NULL END
  );

  WITH leads_bucket AS (
    SELECT date_trunc(v_bucket, f.touch_date)::date AS bucket, COUNT(*) AS leads, COUNT(*) FILTER (WHERE f.is_converted) AS conversions
    FROM v_channel_lead_facts f
    WHERE f.channel_id = p_channel_id AND f.touch_date::date BETWEEN v_from AND v_to
    GROUP BY 1
  ),
  rev_bucket AS (
    SELECT date_trunc(v_bucket, r.contract_date)::date AS bucket, SUM(r.attributed_revenue) AS revenue
    FROM fn_channel_revenue_facts(v_window, p_channel_id) r
    WHERE r.contract_date::date BETWEEN v_from AND v_to
    GROUP BY 1
  ),
  spend_bucket AS (
    WITH occ AS (
      SELECT gs.occ::date AS d, cse.amount
      FROM channel_spend_entries cse,
           LATERAL generate_series(
             cse.starts_on::timestamp,
             LEAST(COALESCE(cse.ends_on, v_to), v_to)::timestamp,
             (cse.interval_count || ' ' || cse.interval_unit)::interval
           ) AS gs(occ)
      WHERE cse.channel_id = p_channel_id AND cse.entry_type='recurring'
        AND cse.interval_count IS NOT NULL AND cse.interval_unit IS NOT NULL
        AND cse.starts_on <= v_to AND (cse.ends_on IS NULL OR cse.ends_on >= v_from)
        AND gs.occ::date BETWEEN v_from AND v_to
      UNION ALL
      SELECT cse.starts_on, cse.amount FROM channel_spend_entries cse
      WHERE cse.channel_id = p_channel_id AND cse.entry_type='one_time'
        AND cse.starts_on BETWEEN v_from AND v_to
    )
    SELECT date_trunc(v_bucket, d)::date AS bucket, SUM(amount) AS spend FROM occ GROUP BY 1
  ),
  all_buckets AS (
    SELECT bucket FROM leads_bucket
    UNION SELECT bucket FROM rev_bucket
    UNION SELECT bucket FROM spend_bucket
  )
  SELECT COALESCE(jsonb_agg(jsonb_build_object(
    'bucket', ab.bucket,
    'leads', COALESCE(lb.leads, 0),
    'conversions', COALESCE(lb.conversions, 0),
    'revenue', COALESCE(rb.revenue, 0),
    'spend', COALESCE(sb.spend, 0)
  ) ORDER BY ab.bucket), '[]'::jsonb)
  INTO v_series
  FROM all_buckets ab
  LEFT JOIN leads_bucket lb ON lb.bucket = ab.bucket
  LEFT JOIN rev_bucket   rb ON rb.bucket = ab.bucket
  LEFT JOIN spend_bucket sb ON sb.bucket = ab.bucket;

  SELECT COALESCE(jsonb_agg(o ORDER BY (o->>'leads')::int DESC), '[]'::jsonb) INTO v_top_origins
  FROM (
    SELECT jsonb_build_object(
      'source', COALESCE(f.source,'(unknown)'),
      'medium', COALESCE(f.medium,'(unknown)'),
      'leads', COUNT(*),
      'conversions', COUNT(*) FILTER (WHERE f.is_converted),
      'revenue', 0,
      'revenue_note', 'not_attributed_per_origin'
    ) AS o
    FROM v_channel_lead_facts f
    WHERE f.channel_id = p_channel_id
      AND f.touch_date::date BETWEEN v_from AND v_to
    GROUP BY f.source, f.medium
    LIMIT 20
  ) sub;

  WITH dedup_un AS (
    SELECT DISTINCT COALESCE(cl.anew_lead_id, cl.id) AS lead_key
    FROM campaign_leads cl
    WHERE cl.channel_id IS NULL
      AND cl.campaign_id = v_campaign_id
      AND cl.created_at::date BETWEEN v_from AND v_to
  )
  SELECT jsonb_build_object('leads', COUNT(*)) INTO v_unattributed FROM dedup_un;

  RETURN jsonb_build_object(
    'channel', v_channel,
    'summary', v_summary,
    'series', v_series,
    'top_origins', v_top_origins,
    'unattributed', v_unattributed,
    'window', jsonb_build_object('from', v_from, 'to', v_to, 'bucket', v_bucket, 'window_days', v_window)
  );
END;
$$;


--
-- Name: get_commercial_info("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_commercial_info"("p_user_id" "uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_result jsonb;
  v_entity_id uuid;
  v_name text;
  v_email text;
  v_phone text;
BEGIN
  -- Try to find user by id or auth_user_id
  SELECT u.name, COALESCE(u.entity_id, u.id)
  INTO v_name, v_entity_id
  FROM public.anew_users u
  WHERE u.id = p_user_id OR u.auth_user_id = p_user_id
  LIMIT 1;

  IF v_name IS NULL THEN
    RETURN NULL;
  END IF;

  -- Get primary email
  SELECT e.email INTO v_email
  FROM public.anew_entity_emails e
  WHERE e.entity_id = v_entity_id AND e.is_primary = true
  LIMIT 1;

  -- Fallback: get any email
  IF v_email IS NULL THEN
    SELECT e.email INTO v_email
    FROM public.anew_entity_emails e
    WHERE e.entity_id = v_entity_id
    LIMIT 1;
  END IF;

  -- Get primary phone
  SELECT ep.phone_number INTO v_phone
  FROM public.anew_entity_phones ep
  WHERE ep.entity_id = v_entity_id AND ep.is_primary = true
  LIMIT 1;

  IF v_phone IS NULL THEN
    SELECT ep.phone_number INTO v_phone
    FROM public.anew_entity_phones ep
    WHERE ep.entity_id = v_entity_id
    LIMIT 1;
  END IF;

  -- Also try anew_users email/phone directly as fallback
  IF v_email IS NULL THEN
    SELECT u.email INTO v_email
    FROM public.anew_users u
    WHERE u.id = p_user_id OR u.auth_user_id = p_user_id
    LIMIT 1;
  END IF;

  IF v_phone IS NULL THEN
    SELECT u.phone INTO v_phone
    FROM public.anew_users u
    WHERE u.id = p_user_id OR u.auth_user_id = p_user_id
    LIMIT 1;
  END IF;

  RETURN jsonb_build_object(
    'name', v_name,
    'email', v_email,
    'phone', v_phone
  );
END;
$$;


--
-- Name: get_contact_alert_counts("uuid"[]); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_contact_alert_counts"("p_org_ids" "uuid"[]) RETURNS "jsonb"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH excluded_entities AS (
    SELECT DISTINCT entity_id FROM anew_entity_roles
    WHERE organization_id = ANY(p_org_ids)
      AND (
        (role = 'contact' AND status = 'inactive')
        OR (role = 'client' AND status = 'active')
      )
  ),
  active_contacts AS (
    SELECT c.entity_id, c.last_interaction_at, c.assigned_to, c.status
    FROM anew_contacts c
    WHERE c.organization_id = ANY(p_org_ids)
      AND c.entity_id NOT IN (SELECT entity_id FROM excluded_entities)
  ),
  active_only AS (
    SELECT * FROM active_contacts WHERE status = 'active'
  )
  SELECT jsonb_build_object(
    'total', (SELECT COUNT(*) FROM active_contacts),
    'active', (SELECT COUNT(*) FROM active_only),
    'inactive', (SELECT COUNT(*) FROM active_contacts WHERE status != 'active'),
    'no_contact_14d', COALESCE((
      SELECT COUNT(*) FROM active_only
      WHERE last_interaction_at IS NULL OR last_interaction_at < (now() - interval '14 days')
    ), 0),
    'no_contact_7d', COALESCE((
      SELECT COUNT(*) FROM active_only
      WHERE last_interaction_at IS NULL OR last_interaction_at < (now() - interval '7 days')
    ), 0),
    'no_deal', COALESCE((
      SELECT COUNT(*) FROM active_only ac2
      WHERE NOT EXISTS (
        SELECT 1 FROM deals d WHERE d.entity_id = ac2.entity_id
      )
    ), 0),
    'unassigned', COALESCE((
      SELECT COUNT(*) FROM active_only WHERE assigned_to IS NULL
    ), 0)
  );
$$;


--
-- Name: get_effective_price("uuid", "uuid", "public"."price_type"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_effective_price"("p_product_id" "uuid", "p_variant_id" "uuid" DEFAULT NULL::"uuid", "p_price_type" "public"."price_type" DEFAULT 'retail'::"public"."price_type") RETURNS TABLE("price" numeric, "currency" "public"."currency_code", "is_promotional" boolean)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT pp.price, pp.currency,
    (pp.price_type = 'promotional' AND 
     (pp.valid_from IS NULL OR pp.valid_from <= NOW()) AND
     (pp.valid_to IS NULL OR pp.valid_to >= NOW()))::BOOLEAN
  FROM product_prices pp
  WHERE ((p_variant_id IS NOT NULL AND pp.variant_id = p_variant_id) OR
         (p_variant_id IS NULL AND pp.product_id = p_product_id AND pp.variant_id IS NULL))
    AND pp.price_type = p_price_type
    AND (pp.valid_from IS NULL OR pp.valid_from <= NOW())
    AND (pp.valid_to IS NULL OR pp.valid_to >= NOW())
  ORDER BY CASE WHEN pp.price_type = 'promotional' THEN 0 ELSE 1 END, pp.created_at DESC
  LIMIT 1;
END;
$$;


--
-- Name: get_effective_stock("uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_effective_stock"("p_product_id" "uuid", "p_variant_id" "uuid" DEFAULT NULL::"uuid", "p_location_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("available_quantity" integer, "reserved_quantity" integer)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT 
    COALESCE(SUM(ps.qty_available), 0)::INTEGER,
    COALESCE(SUM(ps.qty_reserved), 0)::INTEGER
  FROM product_stock ps
  WHERE ((p_variant_id IS NOT NULL AND ps.variant_id = p_variant_id) OR
         (p_variant_id IS NULL AND ps.product_id = p_product_id AND ps.variant_id IS NULL))
    AND (p_location_id IS NULL OR ps.location_id = p_location_id);
END;
$$;


--
-- Name: get_flow_user_org_ids("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_flow_user_org_ids"("_auth_uid" "uuid") RETURNS SETOF "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  WITH RECURSIVE direct_orgs AS (
    SELECT m.organization_id
    FROM anew_memberships m
    JOIN anew_users u ON u.id = m.user_id
    WHERE u.auth_user_id = _auth_uid
      AND m.status = 'active'
  ),
  descendant_orgs AS (
    SELECT organization_id AS org_id FROM direct_orgs
    UNION
    SELECT h.child_org_id AS org_id
    FROM anew_hierarchy h
    JOIN descendant_orgs d ON h.parent_org_id = d.org_id
  )
  SELECT org_id FROM descendant_orgs;
$$;


--
-- Name: get_lead_dashboard_stats("uuid", timestamp with time zone, timestamp with time zone); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_lead_dashboard_stats"("p_org_id" "uuid", "p_date_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_date_to" timestamp with time zone DEFAULT NULL::timestamp with time zone) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  result jsonb;
  v_status_counts jsonb;
  v_source_counts jsonb;
  v_campaign_counts jsonb;
  v_daily_counts jsonb;
  v_total_leads bigint;
  v_leads_in_period bigint;
  v_converted_in_period bigint;
  v_assigned_counts jsonb;
  v_visits_scheduled bigint;
  v_leads_today bigint;
  v_cohort_conversions bigint;
  v_active_pipeline bigint;
BEGIN
  SELECT count(*) INTO v_total_leads
  FROM anew_leads
  WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
    AND deleted_at IS NULL
    AND converted_at IS NULL;

  v_active_pipeline := v_total_leads;

  SELECT coalesce(jsonb_object_agg(eff_status, cnt), '{}'::jsonb) INTO v_status_counts
  FROM (
    SELECT
      CASE
        WHEN converted_at IS NOT NULL THEN 'converted'
        WHEN scheduled_visit_id IS NOT NULL THEN 'visit_scheduled'
        WHEN lower(coalesce(status, '')) IN ('visit_scheduled', 'visita_agendada') THEN 'visit_scheduled'
        WHEN lower(coalesce(status, '')) IN ('new', 'novo', 'pending', 'pendente', '') THEN 'pending'
        WHEN lower(coalesce(status, '')) IN ('contacted', 'contactado') THEN 'contacted'
        WHEN lower(coalesce(status, '')) IN ('qualified', 'qualificado') THEN 'qualified'
        WHEN lower(coalesce(status, '')) IN ('no_answer', 'sem_resposta') THEN 'no_answer'
        WHEN lower(coalesce(status, '')) IN ('callback_scheduled', 'callback') THEN 'callback_scheduled'
        WHEN lower(coalesce(status, '')) IN ('lost', 'perdido') THEN 'lost'
        WHEN lower(coalesce(status, '')) IN ('rejected', 'rejeitado') THEN 'rejected'
        WHEN lower(coalesce(status, '')) IN ('incomplete', 'incompleto') THEN 'incomplete'
        ELSE lower(coalesce(status, 'pending'))
      END AS eff_status,
      count(*) AS cnt
    FROM anew_leads
    WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
      AND deleted_at IS NULL
      AND (p_date_from IS NULL OR created_at >= p_date_from)
      AND (p_date_to IS NULL OR created_at <= p_date_to)
    GROUP BY 1
  ) sub;

  SELECT count(*) INTO v_leads_in_period
  FROM anew_leads
  WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
    AND deleted_at IS NULL
    AND (p_date_from IS NULL OR created_at >= p_date_from)
    AND (p_date_to IS NULL OR created_at <= p_date_to);

  SELECT count(*) INTO v_converted_in_period
  FROM anew_leads
  WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
    AND deleted_at IS NULL
    AND converted_at IS NOT NULL
    AND (p_date_from IS NULL OR converted_at >= p_date_from)
    AND (p_date_to IS NULL OR converted_at <= p_date_to);

  SELECT count(*) INTO v_cohort_conversions
  FROM anew_leads
  WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
    AND deleted_at IS NULL
    AND converted_at IS NOT NULL
    AND (p_date_from IS NULL OR created_at >= p_date_from)
    AND (p_date_to IS NULL OR created_at <= p_date_to)
    AND (p_date_from IS NULL OR converted_at >= p_date_from)
    AND (p_date_to IS NULL OR converted_at <= p_date_to);

  SELECT count(*) INTO v_visits_scheduled
  FROM anew_leads
  WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
    AND deleted_at IS NULL
    AND (p_date_from IS NULL OR created_at >= p_date_from)
    AND (p_date_to IS NULL OR created_at <= p_date_to)
    AND (
      scheduled_visit_id IS NOT NULL
      OR lower(coalesce(status, '')) IN ('visit_scheduled', 'visita_agendada')
    );

  SELECT count(*) INTO v_leads_today
  FROM anew_leads
  WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
    AND deleted_at IS NULL
    AND (created_at AT TIME ZONE 'Europe/Lisbon')::date
        = (now() AT TIME ZONE 'Europe/Lisbon')::date;

  SELECT coalesce(jsonb_object_agg(coalesce(source, 'unknown'), cnt), '{}'::jsonb) INTO v_source_counts
  FROM (
    SELECT source, count(*) as cnt
    FROM anew_leads
    WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
      AND deleted_at IS NULL
      AND (p_date_from IS NULL OR created_at >= p_date_from)
      AND (p_date_to IS NULL OR created_at <= p_date_to)
    GROUP BY source
  ) sub;

  SELECT coalesce(jsonb_agg(jsonb_build_object('campaign_id', campaign_id, 'campaign_name', campaign_name, 'count', cnt)), '[]'::jsonb) INTO v_campaign_counts
  FROM (
    SELECT l.campaign_id, coalesce(c.name, 'Sem Campanha') as campaign_name, count(*) as cnt
    FROM anew_leads l
    LEFT JOIN campaigns c ON c.id = l.campaign_id
    WHERE (l.organization_id = p_org_id OR l.root_organization_id = p_org_id)
      AND l.deleted_at IS NULL
      AND (p_date_from IS NULL OR l.created_at >= p_date_from)
      AND (p_date_to IS NULL OR l.created_at <= p_date_to)
    GROUP BY l.campaign_id, c.name
    ORDER BY cnt DESC
  ) sub;

  SELECT coalesce(jsonb_agg(jsonb_build_object('date', d, 'count', cnt) ORDER BY d), '[]'::jsonb) INTO v_daily_counts
  FROM (
    SELECT (created_at AT TIME ZONE 'Europe/Lisbon')::date as d, count(*) as cnt
    FROM anew_leads
    WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
      AND deleted_at IS NULL
      AND (p_date_from IS NULL OR created_at >= p_date_from)
      AND (p_date_to IS NULL OR created_at <= p_date_to)
    GROUP BY d
  ) sub;

  SELECT coalesce(jsonb_object_agg(coalesce(assigned_to::text, 'unassigned'), cnt), '{}'::jsonb) INTO v_assigned_counts
  FROM (
    SELECT assigned_to, count(*) as cnt
    FROM anew_leads
    WHERE (organization_id = p_org_id OR root_organization_id = p_org_id)
      AND deleted_at IS NULL
      AND (p_date_from IS NULL OR created_at >= p_date_from)
      AND (p_date_to IS NULL OR created_at <= p_date_to)
    GROUP BY assigned_to
  ) sub;

  result := jsonb_build_object(
    'total_leads', v_total_leads,
    'active_pipeline', v_active_pipeline,
    'leads_in_period', v_leads_in_period,
    'converted_in_period', v_converted_in_period,
    'cohort_conversions', v_cohort_conversions,
    'visits_scheduled', v_visits_scheduled,
    'leads_today', v_leads_today,
    'status_counts', v_status_counts,
    'source_counts', v_source_counts,
    'campaign_counts', v_campaign_counts,
    'daily_counts', v_daily_counts,
    'assigned_counts', v_assigned_counts
  );

  RETURN result;
END;
$$;


--
-- Name: get_lead_status_counts("uuid", boolean, "text", "uuid", "uuid", "uuid", "uuid", boolean, "text", boolean, timestamp with time zone, timestamp with time zone, "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_lead_status_counts"("p_org_id" "uuid", "p_is_root" boolean DEFAULT false, "p_scope" "text" DEFAULT 'ALL'::"text", "p_anew_user_id" "uuid" DEFAULT NULL::"uuid", "p_auth_user_id" "uuid" DEFAULT NULL::"uuid", "p_campaign_id" "uuid" DEFAULT NULL::"uuid", "p_assigned_to" "uuid" DEFAULT NULL::"uuid", "p_assigned_unassigned" boolean DEFAULT false, "p_contact_result" "text" DEFAULT NULL::"text", "p_contact_result_none" boolean DEFAULT false, "p_date_from" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_date_to" timestamp with time zone DEFAULT NULL::timestamp with time zone, "p_search" "text" DEFAULT NULL::"text") RETURNS TABLE("status" "text", "count" bigint)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  RETURN QUERY
  SELECT
    effective_status AS status,
    COUNT(*)::bigint AS count
  FROM (
    SELECT
      CASE
        WHEN l.status = 'visit_scheduled' THEN 'visit_scheduled'
        WHEN l.scheduled_visit_id IS NOT NULL THEN 'visit_scheduled'
        WHEN l.last_contact_result IS NOT NULL AND (
          lower(replace(replace(l.last_contact_result, ' ', '_'), '-', '_')) IN ('visit_scheduled', 'visita_agendada')
          OR lower(replace(replace((
            SELECT lcr.name
            FROM public.lead_contact_results lcr
            WHERE lcr.id::text = l.last_contact_result
            LIMIT 1
          ), ' ', '_'), '-', '_')) IN ('visit_scheduled', 'visita_agendada')
        ) THEN 'visit_scheduled'
        ELSE COALESCE(l.status::text, 'new')
      END AS effective_status
    FROM public.anew_leads l
    WHERE (
        (p_is_root AND (l.root_organization_id = p_org_id OR l.organization_id = p_org_id))
        OR (NOT p_is_root AND l.organization_id = p_org_id)
      )
      AND l.status IS DISTINCT FROM 'converted'
      AND l.converted_to_contact_id IS NULL
      AND l.converted_at IS NULL
      AND (
        p_scope <> 'OWNED'
        OR p_anew_user_id IS NULL
        OR l.assigned_to = p_anew_user_id
        OR l.created_by = p_anew_user_id
        OR (p_auth_user_id IS NOT NULL AND l.created_by = p_auth_user_id)
      )
      AND (p_campaign_id IS NULL OR l.campaign_id = p_campaign_id)
      AND (
        (p_assigned_unassigned AND l.assigned_to IS NULL)
        OR (NOT p_assigned_unassigned AND (p_assigned_to IS NULL OR l.assigned_to = p_assigned_to))
      )
      AND (
        (p_contact_result_none AND l.last_contact_result IS NULL)
        OR (NOT p_contact_result_none AND (p_contact_result IS NULL OR l.last_contact_result = p_contact_result))
      )
      AND (p_date_from IS NULL OR l.created_at >= p_date_from)
      AND (p_date_to IS NULL OR l.created_at <= p_date_to)
      AND (p_search IS NULL OR l.search_text ILIKE '%' || p_search || '%')
  ) sub
  GROUP BY effective_status;
END;
$$;


--
-- Name: get_month_availability("uuid", "date", "date", integer, "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_month_availability"("p_board_id" "uuid", "p_start_date" "date", "p_end_date" "date", "p_duration_minutes" integer DEFAULT 60, "p_postal_code" "text" DEFAULT NULL::"text") RETURNS TABLE("available_date" "date", "has_slots" boolean)
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_org_id uuid;
  v_working_days INTEGER[];
  v_current_date date;
  v_day_of_week INTEGER;
  v_has_slots boolean;
BEGIN
  SELECT organization_id INTO v_org_id
  FROM schedule_boards
  WHERE id = p_board_id
  LIMIT 1;

  IF v_org_id IS NULL THEN
    RETURN;
  END IF;

  SELECT working_days INTO v_working_days
  FROM schedule_settings
  WHERE organization_id = v_org_id
  LIMIT 1;

  v_working_days := COALESCE(v_working_days, ARRAY[1,2,3,4,5]);

  v_current_date := p_start_date;
  WHILE v_current_date <= p_end_date LOOP
    v_day_of_week := EXTRACT(DOW FROM v_current_date);

    IF NOT (v_day_of_week = ANY(v_working_days)) THEN
      available_date := v_current_date;
      has_slots := false;
      RETURN NEXT;
      v_current_date := v_current_date + 1;
      CONTINUE;
    END IF;

    IF EXISTS (
      SELECT 1 FROM schedule_holidays
      WHERE (organization_id = v_org_id OR organization_id IS NULL)
        AND holiday_date = v_current_date
    ) THEN
      available_date := v_current_date;
      has_slots := false;
      RETURN NEXT;
      v_current_date := v_current_date + 1;
      CONTINUE;
    END IF;

    v_has_slots := false;

    IF p_postal_code IS NOT NULL AND p_postal_code != '' THEN
      IF EXISTS (
        SELECT 1 FROM find_nearest_resources(
          p_board_id, p_postal_code, v_current_date, p_duration_minutes, 1
        )
      ) THEN
        v_has_slots := true;
      END IF;
    ELSE
      IF EXISTS (
        SELECT 1 
        FROM schedule_resources sr
        CROSS JOIN LATERAL get_resource_available_slots(sr.id, v_current_date, p_duration_minutes, v_org_id) slots
        WHERE sr.organization_id = v_org_id AND sr.is_active = true
        LIMIT 1
      ) THEN
        v_has_slots := true;
      END IF;
    END IF;

    available_date := v_current_date;
    has_slots := v_has_slots;
    RETURN NEXT;

    v_current_date := v_current_date + 1;
  END LOOP;
END;
$$;


--
-- Name: get_org_group_ids("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_org_group_ids"("p_org_id" "uuid") RETURNS SETOF "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  with recursive
  ancestors as (
    select p_org_id as org_id
    union
    select h.parent_org_id
    from public.anew_hierarchy h
    join ancestors a on a.org_id = h.child_org_id
    where h.parent_org_id is not null
  ),
  roots as (
    select a.org_id from ancestors a
    where not exists (select 1 from public.anew_hierarchy h where h.child_org_id = a.org_id)
  ),
  descendants as (
    select org_id from roots
    union
    select h.child_org_id from public.anew_hierarchy h
    join descendants d on d.org_id = h.parent_org_id
  )
  select distinct org_id from descendants
  union select p_org_id;
$$;


--
-- Name: get_resource_available_slots("uuid", "date", integer, "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_resource_available_slots"("p_resource_id" "uuid", "p_date" "date", "p_duration_minutes" integer DEFAULT 60, "p_organization_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("slot_start" timestamp with time zone, "slot_end" timestamp with time zone)
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_day_of_week INTEGER;
  v_working_start TIME;
  v_working_end TIME;
  v_slot_start TIMESTAMPTZ;
  v_slot_end TIMESTAMPTZ;
  v_current_slot TIMESTAMPTZ;
  v_org_working_days INTEGER[];
  v_org_start TIME;
  v_org_end TIME;
BEGIN
  v_day_of_week := EXTRACT(DOW FROM p_date);

  -- P2: Check holidays â€” if this day is a holiday for the org, return nothing
  IF p_organization_id IS NOT NULL THEN
    IF EXISTS (
      SELECT 1 FROM public.schedule_holidays
      WHERE (organization_id = p_organization_id OR organization_id IS NULL)
        AND holiday_date = p_date
    ) THEN
      RETURN;
    END IF;
  END IF;

  -- P1: Load org settings for fallback
  IF p_organization_id IS NOT NULL THEN
    SELECT working_days, working_hours_start::TIME, working_hours_end::TIME
    INTO v_org_working_days, v_org_start, v_org_end
    FROM public.schedule_settings
    WHERE organization_id = p_organization_id
    LIMIT 1;

    -- Check if today is a non-working day per org settings
    IF v_org_working_days IS NOT NULL AND NOT (v_day_of_week = ANY(v_org_working_days)) THEN
      RETURN;
    END IF;
  END IF;

  -- Get working hours from resource rules
  SELECT start_time, end_time INTO v_working_start, v_working_end
  FROM public.resource_availability_rules
  WHERE resource_id = p_resource_id
    AND day_of_week = v_day_of_week
    AND is_available = true
    AND (valid_from IS NULL OR valid_from <= p_date)
    AND (valid_until IS NULL OR valid_until >= p_date)
  LIMIT 1;
  
  -- Fallback: org settings â†’ then hard defaults
  IF v_working_start IS NULL THEN
    v_working_start := COALESCE(v_org_start, '09:00'::TIME);
    v_working_end := COALESCE(v_org_end, '18:00'::TIME);
  END IF;
  
  -- Check if resource has time off
  IF EXISTS (
    SELECT 1 FROM public.resource_time_off
    WHERE resource_id = p_resource_id
      AND start_date <= p_date AND end_date >= p_date
      AND (all_day = true OR (start_time <= v_working_end AND end_time >= v_working_start))
  ) THEN
    RETURN;
  END IF;
  
  -- Generate slots and check conflicts
  v_current_slot := (p_date::TEXT || ' ' || v_working_start::TEXT)::TIMESTAMPTZ;
  
  WHILE v_current_slot + (p_duration_minutes || ' minutes')::INTERVAL <= (p_date::TEXT || ' ' || v_working_end::TEXT)::TIMESTAMPTZ LOOP
    v_slot_start := v_current_slot;
    v_slot_end := v_current_slot + (p_duration_minutes || ' minutes')::INTERVAL;
    
    IF NOT EXISTS (
      SELECT 1 FROM public.schedule_items si
      JOIN public.schedule_item_assignees sia ON sia.item_id = si.id
      WHERE sia.resource_id = p_resource_id
        AND si.status NOT IN ('cancelled')
        AND si.start_datetime < v_slot_end
        AND si.end_datetime > v_slot_start
    ) THEN
      slot_start := v_slot_start;
      slot_end := v_slot_end;
      RETURN NEXT;
    END IF;
    
    v_current_slot := v_current_slot + '30 minutes'::INTERVAL;
  END LOOP;
END;
$$;


--
-- Name: get_service_category_org_id("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_service_category_org_id"("cat_id" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE v_org_id UUID; v_parent_id UUID;
BEGIN
  SELECT organization_id, parent_id INTO v_org_id, v_parent_id FROM public.service_categories WHERE id = cat_id;
  IF v_org_id IS NOT NULL THEN RETURN v_org_id;
  ELSIF v_parent_id IS NOT NULL THEN RETURN get_service_category_org_id(v_parent_id);
  END IF;
  RETURN NULL;
END;
$$;


--
-- Name: get_user_context("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_user_context"("_auth_user_id" "uuid" DEFAULT "auth"."uid"()) RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_business_user_id uuid;
  v_is_system_admin boolean := false;
  v_org_ids uuid[] := ARRAY[]::uuid[];
  v_memberships jsonb := '[]'::jsonb;
  v_permissions text[] := ARRAY[]::text[];
  v_role_codes text[];
BEGIN
  IF _auth_user_id IS NULL THEN
    RETURN jsonb_build_object(
      'business_user_id', NULL,
      'is_system_admin', false,
      'org_ids', '[]'::jsonb,
      'memberships', '[]'::jsonb,
      'permissions', '[]'::jsonb
    );
  END IF;

  SELECT id INTO v_business_user_id
  FROM public.anew_users
  WHERE auth_user_id = _auth_user_id
  LIMIT 1;

  IF v_business_user_id IS NULL THEN
    RETURN jsonb_build_object(
      'business_user_id', NULL,
      'is_system_admin', false,
      'org_ids', '[]'::jsonb,
      'memberships', '[]'::jsonb,
      'permissions', '[]'::jsonb
    );
  END IF;

  SELECT
    COALESCE(jsonb_agg(jsonb_build_object(
      'organization_id', m.organization_id,
      'role_id', m.role_id,
      'role_code', r.code
    )), '[]'::jsonb),
    COALESCE(array_agg(DISTINCT r.code), ARRAY[]::text[])
  INTO v_memberships, v_role_codes
  FROM public.anew_memberships m
  JOIN public.anew_roles r ON r.id = m.role_id
  WHERE m.user_id = v_business_user_id
    AND m.status = 'active';

  v_is_system_admin := v_role_codes && ARRAY['system_admin','super_admin']::text[];

  -- HF1 FIX: WITH RECURSIVE for the ancestors CTE (self-reference required recursive keyword)
  WITH RECURSIVE ancestors AS (
    SELECT DISTINCT m.organization_id AS org_id
    FROM public.anew_memberships m
    WHERE m.user_id = v_business_user_id
      AND m.status = 'active'
    UNION
    SELECT h.parent_org_id
    FROM public.anew_hierarchy h
    JOIN ancestors a ON a.org_id = h.child_org_id
  )
  SELECT COALESCE(array_agg(DISTINCT org_id), ARRAY[]::uuid[])
  INTO v_org_ids
  FROM ancestors;

  IF v_is_system_admin THEN
    v_permissions := ARRAY['*'];
  ELSE
    SELECT COALESCE(array_agg(DISTINCT rp.permission_code), ARRAY[]::text[])
    INTO v_permissions
    FROM public.anew_role_permissions rp
    WHERE rp.role_id IN (
      SELECT DISTINCT m.role_id
      FROM public.anew_memberships m
      WHERE m.user_id = v_business_user_id
        AND m.status = 'active'
    );
  END IF;

  RETURN jsonb_build_object(
    'business_user_id', v_business_user_id,
    'is_system_admin', v_is_system_admin,
    'org_ids', to_jsonb(v_org_ids),
    'memberships', v_memberships,
    'permissions', to_jsonb(v_permissions)
  );
END;
$$;


--
-- Name: get_user_visible_org_ids("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."get_user_visible_org_ids"("_auth_uid" "uuid") RETURNS SETOF "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  -- If user is system_admin, return ALL organizations
  SELECT id FROM anew_organizations
  WHERE EXISTS (
    SELECT 1
    FROM anew_users au
    JOIN anew_memberships am ON am.user_id = au.id AND am.status = 'active'
    JOIN anew_roles ar ON ar.id = am.role_id
    WHERE au.auth_user_id = _auth_uid
      AND ar.code = 'system_admin'
  )

  UNION

  -- Normal visibility: direct orgs + descendants + ancestors + cross-associations
  SELECT organization_id FROM (
    WITH RECURSIVE direct_orgs AS (
      SELECT m.organization_id
      FROM anew_memberships m
      JOIN anew_users u ON u.id = m.user_id
      WHERE u.auth_user_id = _auth_uid
        AND m.status = 'active'
    ),
    descendant_orgs AS (
      SELECT organization_id FROM direct_orgs
      UNION
      SELECT h.child_org_id
      FROM anew_hierarchy h
      JOIN descendant_orgs d ON d.organization_id = h.parent_org_id
    ),
    ancestor_orgs AS (
      SELECT organization_id FROM direct_orgs
      UNION
      SELECT h.parent_org_id
      FROM anew_hierarchy h
      JOIN ancestor_orgs a ON a.organization_id = h.child_org_id
    ),
    hierarchy_orgs AS (
      SELECT organization_id FROM descendant_orgs
      UNION
      SELECT organization_id FROM ancestor_orgs
    ),
    expanded AS (
      SELECT organization_id FROM hierarchy_orgs
      UNION
      SELECT a.associated_org_id
      FROM anew_org_associations a
      JOIN hierarchy_orgs ho ON ho.organization_id = a.org_id
      UNION
      SELECT a.org_id
      FROM anew_org_associations a
      JOIN hierarchy_orgs ho ON ho.organization_id = a.associated_org_id
    )
    SELECT organization_id FROM expanded
  ) sub
  WHERE NOT EXISTS (
    SELECT 1
    FROM anew_users au
    JOIN anew_memberships am ON am.user_id = au.id AND am.status = 'active'
    JOIN anew_roles ar ON ar.id = am.role_id
    WHERE au.auth_user_id = _auth_uid
      AND ar.code = 'system_admin'
  );
$$;


--
-- Name: handle_employee_deletion(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."handle_employee_deletion"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_user_id UUID;
BEGIN
  -- Find if there's a user linked to this employee
  SELECT id INTO v_user_id FROM public.profiles WHERE employee_id = OLD.id;
  
  -- If a user exists, delete them from auth.users (which will cascade to profiles)
  IF v_user_id IS NOT NULL THEN
    -- Delete from auth.users - this will cascade delete the profile
    DELETE FROM auth.users WHERE id = v_user_id;
  END IF;
  
  RETURN OLD;
END;
$$;


--
-- Name: handle_new_user(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."handle_new_user"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_anew_user_id uuid;
  v_entity_id uuid;
  v_full_name text;
BEGIN
  v_full_name := COALESCE(NEW.raw_user_meta_data->>'full_name', 'New User');

  -- Create anew_users entry (idempotent â€” skip if already exists from edge function)
  INSERT INTO public.anew_users (auth_user_id, name, email, status, registration_origin)
  VALUES (
    NEW.id,
    v_full_name,
    COALESCE(NEW.email, ''),
    'active',
    'self_registration'
  )
  ON CONFLICT (auth_user_id) DO NOTHING;

  -- Get the anew_users id
  SELECT id INTO v_anew_user_id
  FROM public.anew_users
  WHERE auth_user_id = NEW.id;

  -- Only create entity if anew_user doesn't already have one
  IF v_anew_user_id IS NOT NULL THEN
    SELECT entity_id INTO v_entity_id
    FROM public.anew_users
    WHERE id = v_anew_user_id;

    IF v_entity_id IS NULL THEN
      -- Create anew_entity
      INSERT INTO public.anew_entities (type, display_name, first_name, status, created_by)
      VALUES ('person', v_full_name, v_full_name, 'active', v_anew_user_id)
      RETURNING id INTO v_entity_id;

      -- Create primary email for the entity
      INSERT INTO public.anew_entity_emails (entity_id, email, email_type, is_primary, is_verified)
      VALUES (v_entity_id, COALESCE(NEW.email, ''), 'personal', true, true);

      -- Link entity to anew_users
      UPDATE public.anew_users SET entity_id = v_entity_id WHERE id = v_anew_user_id;
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: has_anew_permission("uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."has_anew_permission"("_auth_uid" "uuid", "_permission_code" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM anew_users au
    JOIN anew_memberships am ON am.user_id = au.id AND am.status = 'active'
    JOIN anew_roles ar ON ar.id = am.role_id
    WHERE au.auth_user_id = _auth_uid
      AND (
        -- Admin roles bypass all permission checks
        ar.code IN ('system_admin', 'super_admin')
        -- Or explicit permission match
        OR EXISTS (
          SELECT 1 FROM anew_role_permissions arp
          WHERE arp.role_id = am.role_id
            AND arp.permission_code = _permission_code
        )
      )
  )
$$;


--
-- Name: has_permission("uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."has_permission"("_user_id" "uuid", "_permission_code" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_roles ur
    JOIN public.role_permissions rp ON ur.role_id = rp.role_id
    JOIN public.permissions p ON rp.permission_id = p.id
    WHERE ur.user_id = _user_id 
      AND p.codigo = _permission_code
  )
$$;


--
-- Name: has_role("uuid", "public"."app_role"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."has_role"("_user_id" "uuid", "_role" "public"."app_role") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_roles ur
    JOIN public.roles r ON ur.role_id = r.id
    WHERE ur.user_id = _user_id 
      AND (
        -- Map enum values to actual role names for backward compatibility
        (LOWER(_role::text) = 'admin' AND LOWER(r.nome) IN ('systemadmin', 'tenantadmin', 'companyadmin'))
        OR
        (LOWER(_role::text) = 'manager' AND LOWER(r.nome) LIKE '%admin%')
        OR  
        (LOWER(_role::text) = 'sales_rep' AND LOWER(r.nome) LIKE 'sales_%')
        OR
        (LOWER(_role::text) = 'viewer' AND LOWER(r.nome) LIKE '%view%')
        OR
        -- Also allow exact role name matches (case insensitive)
        LOWER(r.nome) = LOWER(_role::text)
      )
  )
$$;


--
-- Name: has_role_name("uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."has_role_name"("_user_id" "uuid", "_role_name" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.user_roles ur
    JOIN public.roles r ON ur.role_id = r.id
    WHERE ur.user_id = _user_id 
      AND LOWER(r.nome) = LOWER(_role_name)
  )
$$;


--
-- Name: has_scheduling_permission("uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."has_scheduling_permission"("user_id" "uuid", "permission_code" "text") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.anew_users au
    JOIN public.anew_memberships am ON am.user_id = au.id AND am.status = 'active'
    JOIN public.anew_roles ar ON ar.id = am.role_id
    LEFT JOIN public.anew_role_permissions arp
      ON arp.role_id = am.role_id
      AND arp.permission_code = has_scheduling_permission.permission_code
    WHERE au.auth_user_id = has_scheduling_permission.user_id
      AND (
        ar.code = 'system_admin'
        OR arp.permission_code IS NOT NULL
      )
  )
$$;


--
-- Name: increment_channel_metric_leads("uuid", "date", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."increment_channel_metric_leads"("p_channel_id" "uuid", "p_metric_date" "date", "p_delta" integer DEFAULT 1) RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
