    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM profiles 
    WHERE id = _user_id 
    AND tipo IN ('system_admin', 'tenant_admin', 'company_admin')
  );
$$;


--
-- Name: is_entity_in_user_scope("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."is_entity_in_user_scope"("_entity_id" "uuid", "_auth_uid" "uuid") RETURNS boolean
    LANGUAGE "sql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1 FROM anew_entities e
    WHERE e.id = _entity_id
      AND (
        e.created_by = _auth_uid
        OR EXISTS (
          SELECT 1 FROM anew_users au
          WHERE au.auth_user_id = _auth_uid AND e.created_by = au.id
        )
      )
  )
  OR EXISTS (
    SELECT 1 FROM anew_contacts c
    WHERE c.entity_id = _entity_id
      AND c.organization_id IN (SELECT get_user_visible_org_ids(_auth_uid))
  )
  OR EXISTS (
    SELECT 1 FROM anew_leads l
    WHERE l.entity_id = _entity_id
      AND l.organization_id IN (SELECT get_user_visible_org_ids(_auth_uid))
  )
  OR EXISTS (
    SELECT 1 FROM anew_clients cl
    WHERE cl.entity_id = _entity_id
      AND cl.organization_id IN (SELECT get_user_visible_org_ids(_auth_uid))
  )
  OR EXISTS (
    SELECT 1 FROM anew_organizations o
    WHERE o.entity_id = _entity_id
      AND o.id IN (SELECT get_user_visible_org_ids(_auth_uid))
  );
$$;


