--
-- Name: link_entity_to_org("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."link_entity_to_org"("p_entity_id" "uuid", "p_target_org_id" "uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
declare
  v_visible uuid[];
  v_primary_org uuid;
  v_group uuid[];
  v_business_uid uuid;
begin
  if p_entity_id is null or p_target_org_id is null then
    raise exception 'entity_id and target_org_id are required';
  end if;

  select array(select public.get_user_visible_org_ids(auth.uid())) into v_visible;
  if not (p_target_org_id = ANY(v_visible)) then
    raise exception 'target organization is not visible to current user';
  end if;

  select organization_id into v_primary_org
  from public.anew_entity_org_links
  where entity_id = p_entity_id and is_primary = true
  limit 1;

  if v_primary_org is null then
    raise exception 'entity has no primary organization';
  end if;

  select array(select public.get_org_group_ids(v_primary_org)) into v_group;
  if not (p_target_org_id = ANY(v_group)) then
    raise exception 'target organization is not in the same group as the entity primary org';
  end if;

  select id into v_business_uid from public.anew_users where auth_user_id = auth.uid() limit 1;

  insert into public.anew_entity_org_links (
    entity_id, organization_id, is_primary, shared_from_org_id, shared_by, shared_at
  ) values (
    p_entity_id, p_target_org_id, false, v_primary_org, v_business_uid, now()
  )
  on conflict (entity_id, organization_id) do nothing;
end;
$$;


