--
-- Name: log_client_contract_event(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."log_client_contract_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.client_contract_events (contract_id, event_type, description, new_values, created_by)
    VALUES (NEW.id, 'created', 'Contrato criado', to_jsonb(NEW), NEW.created_by);
  ELSIF TG_OP = 'UPDATE' THEN
    IF OLD.status IS DISTINCT FROM NEW.status THEN
      INSERT INTO public.client_contract_events (contract_id, event_type, description, old_values, new_values, created_by)
      VALUES (NEW.id, 'status_changed', 'Estado alterado de ' || OLD.status || ' para ' || NEW.status,
              jsonb_build_object('status', OLD.status),
              jsonb_build_object('status', NEW.status),
              auth.uid());
    END IF;
  END IF;
  RETURN COALESCE(NEW, OLD);
END;
$$;


