--
-- Name: log_schedule_item_event(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."log_schedule_item_event"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_business_user_id uuid;
BEGIN
  IF TG_OP = 'INSERT' THEN
    INSERT INTO public.schedule_item_events (item_id, event_type, description, new_values, created_by)
    VALUES (NEW.id, 'created', 'Item created', to_jsonb(NEW), NEW.created_by);
  ELSIF TG_OP = 'UPDATE' THEN
    v_business_user_id := public.current_business_user_id();

    IF v_business_user_id IS NULL THEN
      v_business_user_id := NEW.created_by;
    END IF;

    IF OLD.status IS DISTINCT FROM NEW.status THEN
      INSERT INTO public.schedule_item_events (item_id, event_type, description, old_values, new_values, created_by)
      VALUES (NEW.id, 'status_changed', 'Status changed from ' || OLD.status || ' to ' || NEW.status,
              jsonb_build_object('status', OLD.status),
              jsonb_build_object('status', NEW.status),
              v_business_user_id);
    END IF;
    
    IF OLD.start_datetime IS DISTINCT FROM NEW.start_datetime OR OLD.end_datetime IS DISTINCT FROM NEW.end_datetime THEN
      INSERT INTO public.schedule_item_events (item_id, event_type, description, old_values, new_values, created_by)
      VALUES (NEW.id, 'rescheduled', 'Item rescheduled',
              jsonb_build_object('start_datetime', OLD.start_datetime, 'end_datetime', OLD.end_datetime),
              jsonb_build_object('start_datetime', NEW.start_datetime, 'end_datetime', NEW.end_datetime),
              v_business_user_id);
    END IF;
  END IF;
  
  RETURN COALESCE(NEW, OLD);
END;
$$;


