--
-- Name: move_organization_node("uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."move_organization_node"("p_child_org_id" "uuid", "p_new_parent_org_id" "uuid", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_existing_child uuid;
BEGIN
  IF p_child_org_id IS NULL OR p_new_parent_org_id IS NULL THEN
    RAISE EXCEPTION 'child_org_id and new_parent_org_id are required';
  END IF;

  IF p_child_org_id = p_new_parent_org_id THEN
    RAISE EXCEPTION 'An organization cannot be its own parent';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.anew_organizations WHERE id = p_child_org_id) THEN
    RAISE EXCEPTION 'Child organization does not exist';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.anew_organizations WHERE id = p_new_parent_org_id) THEN
    RAISE EXCEPTION 'Parent organization does not exist';
  END IF;

  WITH RECURSIVE descendants AS (
    SELECT h.child_org_id
    FROM public.anew_hierarchy h
    WHERE h.parent_org_id = p_child_org_id
    UNION
    SELECT h.child_org_id
    FROM public.anew_hierarchy h
    JOIN descendants d ON h.parent_org_id = d.child_org_id
  )
  SELECT child_org_id INTO v_existing_child
  FROM descendants
  WHERE child_org_id = p_new_parent_org_id
  LIMIT 1;

  IF v_existing_child IS NOT NULL THEN
    RAISE EXCEPTION 'Move would create a hierarchy cycle';
  END IF;

  DELETE FROM public.anew_hierarchy
  WHERE child_org_id = p_child_org_id;

  INSERT INTO public.anew_hierarchy (
    parent_org_id,
    child_org_id,
    relationship_type,
    is_primary,
    created_by
  ) VALUES (
    p_new_parent_org_id,
    p_child_org_id,
    'parent_of',
    true,
    p_created_by
  );
END;
$$;


--
-- Name: portal_user_can_see_doc("text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."portal_user_can_see_doc"("_entity_type" "text", "_entity_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.client_portal_users cpu
    WHERE cpu.auth_user_id = auth.uid()
      AND (
        (_entity_type = 'contract' AND cpu.contract_id = _entity_id)
        OR (_entity_type = 'proposal' AND cpu.proposal_id = _entity_id)
        OR (_entity_type = 'quote'    AND cpu.quote_id    = _entity_id)
        OR (_entity_type = 'quote' AND EXISTS (
              SELECT 1 FROM public.quotes q
               WHERE q.id = _entity_id
                 AND q.proposal_id IS NOT NULL
                 AND q.proposal_id = cpu.proposal_id))
        OR (_entity_type = 'quote' AND EXISTS (
              SELECT 1 FROM public.client_contracts c
               WHERE c.id = cpu.contract_id
                 AND c.quote_id = _entity_id))
      )
  );
$$;


--
-- Name: portal_user_can_see_document("public"."portal_document_type", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."portal_user_can_see_document"("_doc_type" "public"."portal_document_type", "_doc_id" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM client_portal_documents d
    JOIN client_portal_users pu ON pu.id = d.portal_user_id
    WHERE pu.auth_user_id = auth.uid()
      AND d.document_type = _doc_type
      AND d.document_id   = _doc_id
      AND d.is_visible    = true
  );
$$;


--
-- Name: prevent_schedule_items_on_holidays(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."prevent_schedule_items_on_holidays"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_organization_id uuid;
  v_start_date date;
  v_end_date date;
  v_holiday_name text;
BEGIN
  IF NEW.status::text = 'cancelled' THEN
    RETURN NEW;
  END IF;

  v_organization_id := NEW.organization_id;

  IF v_organization_id IS NULL THEN
    SELECT sb.organization_id
      INTO v_organization_id
    FROM public.schedule_boards sb
    WHERE sb.id = NEW.board_id;
  END IF;

  IF v_organization_id IS NULL THEN
    v_organization_id := NEW.company_id;
  END IF;

  IF v_organization_id IS NULL THEN
    RETURN NEW;
  END IF;

  v_start_date := (NEW.start_datetime AT TIME ZONE 'Europe/Lisbon')::date;
  v_end_date := (NEW.end_datetime AT TIME ZONE 'Europe/Lisbon')::date;

  SELECT sh.name
    INTO v_holiday_name
  FROM public.schedule_holidays sh
  WHERE sh.organization_id = v_organization_id
    AND (
      (COALESCE(sh.is_recurring, false) = false AND sh.holiday_date BETWEEN v_start_date AND v_end_date)
      OR (
        COALESCE(sh.is_recurring, false) = true
        AND to_char(sh.holiday_date, 'MM-DD') BETWEEN to_char(v_start_date, 'MM-DD') AND to_char(v_end_date, 'MM-DD')
      )
    )
  ORDER BY sh.holiday_date
  LIMIT 1;

  IF v_holiday_name IS NOT NULL THEN
    RAISE EXCEPTION 'NÃ£o Ã© possÃ­vel criar ou alterar agendamentos em dia bloqueado/feriado: %', v_holiday_name
      USING ERRCODE = '23514';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: protect_system_role_permissions(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."protect_system_role_permissions"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_system boolean;
  v_role_id uuid;
BEGIN
  IF current_setting('request.jwt.claims', true)::jsonb->>'role' = 'service_role' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  v_role_id := COALESCE(NEW.role_id, OLD.role_id);
  SELECT is_system INTO v_is_system FROM public.anew_roles WHERE id = v_role_id;

  IF v_is_system = true THEN
    RAISE EXCEPTION 'PermissÃµes de roles de sistema nÃ£o podem ser modificadas'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: protect_system_roles(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."protect_system_roles"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  -- service_role bypass (edge functions, migrations)
  IF current_setting('request.jwt.claims', true)::jsonb->>'role' = 'service_role' THEN
    RETURN COALESCE(NEW, OLD);
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.is_system = true THEN
    RAISE EXCEPTION 'Roles de sistema nÃ£o podem ser modificadas (is_system=true)'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  IF TG_OP = 'DELETE' AND OLD.is_system = true THEN
    RAISE EXCEPTION 'Roles de sistema nÃ£o podem ser eliminadas (is_system=true)'
      USING ERRCODE = 'insufficient_privilege';
  END IF;

  RETURN COALESCE(NEW, OLD);
END;
$$;


--
-- Name: purge_business_entity("text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."purge_business_entity"("p_kind" "text", "p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entity_id uuid;
  v_org_id uuid;
  v_actor uuid := auth.uid();
  v_live_count int;
BEGIN
  IF p_kind NOT IN ('deal','quote','proposal','contract') THEN
    RAISE EXCEPTION 'Invalid kind: %', p_kind;
  END IF;

  IF p_kind = 'deal' THEN
    SELECT entity_id, organization_id INTO v_entity_id, v_org_id FROM public.deals WHERE id = p_id;

    -- bloqueio: nÃ£o permitir purge se houver quotes/proposals vivos ligados
    SELECT count(*) INTO v_live_count FROM public.quotes WHERE deal_id = p_id AND deleted_at IS NULL;
    IF v_live_count > 0 THEN
      RAISE EXCEPTION 'NÃ£o Ã© possÃ­vel eliminar definitivamente: existem % orÃ§amento(s) vivos ligados. Apague-os primeiro.', v_live_count;
    END IF;
    SELECT count(*) INTO v_live_count FROM public.proposals WHERE deal_id = p_id AND deleted_at IS NULL;
    IF v_live_count > 0 THEN
      RAISE EXCEPTION 'NÃ£o Ã© possÃ­vel eliminar definitivamente: existem % proposta(s) vivas ligadas. Apague-as primeiro.', v_live_count;
    END IF;

    -- purge filhos soft-deleted explicitamente (CASCADE trataria, mas queremos limpar tudo)
    DELETE FROM public.proposals WHERE deal_id = p_id; -- CASCADE em proposal_*
    DELETE FROM public.quotes WHERE deal_id = p_id;    -- CASCADE em quote_*
    DELETE FROM public.deals WHERE id = p_id;

  ELSIF p_kind = 'quote' THEN
    SELECT entity_id, organization_id INTO v_entity_id, v_org_id FROM public.quotes WHERE id = p_id;
    -- quote_lines, quote_fees, quote_documents jÃ¡ tÃªm ON DELETE CASCADE
    DELETE FROM public.quote_sends WHERE quote_id = p_id;
    DELETE FROM public.quotes WHERE id = p_id;

  ELSIF p_kind = 'proposal' THEN
    SELECT entity_id, organization_id INTO v_entity_id, v_org_id FROM public.proposals WHERE id = p_id;
    -- proposal_items, proposal_sends, proposal_access_tokens, proposal_deliveries, proposal_verification_codes tÃªm CASCADE
    DELETE FROM public.proposals WHERE id = p_id;

  ELSE -- contract
    SELECT entity_id, organization_id INTO v_entity_id, v_org_id FROM public.client_contracts WHERE id = p_id;
    -- contract_sends, client_contract_*, contract_documents tÃªm CASCADE
    DELETE FROM public.client_contracts WHERE id = p_id;
  END IF;

  IF v_entity_id IS NOT NULL THEN
    BEGIN
      INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
      VALUES (v_entity_id, 'purged', p_kind, p_id::text, NULL, v_actor,
              jsonb_build_object('kind', p_kind, 'id', p_id, 'organization_id', v_org_id));
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;

  RETURN TRUE;
END;
$$;


--
-- Name: purge_entity_facet("text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."purge_entity_facet"("p_kind" "text", "p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entity_id uuid; v_org_id uuid; v_role text;
  v_actor uuid := auth.uid();
BEGIN
  IF p_kind NOT IN ('lead','contact','client') THEN
    RAISE EXCEPTION 'Invalid kind: %', p_kind;
  END IF;
  v_role := p_kind;

  IF p_kind = 'lead' THEN
    SELECT entity_id, organization_id INTO v_entity_id, v_org_id FROM public.anew_leads WHERE id = p_id;
    DELETE FROM public.anew_leads WHERE id = p_id;
  ELSIF p_kind = 'contact' THEN
    SELECT entity_id, organization_id INTO v_entity_id, v_org_id FROM public.anew_contacts WHERE id = p_id;
    DELETE FROM public.anew_contacts WHERE id = p_id;
  ELSE
    SELECT entity_id, organization_id INTO v_entity_id, v_org_id FROM public.anew_clients WHERE id = p_id;
    DELETE FROM public.anew_clients WHERE id = p_id;
  END IF;

  IF v_entity_id IS NOT NULL THEN
    DELETE FROM public.anew_entity_roles
      WHERE entity_id = v_entity_id AND organization_id = v_org_id AND role = v_role;
    INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
    VALUES (v_entity_id, 'purged', v_role, p_id::text, NULL, v_actor,
            jsonb_build_object('kind', p_kind, 'id', p_id, 'organization_id', v_org_id));
  END IF;

  RETURN TRUE;
END;
$$;


--
-- Name: quotes_autofill_assigned_to(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."quotes_autofill_assigned_to"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_assigned uuid;
BEGIN
  IF NEW.assigned_to IS NOT NULL THEN
    RETURN NEW;
  END IF;

  IF NEW.deal_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT COALESCE(l.assigned_to, c.assigned_to, cl.assigned_to, d.assigned_to)
    INTO v_assigned
  FROM public.deals d
  LEFT JOIN public.anew_leads l ON l.id = d.lead_id
  LEFT JOIN public.anew_contacts c ON c.id = d.contact_id
  LEFT JOIN public.anew_clients cl ON cl.id = d.client_id
  WHERE d.id = NEW.deal_id;

  IF v_assigned IS NOT NULL THEN
    NEW.assigned_to := v_assigned;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: resolve_business_user_id("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."resolve_business_user_id"("p_auth_uid" "uuid") RETURNS "uuid"
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT business_user_id FROM public.auth_to_business_user_map
  WHERE auth_user_id = p_auth_uid LIMIT 1
$$;


--
-- Name: resolve_notifications_on_entity_delete(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."resolve_notifications_on_entity_delete"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE public.notifications
  SET is_resolved = true,
      resolved_at = now(),
      resolved_reason = 'entity_deleted'
  WHERE entity_id = OLD.id
    AND entity_type = TG_ARGV[0]
    AND is_resolved = false;
  RETURN OLD;
END;
$$;


--
-- Name: resolve_product_attribute_options("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."resolve_product_attribute_options"("p_product_id" "uuid", "p_attribute_id" "uuid") RETURNS TABLE("value_text" "text", "display_name" "text", "hex_color" "text", "price_addon" numeric, "is_available" boolean, "source" "text")
    LANGUAGE "plpgsql" STABLE
    AS $$
DECLARE
  v_category_id UUID;
  v_subcategory_id UUID;
  v_has_product_config BOOLEAN;
  v_palette_group_id UUID;
  v_price_category_id UUID;
  v_price_source TEXT;
  v_current_cat UUID;
  v_parent_cat UUID;
BEGIN
  -- Get product's category AND subcategory
  SELECT p.category_id, p.subcategory_id INTO v_category_id, v_subcategory_id
  FROM products p WHERE p.id = p_product_id;

  -- 1. Product-level overrides (highest priority)
  SELECT EXISTS(
    SELECT 1 FROM product_attribute_value_prices
    WHERE product_id = p_product_id AND attribute_id = p_attribute_id
  ) INTO v_has_product_config;

  IF v_has_product_config THEN
    RETURN QUERY
    SELECT
      pavp.value_option::TEXT,
      COALESCE(gv.display_name::TEXT, pavp.value_option::TEXT),
      gv.hex_color::TEXT,
      pavp.price,
      pavp.is_available,
      'product'::TEXT
    FROM product_attribute_value_prices pavp
    LEFT JOIN attribute_option_group_values gv
      ON gv.value_text = pavp.value_option
      AND gv.is_active = true
      AND gv.group_id = (
        SELECT aog2.id FROM attribute_option_groups aog2
        WHERE aog2.attribute_id = p_attribute_id
        ORDER BY aog2.created_at LIMIT 1
      )
    WHERE pavp.product_id = p_product_id
      AND pavp.attribute_id = p_attribute_id
    ORDER BY pavp.sort_order, pavp.value_option;
    RETURN;
  END IF;

  -- Resolve palette group: subcategory -> category -> first available
  IF v_subcategory_id IS NOT NULL THEN
    SELECT cap.base_group_id INTO v_palette_group_id
    FROM category_attribute_palettes cap
    WHERE cap.category_id = v_subcategory_id AND cap.attribute_id = p_attribute_id;
  END IF;

  IF v_palette_group_id IS NULL AND v_category_id IS NOT NULL THEN
    SELECT cap.base_group_id INTO v_palette_group_id
    FROM category_attribute_palettes cap
    WHERE cap.category_id = v_category_id AND cap.attribute_id = p_attribute_id;
  END IF;

  IF v_palette_group_id IS NULL THEN
    SELECT aog.id INTO v_palette_group_id
    FROM attribute_option_groups aog
    WHERE aog.attribute_id = p_attribute_id
    ORDER BY aog.created_at LIMIT 1;
  END IF;

  -- Find the closest ancestor (subcategory -> category -> ancestors) that HAS price overrides
  -- This walks up the hierarchy until it finds configured prices
  v_price_category_id := NULL;

  IF v_subcategory_id IS NOT NULL THEN
    IF EXISTS(
      SELECT 1 FROM product_attribute_value_prices
      WHERE category_id = v_subcategory_id AND product_id IS NULL AND attribute_id = p_attribute_id
    ) THEN
      v_price_category_id := v_subcategory_id;
      v_price_source := 'subcategory';
    END IF;
  END IF;

  IF v_price_category_id IS NULL AND v_category_id IS NOT NULL THEN
    -- Walk up from product's category through parent chain
    v_current_cat := v_category_id;
    WHILE v_current_cat IS NOT NULL LOOP
      IF EXISTS(
        SELECT 1 FROM product_attribute_value_prices
        WHERE category_id = v_current_cat AND product_id IS NULL AND attribute_id = p_attribute_id
      ) THEN
        v_price_category_id := v_current_cat;
        v_price_source := 'category';
        EXIT;
      END IF;

      SELECT COALESCE(pc.parent_category_id, pc.parent_id) INTO v_parent_cat
      FROM product_categories pc
      WHERE pc.id = v_current_cat;

      v_current_cat := v_parent_cat;
    END LOOP;
  END IF;

  -- If we found price overrides at some ancestor level, return values with those prices
  IF v_price_category_id IS NOT NULL AND v_palette_group_id IS NOT NULL THEN
    RETURN QUERY
    SELECT
      gv.value_text::TEXT,
      COALESCE(gv.display_name::TEXT, gv.value_text::TEXT),
      gv.hex_color::TEXT,
      COALESCE(pavp.price, 0::NUMERIC),
      COALESCE(pavp.is_available, true),
      v_price_source
    FROM attribute_option_group_values gv
    LEFT JOIN product_attribute_value_prices pavp
      ON pavp.value_option = gv.value_text
      AND pavp.category_id = v_price_category_id
      AND pavp.product_id IS NULL
      AND pavp.attribute_id = p_attribute_id
    WHERE gv.group_id = v_palette_group_id
      AND gv.is_active = true
    ORDER BY gv.sort_order, gv.value_text;
    IF FOUND THEN RETURN; END IF;
  END IF;

  -- No price overrides found anywhere: return palette via category hierarchy with price = 0
  IF v_subcategory_id IS NOT NULL THEN
    RETURN QUERY
    SELECT
      cao.value_text,
      cao.display_name,
      cao.hex_color,
      0::NUMERIC AS price_addon,
      true AS is_available,
      'subcategory_palette'::TEXT AS source
    FROM get_category_attribute_options(v_subcategory_id, p_attribute_id) cao;
    IF FOUND THEN RETURN; END IF;
  END IF;

  IF v_category_id IS NOT NULL THEN
    RETURN QUERY
    SELECT
      cao.value_text,
      cao.display_name,
      cao.hex_color,
      0::NUMERIC AS price_addon,
      true AS is_available,
      'category_palette'::TEXT AS source
    FROM get_category_attribute_options(v_category_id, p_attribute_id) cao;
    IF FOUND THEN RETURN; END IF;
  END IF;

  -- Final global fallback
  IF v_palette_group_id IS NOT NULL THEN
    RETURN QUERY
    SELECT
      gv.value_text::TEXT,
      COALESCE(gv.display_name::TEXT, gv.value_text::TEXT),
      gv.hex_color::TEXT,
      0::NUMERIC,
      true,
      'global'::TEXT
    FROM attribute_option_group_values gv
    WHERE gv.group_id = v_palette_group_id
      AND gv.is_active = true
    ORDER BY gv.sort_order, gv.value_text;
  END IF;
END;
$$;


--
-- Name: resolve_product_configuration("uuid", "uuid", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."resolve_product_configuration"("p_product_id" "uuid", "p_organization_id" "uuid", "p_price_context" "text" DEFAULT NULL::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_template record;
  v_price_context_id uuid := NULL;
  v_price_context_warning text := NULL;
  v_blocks jsonb := '[]'::jsonb;
  v_slots jsonb := '[]'::jsonb;
  v_options jsonb := '[]'::jsonb;
  v_rules jsonb := '[]'::jsonb;
BEGIN
  -- Gate
  IF NOT public._configurator_can_access_product(p_product_id, p_organization_id) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  -- Resolver price_context_id: estrito Ã  org passada, fallback global
  IF p_price_context IS NOT NULL AND length(trim(p_price_context)) > 0 THEN
    SELECT id INTO v_price_context_id
    FROM public.price_contexts
    WHERE code = p_price_context
      AND is_active = true
      AND (organization_id = p_organization_id OR organization_id IS NULL)
    ORDER BY (organization_id = p_organization_id) DESC
    LIMIT 1;

    IF v_price_context_id IS NULL THEN
      v_price_context_warning := 'price_context "' || p_price_context || '" nÃ£o encontrado nesta organizaÃ§Ã£o nem como global';
    END IF;
  END IF;

  -- Template ativo
  SELECT * INTO v_template
  FROM public.product_configuration_templates
  WHERE product_id = p_product_id
    AND organization_id = p_organization_id
    AND is_active = true
  ORDER BY version DESC
  LIMIT 1;

  IF v_template IS NULL THEN
    RETURN jsonb_build_object(
      'template', NULL,
      'blocks', '[]'::jsonb,
      'slots', '[]'::jsonb,
      'options', '[]'::jsonb,
      'rules', '[]'::jsonb,
      'price_context_id', v_price_context_id,
      'price_context_warning', v_price_context_warning,
      'organization_id', p_organization_id
    );
  END IF;

  -- Blocks
  SELECT COALESCE(jsonb_agg(to_jsonb(b) ORDER BY b.sort_order, b.created_at), '[]'::jsonb)
  INTO v_blocks
  FROM public.product_config_blocks b
  WHERE b.template_id = v_template.id;

  -- Slots
  SELECT COALESCE(jsonb_agg(to_jsonb(s) ORDER BY s.sort_order, s.created_at), '[]'::jsonb)
  INTO v_slots
  FROM public.product_config_slots s
  WHERE s.block_id IN (
    SELECT id FROM public.product_config_blocks WHERE template_id = v_template.id
  );

  -- Options
  SELECT COALESCE(jsonb_agg(to_jsonb(o) ORDER BY o.sort_order, o.created_at), '[]'::jsonb)
  INTO v_options
  FROM public.product_config_slot_options o
  WHERE o.slot_id IN (
    SELECT s.id FROM public.product_config_slots s
    WHERE s.block_id IN (
      SELECT id FROM public.product_config_blocks WHERE template_id = v_template.id
    )
  );

  -- Rules â€” desempate determinÃ­stico
  SELECT COALESCE(jsonb_agg(to_jsonb(r) ORDER BY r.priority ASC, r.created_at ASC, r.id ASC), '[]'::jsonb)
  INTO v_rules
  FROM public.product_config_rules r
  WHERE r.template_id = v_template.id
    AND r.is_active = true;

  RETURN jsonb_build_object(
    'template', to_jsonb(v_template),
    'blocks', v_blocks,
    'slots', v_slots,
    'options', v_options,
    'rules', v_rules,
    'price_context_id', v_price_context_id,
    'price_context_warning', v_price_context_warning,
    'organization_id', p_organization_id
  );
END;
$$;


--
-- Name: resolve_product_configuration("uuid", "uuid", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."resolve_product_configuration"("p_product_id" "uuid", "p_organization_id" "uuid", "p_price_context" "text" DEFAULT NULL::"text", "p_template_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_template record;
  v_price_context_id uuid := NULL;
  v_price_context_warning text := NULL;
  v_blocks jsonb := '[]'::jsonb;
  v_slots jsonb := '[]'::jsonb;
  v_options jsonb := '[]'::jsonb;
  v_rules jsonb := '[]'::jsonb;
BEGIN
  -- Gate
  IF NOT public._configurator_can_access_product(p_product_id, p_organization_id) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  -- Resolver price_context_id: estrito Ã  org passada, fallback global
  IF p_price_context IS NOT NULL AND length(trim(p_price_context)) > 0 THEN
    SELECT id INTO v_price_context_id
    FROM public.price_contexts
    WHERE code = p_price_context
      AND is_active = true
      AND (organization_id = p_organization_id OR organization_id IS NULL)
    ORDER BY (organization_id = p_organization_id) DESC
    LIMIT 1;

    IF v_price_context_id IS NULL THEN
      v_price_context_warning := 'price_context "' || p_price_context || '" nÃ£o encontrado nesta organizaÃ§Ã£o nem como global';
    END IF;
  END IF;

  -- Template: especÃ­fico (Lab) ou ativo (default)
  IF p_template_id IS NOT NULL THEN
    SELECT * INTO v_template
    FROM public.product_configuration_templates
    WHERE id = p_template_id
      AND product_id = p_product_id
      AND organization_id = p_organization_id
    LIMIT 1;

    IF v_template IS NULL THEN
      RETURN jsonb_build_object('error', 'invalid_template_for_product');
    END IF;
  ELSE
    SELECT * INTO v_template
    FROM public.product_configuration_templates
    WHERE product_id = p_product_id
      AND organization_id = p_organization_id
      AND is_active = true
    ORDER BY version DESC
    LIMIT 1;
  END IF;

  IF v_template IS NULL THEN
    RETURN jsonb_build_object(
      'template', NULL,
      'blocks', '[]'::jsonb,
      'slots', '[]'::jsonb,
      'options', '[]'::jsonb,
      'rules', '[]'::jsonb,
      'price_context_id', v_price_context_id,
      'price_context_warning', v_price_context_warning,
      'organization_id', p_organization_id
    );
  END IF;

  -- Blocks
  SELECT COALESCE(jsonb_agg(to_jsonb(b) ORDER BY b.sort_order, b.created_at), '[]'::jsonb)
  INTO v_blocks
  FROM public.product_config_blocks b
  WHERE b.template_id = v_template.id;

  -- Slots
  SELECT COALESCE(jsonb_agg(to_jsonb(s) ORDER BY s.sort_order, s.created_at), '[]'::jsonb)
  INTO v_slots
  FROM public.product_config_slots s
  WHERE s.block_id IN (
    SELECT id FROM public.product_config_blocks WHERE template_id = v_template.id
  );

  -- Options
  SELECT COALESCE(jsonb_agg(to_jsonb(o) ORDER BY o.sort_order, o.created_at), '[]'::jsonb)
  INTO v_options
  FROM public.product_config_slot_options o
  WHERE o.slot_id IN (
    SELECT s.id FROM public.product_config_slots s
    WHERE s.block_id IN (
      SELECT id FROM public.product_config_blocks WHERE template_id = v_template.id
    )
  );

  -- Rules â€” desempate determinÃ­stico
  SELECT COALESCE(jsonb_agg(to_jsonb(r) ORDER BY r.priority ASC, r.created_at ASC, r.id ASC), '[]'::jsonb)
  INTO v_rules
  FROM public.product_config_rules r
  WHERE r.template_id = v_template.id
    AND r.is_active = true;

  RETURN jsonb_build_object(
    'template', to_jsonb(v_template),
    'blocks', v_blocks,
    'slots', v_slots,
    'options', v_options,
    'rules', v_rules,
    'price_context_id', v_price_context_id,
    'price_context_warning', v_price_context_warning,
    'organization_id', p_organization_id
  );
END;
$$;


--
-- Name: resolve_proposal_commercial("uuid", "uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."resolve_proposal_commercial"("p_entity_id" "uuid", "p_deal_id" "uuid", "p_org_id" "uuid", "p_created_by" "uuid") RETURNS "uuid"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entity_id uuid := p_entity_id;
  v_result uuid;
BEGIN
  IF p_org_id IS NULL THEN
    RETURN p_created_by;
  END IF;

  -- If entity_id is not provided, try to derive it from the deal
  IF v_entity_id IS NULL AND p_deal_id IS NOT NULL THEN
    SELECT d.entity_id
      INTO v_entity_id
      FROM public.deals d
     WHERE d.id = p_deal_id
       AND d.organization_id = p_org_id
       AND d.deleted_at IS NULL
     LIMIT 1;
  END IF;

  IF v_entity_id IS NOT NULL THEN
    -- 1) Client of the same org
    SELECT COALESCE(c.assigned_to, c.created_by)
      INTO v_result
      FROM public.anew_clients c
     WHERE c.entity_id = v_entity_id
       AND c.organization_id = p_org_id
       AND c.deleted_at IS NULL
     ORDER BY c.created_at DESC
     LIMIT 1;
    IF v_result IS NOT NULL THEN
      RETURN v_result;
    END IF;

    -- 2) Contact of the same org
    SELECT COALESCE(co.assigned_to, co.created_by)
      INTO v_result
      FROM public.anew_contacts co
     WHERE co.entity_id = v_entity_id
       AND co.organization_id = p_org_id
       AND co.deleted_at IS NULL
     ORDER BY co.created_at DESC
     LIMIT 1;
    IF v_result IS NOT NULL THEN
      RETURN v_result;
    END IF;

    -- 3) Most recent Lead of the same org
    SELECT COALESCE(l.assigned_to, l.created_by)
      INTO v_result
      FROM public.anew_leads l
     WHERE l.entity_id = v_entity_id
       AND l.organization_id = p_org_id
       AND l.deleted_at IS NULL
     ORDER BY l.created_at DESC
     LIMIT 1;
    IF v_result IS NOT NULL THEN
      RETURN v_result;
    END IF;
  END IF;

  -- 4) Final fallback: proposal creator
  RETURN p_created_by;
END;
$$;


--
-- Name: restore_business_entity("text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."restore_business_entity"("p_kind" "text", "p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entity_id uuid;
  v_org_id uuid;
  v_actor uuid := auth.uid();
BEGIN
  IF p_kind NOT IN ('deal','quote','proposal','contract') THEN
    RAISE EXCEPTION 'Invalid kind: %', p_kind;
  END IF;

  IF p_kind = 'deal' THEN
    UPDATE public.deals SET deleted_at = NULL, deleted_by = NULL
      WHERE id = p_id AND deleted_at IS NOT NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  ELSIF p_kind = 'quote' THEN
    UPDATE public.quotes SET deleted_at = NULL, deleted_by = NULL
      WHERE id = p_id AND deleted_at IS NOT NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  ELSIF p_kind = 'proposal' THEN
    UPDATE public.proposals SET deleted_at = NULL, deleted_by = NULL, is_deleted = false
      WHERE id = p_id AND deleted_at IS NOT NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  ELSE
    UPDATE public.client_contracts SET deleted_at = NULL, deleted_by = NULL
      WHERE id = p_id AND deleted_at IS NOT NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  END IF;

  IF v_entity_id IS NOT NULL THEN
    BEGIN
      INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
      VALUES (v_entity_id, 'restored', p_kind, p_id::text, NULL, v_actor,
              jsonb_build_object('kind', p_kind, 'id', p_id, 'organization_id', v_org_id));
    EXCEPTION WHEN OTHERS THEN NULL;
    END;
  END IF;

  RETURN TRUE;
END;
$$;


--
-- Name: restore_entity_facet("text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."restore_entity_facet"("p_kind" "text", "p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_actor      uuid := public.resolve_business_user_id(auth.uid());
  v_table      text;
  v_entity_id  uuid;
  v_org_id     uuid;
  v_deleted_at timestamptz;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'restore_entity_facet: actor not resolved for auth.uid=%', auth.uid()
      USING ERRCODE = 'P0001';
  END IF;

  v_table := CASE p_kind
    WHEN 'lead'    THEN 'anew_leads'
    WHEN 'contact' THEN 'anew_contacts'
    WHEN 'client'  THEN 'anew_clients'
    ELSE NULL END;
  IF v_table IS NULL THEN
    RAISE EXCEPTION 'Invalid kind: %', p_kind;
  END IF;

  EXECUTE format(
    'SELECT entity_id, organization_id, deleted_at FROM public.%I WHERE id = $1', v_table)
  INTO v_entity_id, v_org_id, v_deleted_at
  USING p_id;

  IF v_deleted_at IS NULL THEN
    RETURN FALSE;
  END IF;

  EXECUTE format(
    'UPDATE public.%I SET deleted_at = NULL, deleted_by = NULL WHERE id = $1', v_table)
  USING p_id;

  UPDATE public.anew_entity_roles
     SET status          = COALESCE(previous_status, 'active'),
         previous_status = NULL,
         deleted_at      = NULL,
         deleted_by      = NULL
   WHERE entity_id = v_entity_id
     AND organization_id = v_org_id
     AND role = p_kind
     AND status = 'deleted'
     AND deleted_at = v_deleted_at;

  UPDATE public.deals SET deleted_at = NULL, deleted_by = NULL
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at = v_deleted_at;

  UPDATE public.quotes SET deleted_at = NULL, deleted_by = NULL
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at = v_deleted_at;

  UPDATE public.client_contracts SET deleted_at = NULL, deleted_by = NULL
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at = v_deleted_at;

  UPDATE public.proposals SET deleted_at = NULL, deleted_by = NULL, is_deleted = FALSE
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at = v_deleted_at;

  BEGIN
    INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
    VALUES (v_entity_id, 'restored', p_kind, p_id::text, NULL, v_actor,
            jsonb_build_object('kind', p_kind, 'id', p_id, 'organization_id', v_org_id,
                               'deleted_at', v_deleted_at));
  EXCEPTION WHEN OTHERS THEN NULL; END;

  RETURN TRUE;
END;
$_$;


--
-- Name: revert_contact_to_client("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."revert_contact_to_client"("p_client_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_client RECORD;
  v_contact_id uuid;
  v_actor uuid := auth.uid();
BEGIN
  SELECT id, entity_id, organization_id, source_id, source_type, status
  INTO v_client
  FROM public.anew_clients
  WHERE id = p_client_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Client not found';
  END IF;

  IF v_client.source_type <> 'contact' OR v_client.source_id IS NULL THEN
    RAISE EXCEPTION 'Client was not converted from a contact';
  END IF;

  v_contact_id := v_client.source_id;

  -- Reversion is not deletion: keep the former client out of the trash.
  UPDATE public.anew_clients
  SET status = 'inactive',
      deleted_at = NULL,
      deleted_by = NULL
  WHERE id = p_client_id;

  UPDATE public.anew_entity_roles
  SET status = 'inactive',
      deleted_at = NULL,
      deleted_by = NULL
  WHERE entity_id = v_client.entity_id
    AND organization_id = v_client.organization_id
    AND role = 'client';

  -- Restore the original contact and explicitly clear trash markers.
  UPDATE public.anew_contacts
  SET converted_to_client_id = NULL,
      converted_at = NULL,
      status = 'active',
      deleted_at = NULL,
      deleted_by = NULL
  WHERE id = v_contact_id;

  UPDATE public.anew_entity_roles
  SET status = 'active',
      previous_status = NULL,
      deleted_at = NULL,
      deleted_by = NULL
  WHERE entity_id = v_client.entity_id
    AND organization_id = v_client.organization_id
    AND role = 'contact';

  INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
  VALUES (
    v_client.entity_id,
    'conversion_reverted',
    'contact_to_client',
    p_client_id::text,
    v_contact_id::text,
    v_actor,
    jsonb_build_object('client_id', p_client_id, 'contact_id', v_contact_id, 'organization_id', v_client.organization_id)
  );

  RETURN TRUE;
END;
$$;


--
-- Name: revert_contact_to_client_conversion("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."revert_contact_to_client_conversion"("p_client_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact_id UUID;
BEGIN
  -- Get the source contact
  SELECT source_contact_id INTO v_contact_id
  FROM clients
  WHERE id = p_client_id;
  
  IF v_contact_id IS NULL THEN
    RAISE EXCEPTION 'Client was not converted from a contact';
  END IF;
  
  -- Clear the conversion on the contact
  UPDATE contacts
  SET converted_to_client_id = NULL,
      converted_at = NULL,
      client_id = NULL,
      status = 'prospect' -- Reset to prospect status
  WHERE id = v_contact_id;
  
  -- Delete the client (or soft-delete if column exists)
  DELETE FROM clients WHERE id = p_client_id;
  
  RETURN TRUE;
END;
$$;


--
-- Name: revert_lead_to_contact("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."revert_lead_to_contact"("p_contact_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_contact RECORD;
  v_lead_id uuid;
  v_actor uuid := auth.uid();
BEGIN
  SELECT id, entity_id, organization_id, source_lead_id
  INTO v_contact FROM public.anew_contacts WHERE id = p_contact_id;

  IF NOT FOUND THEN RAISE EXCEPTION 'Contact not found'; END IF;
  IF v_contact.source_lead_id IS NULL THEN RAISE EXCEPTION 'Contact was not converted from a lead'; END IF;

  v_lead_id := v_contact.source_lead_id;

  -- Step 1: deactivate contact FIRST
  UPDATE public.anew_contacts SET status = 'inactive' WHERE id = p_contact_id;
  UPDATE public.anew_entity_roles
    SET status = 'inactive'
    WHERE entity_id = v_contact.entity_id
      AND organization_id = v_contact.organization_id
      AND role = 'contact'
      AND status <> 'deleted';

  -- Step 2: reactivate lead
  UPDATE public.anew_leads
    SET converted_to_contact_id = NULL,
        converted_at = NULL,
        converted_by = NULL,
        status = 'qualified'
    WHERE id = v_lead_id;

  UPDATE public.anew_entity_roles
    SET status = 'active'
    WHERE entity_id = v_contact.entity_id
      AND organization_id = v_contact.organization_id
      AND role = 'lead'
      AND status <> 'deleted';

  INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
  VALUES (v_contact.entity_id, 'conversion_reverted', 'lead_to_contact', p_contact_id::text, v_lead_id::text, v_actor,
          jsonb_build_object('contact_id', p_contact_id, 'lead_id', v_lead_id, 'organization_id', v_contact.organization_id));

  RETURN TRUE;
END;
$$;


--
-- Name: revert_lead_to_contact_conversion("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."revert_lead_to_contact_conversion"("p_contact_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_lead_id UUID;
BEGIN
  -- Get the source lead
  SELECT source_lead_id INTO v_lead_id
  FROM contacts
  WHERE id = p_contact_id;
  
  IF v_lead_id IS NULL THEN
    RAISE EXCEPTION 'Contact was not converted from a lead';
  END IF;
  
  -- Clear the conversion on the lead
  UPDATE leads
  SET converted_to_contact_id = NULL,
      converted_at = NULL,
      status = 'qualified' -- Reset to qualified status
  WHERE id = v_lead_id;
  
  -- Soft-delete the contact
  UPDATE contacts
  SET is_deleted = TRUE,
      deleted_at = NOW(),
      deleted_by = auth.uid()
  WHERE id = p_contact_id;
  
  RETURN TRUE;
END;
$$;


--
-- Name: rls_auto_enable(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."rls_auto_enable"() RETURNS "event_trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'pg_catalog'
    AS $$
DECLARE
  cmd record;
BEGIN
  FOR cmd IN
    SELECT *
    FROM pg_event_trigger_ddl_commands()
    WHERE command_tag IN ('CREATE TABLE', 'CREATE TABLE AS', 'SELECT INTO')
      AND object_type IN ('table','partitioned table')
  LOOP
     IF cmd.schema_name IS NOT NULL AND cmd.schema_name IN ('public') AND cmd.schema_name NOT IN ('pg_catalog','information_schema') AND cmd.schema_name NOT LIKE 'pg_toast%' AND cmd.schema_name NOT LIKE 'pg_temp%' THEN
      BEGIN
        EXECUTE format('alter table if exists %s enable row level security', cmd.object_identity);
        RAISE LOG 'rls_auto_enable: enabled RLS on %', cmd.object_identity;
      EXCEPTION
        WHEN OTHERS THEN
          RAISE LOG 'rls_auto_enable: failed to enable RLS on %', cmd.object_identity;
      END;
     ELSE
        RAISE LOG 'rls_auto_enable: skip % (either system schema or not in enforced list: %.)', cmd.object_identity, cmd.schema_name;
     END IF;
  END LOOP;
END;
$$;


--
-- Name: search_proposal_entities("text", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."search_proposal_entities"("p_search" "text", "p_limit" integer DEFAULT 50) RETURNS TABLE("type" "text", "id" "uuid", "entity_id" "uuid", "name" "text", "email" "text", "phone" "text", "status" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_search text := '%' || trim(coalesce(p_search, '')) || '%';
  v_limit integer := least(greatest(coalesce(p_limit, 50), 1), 100);
BEGIN
  IF auth.uid() IS NULL OR length(trim(coalesce(p_search, ''))) < 2 THEN
    RETURN;
  END IF;

  RETURN QUERY
  WITH visible_orgs AS (
    SELECT public.get_user_visible_org_ids(auth.uid()) AS organization_id
  ), matched_contacts AS (
    SELECT
      'contact'::text AS type,
      c.id,
      c.entity_id,
      COALESCE(e.display_name, trim(concat_ws(' ', e.first_name, e.last_name)))::text AS name,
      pe.email::text AS email,
      pp.phone::text AS phone,
      c.status::text AS status,
      c.created_at
    FROM public.anew_contacts c
    JOIN visible_orgs vo ON vo.organization_id = c.organization_id
    JOIN public.anew_entities e ON e.id = c.entity_id
    LEFT JOIN LATERAL (
      SELECT ee.email FROM public.anew_entity_emails ee
      WHERE ee.entity_id = c.entity_id AND coalesce(ee.is_primary, true)
      ORDER BY ee.is_primary DESC NULLS LAST, ee.created_at DESC LIMIT 1
    ) pe ON true
    LEFT JOIN LATERAL (
      SELECT ep.phone_number AS phone FROM public.anew_entity_phones ep
      WHERE ep.entity_id = c.entity_id AND coalesce(ep.is_primary, true)
      ORDER BY ep.is_primary DESC NULLS LAST, ep.created_at DESC LIMIT 1
    ) pp ON true
    WHERE c.deleted_at IS NULL
      AND c.converted_to_client_id IS NULL
      AND (
        extensions.unaccent(coalesce(e.display_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.first_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.last_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(trim(concat_ws(' ', e.first_name, e.last_name))) ILIKE extensions.unaccent(v_search)
        OR pe.email ILIKE v_search
        OR pp.phone ILIKE v_search
      )
  ), matched_clients AS (
    SELECT
      'client'::text AS type,
      cl.id,
      cl.entity_id,
      COALESCE(e.display_name, trim(concat_ws(' ', e.first_name, e.last_name)))::text AS name,
      pe.email::text AS email,
      pp.phone::text AS phone,
      cl.status::text AS status,
      cl.created_at
    FROM public.anew_clients cl
    JOIN visible_orgs vo ON vo.organization_id = cl.organization_id
    JOIN public.anew_entities e ON e.id = cl.entity_id
    LEFT JOIN LATERAL (
      SELECT ee.email FROM public.anew_entity_emails ee
      WHERE ee.entity_id = cl.entity_id AND coalesce(ee.is_primary, true)
      ORDER BY ee.is_primary DESC NULLS LAST, ee.created_at DESC LIMIT 1
    ) pe ON true
    LEFT JOIN LATERAL (
      SELECT ep.phone_number AS phone FROM public.anew_entity_phones ep
      WHERE ep.entity_id = cl.entity_id AND coalesce(ep.is_primary, true)
      ORDER BY ep.is_primary DESC NULLS LAST, ep.created_at DESC LIMIT 1
    ) pp ON true
    WHERE cl.deleted_at IS NULL
      AND (
        extensions.unaccent(coalesce(e.display_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.first_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.last_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(trim(concat_ws(' ', e.first_name, e.last_name))) ILIKE extensions.unaccent(v_search)
        OR pe.email ILIKE v_search
        OR pp.phone ILIKE v_search
      )
  )
  SELECT r.type, r.id, r.entity_id, r.name, r.email, r.phone, r.status
  FROM (
    SELECT type, id, entity_id, name, email, phone, status, created_at FROM matched_contacts
    UNION ALL
    SELECT type, id, entity_id, name, email, phone, status, created_at FROM matched_clients
  ) r
  ORDER BY r.created_at DESC
  LIMIT v_limit;
END;
$$;


--
-- Name: search_proposal_entities("text", integer, "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."search_proposal_entities"("p_search" "text", "p_limit" integer DEFAULT 50, "p_organization_id" "uuid" DEFAULT NULL::"uuid") RETURNS TABLE("type" "text", "id" "uuid", "entity_id" "uuid", "name" "text", "email" "text", "phone" "text", "status" "text")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_search text := '%' || trim(coalesce(p_search, '')) || '%';
  v_limit integer := least(greatest(coalesce(p_limit, 50), 1), 100);
  v_org uuid;
BEGIN
  IF auth.uid() IS NULL OR length(trim(coalesce(p_search, ''))) < 2 OR p_organization_id IS NULL THEN
    RETURN;
  END IF;

  SELECT vo INTO v_org
  FROM public.get_user_visible_org_ids(auth.uid()) AS vo
  WHERE vo = p_organization_id
  LIMIT 1;

  IF v_org IS NULL THEN
    RETURN;
  END IF;

  RETURN QUERY
  WITH matched_contacts AS (
    SELECT
      'contact'::text AS entity_type,
      c.id,
      c.entity_id,
      COALESCE(e.display_name, trim(concat_ws(' ', e.first_name, e.last_name)))::text AS name,
      pe.email::text AS email,
      pp.phone::text AS phone,
      c.status::text AS status,
      c.created_at
    FROM public.anew_contacts c
    JOIN public.anew_entities e ON e.id = c.entity_id
    LEFT JOIN LATERAL (
      SELECT ee.email
      FROM public.anew_entity_emails ee
      WHERE ee.entity_id = c.entity_id AND coalesce(ee.is_primary, true)
      ORDER BY ee.is_primary DESC NULLS LAST, ee.created_at DESC
      LIMIT 1
    ) pe ON true
    LEFT JOIN LATERAL (
      SELECT ep.phone_number AS phone
      FROM public.anew_entity_phones ep
      WHERE ep.entity_id = c.entity_id AND coalesce(ep.is_primary, true)
      ORDER BY ep.is_primary DESC NULLS LAST, ep.created_at DESC
      LIMIT 1
    ) pp ON true
    LEFT JOIN LATERAL (
      SELECT fe.nif
      FROM public.anew_entity_fiscal_entities efe
      JOIN public.fiscal_entities fe ON fe.id = efe.fiscal_entity_id
      WHERE efe.entity_id = c.entity_id
        AND coalesce(efe.is_primary, true)
        AND efe.valid_to IS NULL
      LIMIT 1
    ) pf ON true
    WHERE c.organization_id = v_org
      AND c.deleted_at IS NULL
      AND c.converted_to_client_id IS NULL
      AND c.status = 'active'
      AND (
        extensions.unaccent(coalesce(e.display_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.first_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.last_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(trim(concat_ws(' ', e.first_name, e.last_name))) ILIKE extensions.unaccent(v_search)
        OR pe.email ILIKE v_search
        OR pp.phone ILIKE v_search
        OR pf.nif ILIKE v_search
      )
  ), matched_clients AS (
    SELECT
      'client'::text AS entity_type,
      cl.id,
      cl.entity_id,
      COALESCE(e.display_name, trim(concat_ws(' ', e.first_name, e.last_name)))::text AS name,
      pe.email::text AS email,
      pp.phone::text AS phone,
      cl.status::text AS status,
      cl.created_at
    FROM public.anew_clients cl
    JOIN public.anew_entities e ON e.id = cl.entity_id
    LEFT JOIN LATERAL (
      SELECT ee.email
      FROM public.anew_entity_emails ee
      WHERE ee.entity_id = cl.entity_id AND coalesce(ee.is_primary, true)
      ORDER BY ee.is_primary DESC NULLS LAST, ee.created_at DESC
      LIMIT 1
    ) pe ON true
    LEFT JOIN LATERAL (
      SELECT ep.phone_number AS phone
      FROM public.anew_entity_phones ep
      WHERE ep.entity_id = cl.entity_id AND coalesce(ep.is_primary, true)
      ORDER BY ep.is_primary DESC NULLS LAST, ep.created_at DESC
      LIMIT 1
    ) pp ON true
    LEFT JOIN LATERAL (
      SELECT fe.nif
      FROM public.anew_entity_fiscal_entities efe
      JOIN public.fiscal_entities fe ON fe.id = efe.fiscal_entity_id
      WHERE efe.entity_id = cl.entity_id
        AND coalesce(efe.is_primary, true)
        AND efe.valid_to IS NULL
      LIMIT 1
    ) pf ON true
    WHERE cl.organization_id = v_org
      AND cl.deleted_at IS NULL
      AND cl.status = 'active'
      AND (
        extensions.unaccent(coalesce(e.display_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.first_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(coalesce(e.last_name,'')) ILIKE extensions.unaccent(v_search)
        OR extensions.unaccent(trim(concat_ws(' ', e.first_name, e.last_name))) ILIKE extensions.unaccent(v_search)
        OR pe.email ILIKE v_search
        OR pp.phone ILIKE v_search
        OR pf.nif ILIKE v_search
      )
  )
  SELECT r.entity_type, r.id, r.entity_id, r.name, r.email, r.phone, r.status
  FROM (
    SELECT mc.entity_type, mc.id, mc.entity_id, mc.name, mc.email, mc.phone, mc.status, mc.created_at
    FROM matched_contacts mc
    UNION ALL
    SELECT mcl.entity_type, mcl.id, mcl.entity_id, mcl.name, mcl.email, mcl.phone, mcl.status, mcl.created_at
    FROM matched_clients mcl
  ) r
  ORDER BY r.created_at DESC
  LIMIT v_limit;
END;
$$;


--
-- Name: search_visible_entity_ids("text", integer); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."search_visible_entity_ids"("p_search" "text", "p_limit" integer DEFAULT 200) RETURNS TABLE("entity_id" "uuid")
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public', 'extensions'
    AS $$
DECLARE
  v_auth         uuid;
  v_business_uid uuid;
  v_visible      uuid[];
  v_term         text;
  v_like         text;
  v_digits       text;
  v_digits_like  text;
  v_limit        integer;
BEGIN
  v_auth := auth.uid();
  IF v_auth IS NULL THEN
    RETURN;
  END IF;

  v_term := btrim(coalesce(p_search, ''));
  IF length(v_term) < 2 THEN
    RETURN;
  END IF;

  v_limit := greatest(1, least(coalesce(p_limit, 200), 1000));

  -- Escape ILIKE wildcards/escape from user input (defence in depth).
  -- Keep original case so the trigram GIN indexes (ILIKE is case-insensitive) are used.
  v_like := '%' ||
            replace(replace(replace(v_term, '\', '\\'), '%', '\%'), '_', '\_') ||
            '%';

  v_digits := regexp_replace(v_term, '[^0-9]', '', 'g');
  IF length(v_digits) >= 2 THEN
    v_digits_like := '%' || v_digits || '%';
  ELSE
    v_digits_like := NULL;
  END IF;

  v_business_uid := public.current_business_user_id();
  v_visible      := ARRAY(SELECT public.get_user_visible_org_ids(v_auth));

  RETURN QUERY
  WITH candidates AS (
    SELECT e.id AS entity_id
      FROM public.anew_entities e
     WHERE e.display_name ILIKE v_like ESCAPE '\'
        OR e.first_name   ILIKE v_like ESCAPE '\'
        OR e.last_name    ILIKE v_like ESCAPE '\'
    UNION
    SELECT em.entity_id
      FROM public.anew_entity_emails em
     WHERE em.email ILIKE v_like ESCAPE '\'
    UNION
    SELECT ph.entity_id
      FROM public.anew_entity_phones ph
     WHERE ph.phone_number ILIKE v_like ESCAPE '\'
    UNION
    SELECT ph.entity_id
      FROM public.anew_entity_phones ph
     WHERE v_digits_like IS NOT NULL
       AND regexp_replace(ph.phone_number, '[^0-9]', '', 'g') ILIKE v_digits_like ESCAPE '\'
    UNION
    SELECT efe.entity_id
      FROM public.fiscal_entities fe
      JOIN public.anew_entity_fiscal_entities efe
        ON efe.fiscal_entity_id = fe.id
     WHERE fe.nif ILIKE v_like ESCAPE '\'
  ),
  visible AS (
    SELECT DISTINCT c.entity_id
      FROM candidates c
     WHERE
        (v_business_uid IS NOT NULL
         AND EXISTS (SELECT 1 FROM public.anew_entities e
                      WHERE e.id = c.entity_id AND e.created_by = v_business_uid))
        OR EXISTS (SELECT 1 FROM public.anew_entity_org_links l
                    WHERE l.entity_id = c.entity_id AND l.organization_id = ANY(v_visible))
        OR EXISTS (SELECT 1 FROM public.anew_leads x
                    WHERE x.entity_id = c.entity_id AND x.organization_id = ANY(v_visible))
        OR EXISTS (SELECT 1 FROM public.anew_contacts x
                    WHERE x.entity_id = c.entity_id AND x.organization_id = ANY(v_visible))
        OR EXISTS (SELECT 1 FROM public.anew_clients x
                    WHERE x.entity_id = c.entity_id AND x.organization_id = ANY(v_visible))
        OR EXISTS (SELECT 1 FROM public.quotes x
                    WHERE x.entity_id = c.entity_id AND x.organization_id = ANY(v_visible))
        OR EXISTS (SELECT 1 FROM public.deals x
                    WHERE x.entity_id = c.entity_id AND x.organization_id = ANY(v_visible))
  )
  SELECT v.entity_id FROM visible v LIMIT v_limit;
END;
$$;


