--
-- Name: set_proposal_accepted_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."set_proposal_accepted_at"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_is_won boolean := false;
  v_was_won boolean := false;
BEGIN
  IF NEW.stage_id IS NOT NULL THEN
    SELECT COALESCE(is_won, false) INTO v_is_won
    FROM public.proposal_workflow_stages WHERE id = NEW.stage_id;
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.stage_id IS NOT NULL THEN
    SELECT COALESCE(is_won, false) INTO v_was_won
    FROM public.proposal_workflow_stages WHERE id = OLD.stage_id;
  END IF;

  IF v_is_won AND NEW.accepted_at IS NULL THEN
    NEW.accepted_at := COALESCE(NEW.accepted_at, now());
  END IF;

  IF NOT v_is_won AND v_was_won THEN
    NEW.accepted_at := NULL;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: set_proposal_assigned_to(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."set_proposal_assigned_to"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.assigned_to IS NULL THEN
    NEW.assigned_to := public.resolve_proposal_commercial(
      NEW.entity_id,
      NEW.deal_id,
      NEW.organization_id,
      NEW.created_by
    );
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: set_quote_accepted_at(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."set_quote_accepted_at"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  won_states constant text[] := ARRAY['aceite','finalizado'];
BEGIN
  IF NEW.estado = ANY(won_states)
     AND (TG_OP = 'INSERT' OR OLD.estado IS DISTINCT FROM NEW.estado)
     AND NEW.accepted_at IS NULL THEN
    NEW.accepted_at := now();
  END IF;

  IF TG_OP = 'UPDATE'
     AND OLD.estado = ANY(won_states)
     AND NOT (NEW.estado = ANY(won_states)) THEN
    NEW.accepted_at := NULL;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: set_quote_number(); Type: FUNCTION; Schema: public; Owner: -
