--
-- Name: soft_delete_business_entity("text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."soft_delete_business_entity"("p_kind" "text", "p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_entity_id uuid; v_org_id uuid;
  v_actor uuid := public.resolve_business_user_id(auth.uid());
BEGIN
  IF p_kind NOT IN ('deal','quote','proposal','contract') THEN
    RAISE EXCEPTION 'Invalid kind: %', p_kind;
  END IF;
  IF p_kind = 'deal' THEN
    UPDATE public.deals SET deleted_at=now(), deleted_by=v_actor
      WHERE id=p_id AND deleted_at IS NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  ELSIF p_kind = 'quote' THEN
    UPDATE public.quotes SET deleted_at=now(), deleted_by=v_actor
      WHERE id=p_id AND deleted_at IS NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  ELSIF p_kind = 'proposal' THEN
    UPDATE public.proposals SET deleted_at=now(), deleted_by=v_actor, is_deleted=true
      WHERE id=p_id AND deleted_at IS NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  ELSE
    UPDATE public.client_contracts SET deleted_at=now(), deleted_by=v_actor
      WHERE id=p_id AND deleted_at IS NULL
      RETURNING entity_id, organization_id INTO v_entity_id, v_org_id;
  END IF;
  IF v_entity_id IS NOT NULL THEN
    BEGIN
      INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
      VALUES (v_entity_id, 'deleted', p_kind, NULL, p_id::text, v_actor,
              jsonb_build_object('kind', p_kind, 'id', p_id, 'organization_id', v_org_id));
    EXCEPTION WHEN OTHERS THEN NULL; END;
  END IF;
  RETURN TRUE;
END;
$$;


--
-- Name: soft_delete_entity_facet("text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."soft_delete_entity_facet"("p_kind" "text", "p_id" "uuid") RETURNS boolean
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $_$
DECLARE
  v_actor      uuid := public.resolve_business_user_id(auth.uid());
  v_table      text;
  v_entity_id  uuid;
  v_org_id     uuid;
  v_deleted_at timestamptz;
  v_deals integer := 0; v_quotes integer := 0; v_props integer := 0; v_contracts integer := 0;
BEGIN
  IF v_actor IS NULL THEN
    RAISE EXCEPTION 'soft_delete_entity_facet: actor not resolved for auth.uid=%', auth.uid()
      USING ERRCODE = 'P0001';
  END IF;

  v_table := CASE p_kind
    WHEN 'lead'    THEN 'anew_leads'
    WHEN 'contact' THEN 'anew_contacts'
    WHEN 'client'  THEN 'anew_clients'
    ELSE NULL END;
  IF v_table IS NULL THEN
    RAISE EXCEPTION 'Invalid kind: %', p_kind;
  END IF;

  EXECUTE format(
    'UPDATE public.%I SET deleted_at = now(), deleted_by = $1
     WHERE id = $2 AND deleted_at IS NULL
     RETURNING entity_id, organization_id, deleted_at', v_table)
  INTO v_entity_id, v_org_id, v_deleted_at
  USING v_actor, p_id;

  IF v_entity_id IS NULL THEN
    RETURN FALSE;
  END IF;

  UPDATE public.anew_entity_roles
     SET previous_status = status,
         status          = 'deleted',
         deleted_at      = v_deleted_at,
         deleted_by      = v_actor
   WHERE entity_id = v_entity_id
     AND organization_id = v_org_id
     AND role = p_kind
     AND deleted_at IS NULL;

  UPDATE public.deals SET deleted_at = v_deleted_at, deleted_by = v_actor
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at IS NULL;
  GET DIAGNOSTICS v_deals = ROW_COUNT;

  UPDATE public.quotes SET deleted_at = v_deleted_at, deleted_by = v_actor
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at IS NULL;
  GET DIAGNOSTICS v_quotes = ROW_COUNT;

  UPDATE public.client_contracts SET deleted_at = v_deleted_at, deleted_by = v_actor
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at IS NULL;
  GET DIAGNOSTICS v_contracts = ROW_COUNT;

  UPDATE public.proposals SET deleted_at = v_deleted_at, deleted_by = v_actor, is_deleted = TRUE
   WHERE entity_id = v_entity_id AND organization_id = v_org_id AND deleted_at IS NULL;
  GET DIAGNOSTICS v_props = ROW_COUNT;

  BEGIN
    INSERT INTO public.anew_entity_history(entity_id, change_type, field_name, old_value, new_value, changed_by, metadata)
    VALUES (v_entity_id, 'deleted', p_kind, NULL, p_id::text, v_actor,
            jsonb_build_object(
              'kind', p_kind, 'id', p_id, 'organization_id', v_org_id,
              'cascade', jsonb_build_object(
                'deals', v_deals, 'quotes', v_quotes,
                'proposals', v_props, 'contracts', v_contracts)));
  EXCEPTION WHEN OTHERS THEN NULL; END;

  RETURN TRUE;
END;
$_$;


--
-- Name: sync_client_contact_roles("uuid", "uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."sync_client_contact_roles"("_entity_id" "uuid", "_organization_id" "uuid", "_client_id" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_client_id uuid;
  v_actor uuid;
BEGIN
  IF _entity_id IS NULL OR _organization_id IS NULL THEN RETURN; END IF;

  SELECT id, created_by INTO v_client_id, v_actor
  FROM public.anew_clients
  WHERE entity_id = _entity_id
    AND organization_id = _organization_id
    AND deleted_at IS NULL
    AND COALESCE(status, '') <> 'inactive'
  ORDER BY created_at ASC LIMIT 1;

  v_client_id := COALESCE(_client_id, v_client_id);
  IF v_client_id IS NULL THEN RETURN; END IF;

  UPDATE public.anew_contacts
  SET status = 'inactive',
      converted_to_client_id = COALESCE(converted_to_client_id, v_client_id),
      converted_at = COALESCE(converted_at, now())
  WHERE entity_id = _entity_id
    AND organization_id = _organization_id
    AND deleted_at IS NULL
    AND converted_to_client_id IS NULL
    AND COALESCE(status, '') <> 'inactive';

  UPDATE public.anew_entity_roles
  SET status = 'inactive'
  WHERE entity_id = _entity_id
    AND organization_id = _organization_id
    AND role = 'contact'
    AND status NOT IN ('inactive','deleted');

  UPDATE public.anew_entity_roles
  SET status = 'active'
  WHERE entity_id = _entity_id
    AND organization_id = _organization_id
    AND role = 'client'
    AND status NOT IN ('active','deleted');

  IF NOT EXISTS (
    SELECT 1 FROM public.anew_entity_roles
    WHERE entity_id = _entity_id AND organization_id = _organization_id AND role = 'client'
  ) THEN
    INSERT INTO public.anew_entity_roles (entity_id, organization_id, role, status, source_type, created_by)
    VALUES (_entity_id, _organization_id, 'client', 'active', 'client_contact_sync', v_actor);
  END IF;
END;
$$;


--
-- Name: sync_proposal_value_from_quote(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."sync_proposal_value_from_quote"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.proposal_id IS NOT NULL THEN
    UPDATE public.proposals
       SET value = COALESCE(NEW.total, 0),
           updated_at = now()
     WHERE id = NEW.proposal_id;
  END IF;

  IF TG_OP = 'UPDATE' AND OLD.proposal_id IS NOT NULL AND OLD.proposal_id IS DISTINCT FROM NEW.proposal_id THEN
    UPDATE public.proposals p
       SET value = COALESCE((SELECT SUM(q.total) FROM public.quotes q WHERE q.proposal_id = OLD.proposal_id), 0),
           updated_at = now()
     WHERE p.id = OLD.proposal_id;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: trg_prevent_active_contact_when_client(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."trg_prevent_active_contact_when_client"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_client_id uuid;
BEGIN
  IF NEW.deleted_at IS NOT NULL THEN
    RETURN NEW;
  END IF;

  IF NEW.entity_id IS NOT NULL
     AND NEW.organization_id IS NOT NULL
     AND NEW.converted_to_client_id IS NULL
     AND COALESCE(NEW.status, '') <> 'inactive' THEN
    SELECT id INTO v_client_id
    FROM public.anew_clients
    WHERE entity_id = NEW.entity_id
      AND organization_id = NEW.organization_id
      AND deleted_at IS NULL
      AND COALESCE(status, '') <> 'inactive'
    ORDER BY created_at ASC
    LIMIT 1;

    IF v_client_id IS NOT NULL THEN
      NEW.status := 'inactive';
      NEW.converted_to_client_id := v_client_id;
      NEW.converted_at := COALESCE(NEW.converted_at, now());
    END IF;
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: trg_prevent_contact_pointing_to_inactive_client(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."trg_prevent_contact_pointing_to_inactive_client"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_client RECORD;
BEGIN
  -- Only enforce when the contact is marked as converted (inactive + has target client).
  IF NEW.deleted_at IS NOT NULL
     OR NEW.converted_to_client_id IS NULL
     OR COALESCE(NEW.status, '') <> 'inactive' THEN
    RETURN NEW;
  END IF;

  SELECT id, status, deleted_at
    INTO v_client
  FROM public.anew_clients
  WHERE id = NEW.converted_to_client_id;

  IF NOT FOUND THEN
    RAISE EXCEPTION 'Contacto convertido aponta para cliente inexistente (%).', NEW.converted_to_client_id
      USING ERRCODE = 'check_violation';
  END IF;

  IF v_client.deleted_at IS NOT NULL OR COALESCE(v_client.status, '') <> 'active' THEN
    RAISE EXCEPTION 'Contacto inativo nÃ£o pode apontar para cliente inativo ou apagado (cliente=%, status=%, deleted_at=%).',
      v_client.id, v_client.status, v_client.deleted_at
      USING ERRCODE = 'check_violation';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: trg_sync_from_client(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."trg_sync_from_client"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF NEW.entity_id IS NOT NULL
     AND NEW.organization_id IS NOT NULL
     AND NEW.deleted_at IS NULL
     AND COALESCE(NEW.status, '') <> 'inactive' THEN
    PERFORM public.sync_client_contact_roles(NEW.entity_id, NEW.organization_id, NEW.id);
  END IF;
  RETURN NEW;
END;
$$;


--
-- Name: trg_sync_from_entity_role(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."trg_sync_from_entity_role"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_client_id uuid;
BEGIN
  IF NEW.entity_id IS NULL OR NEW.organization_id IS NULL THEN
    RETURN NEW;
  END IF;

  SELECT id INTO v_client_id
  FROM public.anew_clients
  WHERE entity_id = NEW.entity_id
    AND organization_id = NEW.organization_id
    AND COALESCE(status, '') <> 'inactive'
  ORDER BY created_at ASC
  LIMIT 1;

  IF NEW.role = 'contact' AND NEW.status = 'active' AND v_client_id IS NOT NULL THEN
    NEW.status := 'inactive';
  END IF;

  IF NEW.role = 'client' AND NEW.status = 'active' THEN
    UPDATE public.anew_entity_roles
    SET status = 'inactive'
    WHERE entity_id = NEW.entity_id
      AND organization_id = NEW.organization_id
      AND role = 'contact'
      AND id IS DISTINCT FROM NEW.id
      AND status <> 'inactive';

    UPDATE public.anew_contacts
    SET status = 'inactive',
        converted_to_client_id = COALESCE(converted_to_client_id, v_client_id),
        converted_at = COALESCE(converted_at, now())
    WHERE v_client_id IS NOT NULL
      AND entity_id = NEW.entity_id
      AND organization_id = NEW.organization_id
      AND converted_to_client_id IS NULL
      AND COALESCE(status, '') <> 'inactive';
  END IF;

  RETURN NEW;
END;
$$;


--
-- Name: unlink_organization_node("uuid", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."unlink_organization_node"("p_child_org_id" "uuid", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS "void"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  IF p_child_org_id IS NULL THEN
    RAISE EXCEPTION 'child_org_id is required';
  END IF;

  IF NOT EXISTS (SELECT 1 FROM public.anew_organizations WHERE id = p_child_org_id) THEN
    RAISE EXCEPTION 'Organization does not exist';
  END IF;

  DELETE FROM public.anew_hierarchy
  WHERE child_org_id = p_child_org_id;
END;
$$;


