    RETURN NEW;
END;
$$;


--
-- Name: upsert_entity_identity("uuid", "jsonb", "jsonb", "jsonb", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."upsert_entity_identity"("p_entity_id" "uuid", "p_emails" "jsonb" DEFAULT '[]'::"jsonb", "p_phones" "jsonb" DEFAULT '[]'::"jsonb", "p_addresses" "jsonb" DEFAULT '[]'::"jsonb", "p_created_by" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_anew_user_id UUID;
  v_creator UUID;
  v_email JSONB;
  v_phone JSONB;
  v_addr JSONB;
  v_addr_id UUID;
  v_entity_exists BOOLEAN;
BEGIN
  -- Verify entity exists
  SELECT EXISTS(SELECT 1 FROM anew_entities WHERE id = p_entity_id) INTO v_entity_exists;
  IF NOT v_entity_exists THEN
    RAISE EXCEPTION 'Entity % does not exist', p_entity_id;
  END IF;

  -- Resolve creator: prefer canonical anew_users.id (translate auth_user_id if needed)
  IF p_created_by IS NOT NULL THEN
    SELECT id INTO v_anew_user_id FROM anew_users WHERE id = p_created_by LIMIT 1;
    IF v_anew_user_id IS NOT NULL THEN
      v_creator := v_anew_user_id;
    ELSE
      SELECT id INTO v_anew_user_id FROM anew_users WHERE auth_user_id = p_created_by LIMIT 1;
      v_creator := COALESCE(v_anew_user_id, p_created_by);
    END IF;
  ELSE
    SELECT id INTO v_creator FROM anew_users WHERE auth_user_id = auth.uid() LIMIT 1;
  END IF;

  -- ===== EMAILS =====
  IF p_emails IS NOT NULL THEN
    DELETE FROM anew_entity_emails WHERE entity_id = p_entity_id;
    FOR v_email IN SELECT * FROM jsonb_array_elements(p_emails) LOOP
      INSERT INTO anew_entity_emails (entity_id, email, email_type, is_primary, created_by)
      VALUES (
        p_entity_id,
        v_email->>'email',
        COALESCE(v_email->>'email_type', 'personal'),
        COALESCE((v_email->>'is_primary')::boolean, false),
        v_creator
      );
    END LOOP;
  END IF;

  -- ===== PHONES =====
  IF p_phones IS NOT NULL THEN
    DELETE FROM anew_entity_phones WHERE entity_id = p_entity_id;
    FOR v_phone IN SELECT * FROM jsonb_array_elements(p_phones) LOOP
      INSERT INTO anew_entity_phones (entity_id, phone_number, country_code, phone_type, is_primary, created_by)
      VALUES (
        p_entity_id,
        v_phone->>'phone_number',
        COALESCE(v_phone->>'country_code', '+351'),
        COALESCE(v_phone->>'phone_type', 'mobile'),
        COALESCE((v_phone->>'is_primary')::boolean, false),
        v_creator
      );
    END LOOP;
  END IF;

  -- ===== ADDRESSES =====
  -- Strategy: soft-delete (valid_to = now) existing primary links, insert new ones.
  -- We do NOT delete anew_addresses rows (they may be shared).
  IF p_addresses IS NOT NULL THEN
    UPDATE anew_entity_addresses
    SET valid_to = now()
    WHERE entity_id = p_entity_id AND valid_to IS NULL;

    FOR v_addr IN SELECT * FROM jsonb_array_elements(p_addresses) LOOP
      INSERT INTO anew_addresses (
        address_key, street, number, floor, unit, postal_code,
        city, district, country, extra, created_by
      )
      VALUES (
        md5(COALESCE(v_addr->>'street','') || '|' ||
            COALESCE(v_addr->>'number','') || '|' ||
            COALESCE(v_addr->>'postal_code','') || '|' ||
            COALESCE(v_addr->>'city','')),
        COALESCE(v_addr->>'street',''),
        COALESCE(v_addr->>'number',''),
        NULLIF(v_addr->>'floor',''),
        NULLIF(v_addr->>'unit',''),
        COALESCE(v_addr->>'postal_code',''),
        COALESCE(v_addr->>'city',''),
        NULLIF(v_addr->>'district',''),
        COALESCE(v_addr->>'country','PT'),
        NULLIF(v_addr->>'extra',''),
        v_creator
      )
      RETURNING id INTO v_addr_id;

      INSERT INTO anew_entity_addresses (
        entity_id, address_id, address_type, is_primary, is_fiscal,
        valid_from, created_by
      )
      VALUES (
        p_entity_id,
        v_addr_id,
        COALESCE(v_addr->>'address_type', 'home'),
        COALESCE((v_addr->>'is_primary')::boolean, false),
        COALESCE((v_addr->>'is_fiscal')::boolean, false),
        now(),
        v_creator
      );
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'success', true,
    'entity_id', p_entity_id,
    'emails_count', jsonb_array_length(COALESCE(p_emails, '[]'::jsonb)),
    'phones_count', jsonb_array_length(COALESCE(p_phones, '[]'::jsonb)),
    'addresses_count', jsonb_array_length(COALESCE(p_addresses, '[]'::jsonb))
  );
END;
$$;


--
-- Name: user_has_active_membership("uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."user_has_active_membership"("_auth_uid" "uuid") RETURNS boolean
    LANGUAGE "sql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.anew_users u
    JOIN public.anew_memberships m ON m.user_id = u.id
    WHERE u.auth_user_id = _auth_uid
      AND m.status = 'active'
  )
$$;


