--
-- Name: validate_product_configuration("uuid", "uuid", "jsonb", "text", "text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."validate_product_configuration"("p_product_id" "uuid", "p_organization_id" "uuid", "p_selection" "jsonb" DEFAULT '{}'::"jsonb", "p_price_context" "text" DEFAULT NULL::"text", "p_mode" "text" DEFAULT 'runtime'::"text") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_template_id uuid;
  v_mode text := COALESCE(p_mode, 'runtime');
  v_errors jsonb := '[]'::jsonb;
  v_warnings jsonb := '[]'::jsonb;
  v_struct_errors jsonb := '[]'::jsonb;
  v_struct_warnings jsonb := '[]'::jsonb;
  v_hidden_slots jsonb := '[]'::jsonb;
  v_required_slots jsonb := '[]'::jsonb;
  v_effective jsonb := '{}'::jsonb;
  r record;
  s record;
  o record;
  v_slot_ids uuid[];
  v_option_ids uuid[];
  v_active_options_per_slot jsonb := '{}'::jsonb;
  v_allow jsonb := '{}'::jsonb;   -- slot_id -> array option_ids
  v_deny jsonb := '{}'::jsonb;
  v_hidden_set uuid[] := ARRAY[]::uuid[];
  v_shown_set uuid[] := ARRAY[]::uuid[];
  v_required_set uuid[] := ARRAY[]::uuid[];
  v_eff_options uuid[];
  v_selected_option uuid;
  v_selected_qty numeric;
BEGIN
  -- Gate
  IF NOT public._configurator_can_access_product(p_product_id, p_organization_id) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  IF v_mode NOT IN ('runtime', 'template_check') THEN
    v_mode := 'runtime';
  END IF;

  -- Template ativo
  SELECT id INTO v_template_id
  FROM public.product_configuration_templates
  WHERE product_id = p_product_id
    AND organization_id = p_organization_id
    AND is_active = true
  ORDER BY version DESC
  LIMIT 1;

  IF v_template_id IS NULL THEN
    RETURN jsonb_build_object(
      'mode', v_mode,
      'valid', true,
      'errors', '[]'::jsonb,
      'warnings', '[]'::jsonb,
      'structural_errors', '[]'::jsonb,
      'structural_warnings', '[]'::jsonb,
      'effective_options_per_slot', '{}'::jsonb,
      'hidden_slots', '[]'::jsonb,
      'required_slots', '[]'::jsonb
    );
  END IF;

  -- Recolher slots e options ativos
  SELECT COALESCE(array_agg(s.id), ARRAY[]::uuid[])
  INTO v_slot_ids
  FROM public.product_config_slots s
  WHERE s.block_id IN (SELECT id FROM public.product_config_blocks WHERE template_id = v_template_id);

  -- options ativas por slot
  FOR s IN
    SELECT id FROM public.product_config_slots
    WHERE block_id IN (SELECT id FROM public.product_config_blocks WHERE template_id = v_template_id)
  LOOP
    SELECT COALESCE(jsonb_agg(o.id ORDER BY o.sort_order, o.created_at), '[]'::jsonb)
    INTO v_active_options_per_slot
    FROM public.product_config_slot_options o
    WHERE o.slot_id = s.id AND o.is_enabled = true;

    v_effective := v_effective || jsonb_build_object(s.id::text, v_active_options_per_slot);
  END LOOP;

  -- Recolher set global de option ids para validaÃ§Ã£o cruzada
  SELECT COALESCE(array_agg(id), ARRAY[]::uuid[])
  INTO v_option_ids
  FROM public.product_config_slot_options
  WHERE slot_id = ANY(v_slot_ids);

  -- Aplicar regras por ordem determinÃ­stica
  FOR r IN
    SELECT *
    FROM public.product_config_rules
    WHERE template_id = v_template_id AND is_active = true
    ORDER BY priority ASC, created_at ASC, id ASC
  LOOP
    -- regra a referenciar slot inexistente
    IF r.target_slot_id IS NOT NULL AND NOT (r.target_slot_id = ANY(v_slot_ids)) THEN
      v_struct_warnings := v_struct_warnings || jsonb_build_array(jsonb_build_object(
        'rule_id', r.id, 'code', 'rule_target_slot_missing',
        'message', 'Regra refere slot inexistente'
      ));
      CONTINUE;
    END IF;

    -- regra a referenciar opÃ§Ãµes inexistentes em target_value (para allow/deny)
    IF r.target_action IN ('allow_options', 'deny_options') AND r.target_value IS NOT NULL THEN
      DECLARE
        v_vals uuid[];
      BEGIN
        SELECT COALESCE(array_agg((v)::uuid), ARRAY[]::uuid[])
        INTO v_vals
        FROM jsonb_array_elements_text(
          CASE WHEN jsonb_typeof(r.target_value) = 'array' THEN r.target_value ELSE '[]'::jsonb END
        ) v;
        IF EXISTS (SELECT 1 FROM unnest(v_vals) x WHERE NOT (x = ANY(v_option_ids))) THEN
          v_struct_warnings := v_struct_warnings || jsonb_build_array(jsonb_build_object(
            'rule_id', r.id, 'code', 'rule_target_option_missing',
            'message', 'Regra refere opÃ§Ã£o inexistente'
          ));
        END IF;
        IF r.target_action = 'allow_options' THEN
          v_allow := v_allow || jsonb_build_object(r.target_slot_id::text,
            COALESCE(v_allow->(r.target_slot_id::text), '[]'::jsonb) || to_jsonb(v_vals));
        ELSE
          v_deny := v_deny || jsonb_build_object(r.target_slot_id::text,
            COALESCE(v_deny->(r.target_slot_id::text), '[]'::jsonb) || to_jsonb(v_vals));
        END IF;
      END;
    END IF;

    IF r.target_action = 'hide_slot' AND r.target_slot_id IS NOT NULL THEN
      v_hidden_set := array_append(v_hidden_set, r.target_slot_id);
    END IF;
    IF r.target_action = 'show_slot' AND r.target_slot_id IS NOT NULL THEN
      v_shown_set := array_append(v_shown_set, r.target_slot_id);
    END IF;
    IF r.target_action = 'require_slot' AND r.target_slot_id IS NOT NULL THEN
      v_required_set := array_append(v_required_set, r.target_slot_id);
    END IF;
  END LOOP;

  -- PrecedÃªncia: hide > show
  v_hidden_slots := COALESCE((SELECT jsonb_agg(DISTINCT x) FROM unnest(v_hidden_set) x), '[]'::jsonb);

  -- require em slot escondido â†’ warning runtime + ignorado
  IF v_mode = 'runtime' THEN
    FOR s IN SELECT unnest(v_required_set) AS sid LOOP
      IF s.sid = ANY(v_hidden_set) THEN
        v_warnings := v_warnings || jsonb_build_array(jsonb_build_object(
          'slot_id', s.sid, 'code', 'require_in_hidden_ignored',
          'message', 'require_slot ignorado porque o slot estÃ¡ escondido'
        ));
      END IF;
    END LOOP;
  END IF;

  -- required final = (slot.required OR require_set) AND NOT hidden
  SELECT COALESCE(jsonb_agg(DISTINCT s.id), '[]'::jsonb)
  INTO v_required_slots
  FROM public.product_config_slots s
  WHERE s.id = ANY(v_slot_ids)
    AND NOT (s.id = ANY(v_hidden_set))
    AND (s.required = true OR s.id = ANY(v_required_set));

  -- Aplicar allow/deny ao effective_options_per_slot (deny ganha)
  FOR s IN SELECT unnest(v_slot_ids) AS sid LOOP
    DECLARE
      v_active uuid[];
      v_allow_arr uuid[];
      v_deny_arr uuid[];
      v_final uuid[];
    BEGIN
      SELECT COALESCE(array_agg((x)::uuid), ARRAY[]::uuid[]) INTO v_active
      FROM jsonb_array_elements_text(COALESCE(v_effective->(s.sid::text), '[]'::jsonb)) x;

      SELECT COALESCE(array_agg(DISTINCT (x)::uuid), ARRAY[]::uuid[]) INTO v_allow_arr
      FROM jsonb_array_elements_text(COALESCE(v_allow->(s.sid::text), '[]'::jsonb)) x;

      SELECT COALESCE(array_agg(DISTINCT (x)::uuid), ARRAY[]::uuid[]) INTO v_deny_arr
      FROM jsonb_array_elements_text(COALESCE(v_deny->(s.sid::text), '[]'::jsonb)) x;

      IF array_length(v_allow_arr, 1) IS NOT NULL THEN
        SELECT array_agg(x) INTO v_final FROM unnest(v_active) x WHERE x = ANY(v_allow_arr);
        v_final := COALESCE(v_final, ARRAY[]::uuid[]);
      ELSE
        v_final := v_active;
      END IF;

      IF array_length(v_deny_arr, 1) IS NOT NULL THEN
        SELECT array_agg(x) INTO v_final FROM unnest(v_final) x WHERE NOT (x = ANY(v_deny_arr));
        v_final := COALESCE(v_final, ARRAY[]::uuid[]);
      END IF;

      v_effective := jsonb_set(v_effective, ARRAY[s.sid::text], COALESCE(to_jsonb(v_final), '[]'::jsonb));
    END;
  END LOOP;

  -- =============================================================
  -- TEMPLATE_CHECK estrutural (sem depender de seleÃ§Ã£o)
  -- =============================================================
  IF v_mode = 'template_check' THEN
    -- slot obrigatÃ³rio sem nenhuma opÃ§Ã£o ativa vÃ¡lida (apÃ³s allow/deny)
    FOR s IN
      SELECT id, label, required FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids)
        AND required = true
        AND slot_type IN ('attribute_value', 'component_product')
    LOOP
      DECLARE
        v_eff jsonb := COALESCE(v_effective->(s.id::text), '[]'::jsonb);
      BEGIN
        IF jsonb_array_length(v_eff) = 0 THEN
          v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
            'slot_id', s.id, 'code', 'required_slot_no_active_options',
            'message', 'Slot obrigatÃ³rio "' || s.label || '" nÃ£o tem opÃ§Ãµes ativas vÃ¡lidas'
          ));
        END IF;
      END;
    END LOOP;

    -- slot obrigatÃ³rio escondido por hide_slot
    FOR s IN
      SELECT id, label FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids)
        AND required = true
        AND id = ANY(v_hidden_set)
    LOOP
      v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
        'slot_id', s.id, 'code', 'required_slot_hidden',
        'message', 'Slot obrigatÃ³rio "' || s.label || '" estÃ¡ escondido por uma regra hide_slot'
      ));
    END LOOP;

    -- regra set_default a apontar para opÃ§Ã£o inexistente / desativada
    FOR r IN
      SELECT * FROM public.product_config_rules
      WHERE template_id = v_template_id AND is_active = true
        AND target_action = 'set_default'
        AND target_value IS NOT NULL
    LOOP
      DECLARE
        v_def_id uuid;
        v_exists boolean := false;
        v_enabled boolean := false;
      BEGIN
        BEGIN
          v_def_id := (r.target_value->>'option_id')::uuid;
        EXCEPTION WHEN OTHERS THEN
          v_def_id := NULL;
        END;
        IF v_def_id IS NULL THEN
          CONTINUE;
        END IF;
        SELECT true, is_enabled INTO v_exists, v_enabled
        FROM public.product_config_slot_options
        WHERE id = v_def_id;
        IF NOT COALESCE(v_exists, false) THEN
          v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
            'rule_id', r.id, 'code', 'default_option_missing',
            'message', 'Regra set_default aponta para opÃ§Ã£o inexistente'
          ));
        ELSIF NOT COALESCE(v_enabled, false) THEN
          v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
            'rule_id', r.id, 'code', 'default_option_disabled',
            'message', 'Regra set_default aponta para opÃ§Ã£o desativada'
          ));
        END IF;
      END;
    END LOOP;
  END IF;

  -- =============================================================
  -- RUNTIME validaÃ§Ã£o de seleÃ§Ã£o
  -- =============================================================
  IF v_mode = 'runtime' THEN
    -- obrigatÃ³rios nÃ£o preenchidos
    FOR s IN
      SELECT id, label, slot_type FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids)
        AND NOT (id = ANY(v_hidden_set))
        AND (required = true OR id = ANY(v_required_set))
    LOOP
      IF NOT (p_selection ? s.id::text) OR p_selection->(s.id::text) IS NULL
         OR jsonb_typeof(p_selection->(s.id::text)) = 'null' THEN
        v_errors := v_errors || jsonb_build_array(jsonb_build_object(
          'slot_id', s.id, 'code', 'required_missing',
          'message', 'Slot obrigatÃ³rio "' || s.label || '" nÃ£o preenchido'
        ));
      END IF;
    END LOOP;

    -- opÃ§Ãµes selecionadas tÃªm de estar em effective
    FOR s IN
      SELECT id, slot_type, label, min_quantity, max_quantity FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids) AND NOT (id = ANY(v_hidden_set))
    LOOP
      IF p_selection ? s.id::text THEN
        DECLARE
          v_sel jsonb := p_selection->(s.id::text);
          v_opt_id uuid;
          v_qty numeric;
          v_eff_arr uuid[];
        BEGIN
          SELECT COALESCE(array_agg((x)::uuid), ARRAY[]::uuid[]) INTO v_eff_arr
          FROM jsonb_array_elements_text(COALESCE(v_effective->(s.id::text), '[]'::jsonb)) x;

          IF s.slot_type IN ('attribute_value', 'component_product') THEN
            BEGIN
              v_opt_id := (v_sel->>'option_id')::uuid;
            EXCEPTION WHEN OTHERS THEN v_opt_id := NULL;
            END;
            IF v_opt_id IS NOT NULL AND NOT (v_opt_id = ANY(v_eff_arr)) THEN
              v_errors := v_errors || jsonb_build_array(jsonb_build_object(
                'slot_id', s.id, 'code', 'option_not_allowed',
                'message', 'OpÃ§Ã£o selecionada nÃ£o estÃ¡ permitida em "' || s.label || '"'
              ));
            END IF;
          END IF;

          IF s.slot_type IN ('quantity', 'measure') THEN
            BEGIN
              v_qty := (v_sel->>'quantity')::numeric;
            EXCEPTION WHEN OTHERS THEN v_qty := NULL;
            END;
            IF v_qty IS NOT NULL THEN
              IF s.min_quantity IS NOT NULL AND v_qty < s.min_quantity THEN
                v_errors := v_errors || jsonb_build_array(jsonb_build_object(
                  'slot_id', s.id, 'code', 'qty_below_min',
                  'message', 'Quantidade abaixo do mÃ­nimo em "' || s.label || '"'
                ));
              END IF;
              IF s.max_quantity IS NOT NULL AND v_qty > s.max_quantity THEN
                v_errors := v_errors || jsonb_build_array(jsonb_build_object(
                  'slot_id', s.id, 'code', 'qty_above_max',
                  'message', 'Quantidade acima do mÃ¡ximo em "' || s.label || '"'
                ));
              END IF;
            END IF;
          END IF;
        END;
      END IF;
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'mode', v_mode,
    'valid', (jsonb_array_length(v_errors) = 0 AND jsonb_array_length(v_struct_errors) = 0),
    'errors', CASE WHEN v_mode = 'runtime' THEN v_errors ELSE '[]'::jsonb END,
    'warnings', CASE WHEN v_mode = 'runtime' THEN v_warnings ELSE '[]'::jsonb END,
    'structural_errors', CASE WHEN v_mode = 'template_check' THEN v_struct_errors ELSE '[]'::jsonb END,
    'structural_warnings', CASE WHEN v_mode = 'template_check' THEN v_struct_warnings ELSE '[]'::jsonb END,
    'effective_options_per_slot', v_effective,
    'hidden_slots', v_hidden_slots,
    'required_slots', v_required_slots
  );
END;
$$;


--
-- Name: validate_product_configuration("uuid", "uuid", "jsonb", "text", "text", "uuid"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."validate_product_configuration"("p_product_id" "uuid", "p_organization_id" "uuid", "p_selection" "jsonb" DEFAULT '{}'::"jsonb", "p_price_context" "text" DEFAULT NULL::"text", "p_mode" "text" DEFAULT 'runtime'::"text", "p_template_id" "uuid" DEFAULT NULL::"uuid") RETURNS "jsonb"
    LANGUAGE "plpgsql" STABLE SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_template_id uuid;
  v_mode text := COALESCE(p_mode, 'runtime');
  v_errors jsonb := '[]'::jsonb;
  v_warnings jsonb := '[]'::jsonb;
  v_struct_errors jsonb := '[]'::jsonb;
  v_struct_warnings jsonb := '[]'::jsonb;
  v_hidden_slots jsonb := '[]'::jsonb;
  v_required_slots jsonb := '[]'::jsonb;
  v_effective jsonb := '{}'::jsonb;
  r record;
  s record;
  o record;
  v_slot_ids uuid[];
  v_option_ids uuid[];
  v_active_options_per_slot jsonb := '{}'::jsonb;
  v_allow jsonb := '{}'::jsonb;
  v_deny jsonb := '{}'::jsonb;
  v_hidden_set uuid[] := ARRAY[]::uuid[];
  v_shown_set uuid[] := ARRAY[]::uuid[];
  v_required_set uuid[] := ARRAY[]::uuid[];
  v_eff_options uuid[];
  v_selected_option uuid;
  v_selected_qty numeric;
BEGIN
  -- Gate
  IF NOT public._configurator_can_access_product(p_product_id, p_organization_id) THEN
    RETURN jsonb_build_object('error', 'forbidden');
  END IF;

  IF v_mode NOT IN ('runtime', 'template_check') THEN
    v_mode := 'runtime';
  END IF;

  -- Template: especÃ­fico (Lab) ou ativo (default)
  IF p_template_id IS NOT NULL THEN
    SELECT id INTO v_template_id
    FROM public.product_configuration_templates
    WHERE id = p_template_id
      AND product_id = p_product_id
      AND organization_id = p_organization_id
    LIMIT 1;

    IF v_template_id IS NULL THEN
      RETURN jsonb_build_object('error', 'invalid_template_for_product');
    END IF;
  ELSE
    SELECT id INTO v_template_id
    FROM public.product_configuration_templates
    WHERE product_id = p_product_id
      AND organization_id = p_organization_id
      AND is_active = true
    ORDER BY version DESC
    LIMIT 1;
  END IF;

  IF v_template_id IS NULL THEN
    RETURN jsonb_build_object(
      'mode', v_mode,
      'valid', true,
      'errors', '[]'::jsonb,
      'warnings', '[]'::jsonb,
      'structural_errors', '[]'::jsonb,
      'structural_warnings', '[]'::jsonb,
      'effective_options_per_slot', '{}'::jsonb,
      'hidden_slots', '[]'::jsonb,
      'required_slots', '[]'::jsonb
    );
  END IF;

  -- Recolher slots e options ativos
  SELECT COALESCE(array_agg(s.id), ARRAY[]::uuid[])
  INTO v_slot_ids
  FROM public.product_config_slots s
  WHERE s.block_id IN (SELECT id FROM public.product_config_blocks WHERE template_id = v_template_id);

  -- options ativas por slot
  FOR s IN
    SELECT id FROM public.product_config_slots
    WHERE block_id IN (SELECT id FROM public.product_config_blocks WHERE template_id = v_template_id)
  LOOP
    SELECT COALESCE(jsonb_agg(o.id ORDER BY o.sort_order, o.created_at), '[]'::jsonb)
    INTO v_active_options_per_slot
    FROM public.product_config_slot_options o
    WHERE o.slot_id = s.id AND o.is_enabled = true;

    v_effective := v_effective || jsonb_build_object(s.id::text, v_active_options_per_slot);
  END LOOP;

  -- Recolher set global de option ids para validaÃ§Ã£o cruzada
  SELECT COALESCE(array_agg(id), ARRAY[]::uuid[])
  INTO v_option_ids
  FROM public.product_config_slot_options
  WHERE slot_id = ANY(v_slot_ids);

  -- Aplicar regras por ordem determinÃ­stica
  FOR r IN
    SELECT *
    FROM public.product_config_rules
    WHERE template_id = v_template_id AND is_active = true
    ORDER BY priority ASC, created_at ASC, id ASC
  LOOP
    IF r.target_slot_id IS NOT NULL AND NOT (r.target_slot_id = ANY(v_slot_ids)) THEN
      v_struct_warnings := v_struct_warnings || jsonb_build_array(jsonb_build_object(
        'rule_id', r.id, 'code', 'rule_target_slot_missing',
        'message', 'Regra refere slot inexistente'
      ));
      CONTINUE;
    END IF;

    IF r.target_action IN ('allow_options', 'deny_options') AND r.target_value IS NOT NULL THEN
      DECLARE
        v_vals uuid[];
      BEGIN
        SELECT COALESCE(array_agg((v)::uuid), ARRAY[]::uuid[])
        INTO v_vals
        FROM jsonb_array_elements_text(
          CASE WHEN jsonb_typeof(r.target_value) = 'array' THEN r.target_value ELSE '[]'::jsonb END
        ) v;
        IF EXISTS (SELECT 1 FROM unnest(v_vals) x WHERE NOT (x = ANY(v_option_ids))) THEN
          v_struct_warnings := v_struct_warnings || jsonb_build_array(jsonb_build_object(
            'rule_id', r.id, 'code', 'rule_target_option_missing',
            'message', 'Regra refere opÃ§Ã£o inexistente'
          ));
        END IF;
        IF r.target_action = 'allow_options' THEN
          v_allow := v_allow || jsonb_build_object(r.target_slot_id::text,
            COALESCE(v_allow->(r.target_slot_id::text), '[]'::jsonb) || to_jsonb(v_vals));
        ELSE
          v_deny := v_deny || jsonb_build_object(r.target_slot_id::text,
            COALESCE(v_deny->(r.target_slot_id::text), '[]'::jsonb) || to_jsonb(v_vals));
        END IF;
      END;
    END IF;

    IF r.target_action = 'hide_slot' AND r.target_slot_id IS NOT NULL THEN
      v_hidden_set := array_append(v_hidden_set, r.target_slot_id);
    END IF;
    IF r.target_action = 'show_slot' AND r.target_slot_id IS NOT NULL THEN
      v_shown_set := array_append(v_shown_set, r.target_slot_id);
    END IF;
    IF r.target_action = 'require_slot' AND r.target_slot_id IS NOT NULL THEN
      v_required_set := array_append(v_required_set, r.target_slot_id);
    END IF;
  END LOOP;

  v_hidden_slots := COALESCE((SELECT jsonb_agg(DISTINCT x) FROM unnest(v_hidden_set) x), '[]'::jsonb);

  IF v_mode = 'runtime' THEN
    FOR s IN SELECT unnest(v_required_set) AS sid LOOP
      IF s.sid = ANY(v_hidden_set) THEN
        v_warnings := v_warnings || jsonb_build_array(jsonb_build_object(
          'slot_id', s.sid, 'code', 'require_in_hidden_ignored',
          'message', 'require_slot ignorado porque o slot estÃ¡ escondido'
        ));
      END IF;
    END LOOP;
  END IF;

  SELECT COALESCE(jsonb_agg(DISTINCT s.id), '[]'::jsonb)
  INTO v_required_slots
  FROM public.product_config_slots s
  WHERE s.id = ANY(v_slot_ids)
    AND NOT (s.id = ANY(v_hidden_set))
    AND (s.required = true OR s.id = ANY(v_required_set));

  FOR s IN SELECT unnest(v_slot_ids) AS sid LOOP
    DECLARE
      v_active uuid[];
      v_allow_arr uuid[];
      v_deny_arr uuid[];
      v_final uuid[];
    BEGIN
      SELECT COALESCE(array_agg((x)::uuid), ARRAY[]::uuid[]) INTO v_active
      FROM jsonb_array_elements_text(COALESCE(v_effective->(s.sid::text), '[]'::jsonb)) x;

      SELECT COALESCE(array_agg(DISTINCT (x)::uuid), ARRAY[]::uuid[]) INTO v_allow_arr
      FROM jsonb_array_elements_text(COALESCE(v_allow->(s.sid::text), '[]'::jsonb)) x;

      SELECT COALESCE(array_agg(DISTINCT (x)::uuid), ARRAY[]::uuid[]) INTO v_deny_arr
      FROM jsonb_array_elements_text(COALESCE(v_deny->(s.sid::text), '[]'::jsonb)) x;

      IF array_length(v_allow_arr, 1) IS NOT NULL THEN
        SELECT array_agg(x) INTO v_final FROM unnest(v_active) x WHERE x = ANY(v_allow_arr);
        v_final := COALESCE(v_final, ARRAY[]::uuid[]);
      ELSE
        v_final := v_active;
      END IF;

      IF array_length(v_deny_arr, 1) IS NOT NULL THEN
        SELECT array_agg(x) INTO v_final FROM unnest(v_final) x WHERE NOT (x = ANY(v_deny_arr));
        v_final := COALESCE(v_final, ARRAY[]::uuid[]);
      END IF;

      v_effective := jsonb_set(v_effective, ARRAY[s.sid::text], COALESCE(to_jsonb(v_final), '[]'::jsonb));
    END;
  END LOOP;

  IF v_mode = 'template_check' THEN
    FOR s IN
      SELECT id, label, required FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids)
        AND required = true
        AND slot_type IN ('attribute_value', 'component_product')
    LOOP
      DECLARE
        v_eff jsonb := COALESCE(v_effective->(s.id::text), '[]'::jsonb);
      BEGIN
        IF jsonb_array_length(v_eff) = 0 THEN
          v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
            'slot_id', s.id, 'code', 'required_slot_no_active_options',
            'message', 'Slot obrigatÃ³rio "' || s.label || '" nÃ£o tem opÃ§Ãµes ativas vÃ¡lidas'
          ));
        END IF;
      END;
    END LOOP;

    FOR s IN
      SELECT id, label FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids)
        AND required = true
        AND id = ANY(v_hidden_set)
    LOOP
      v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
        'slot_id', s.id, 'code', 'required_slot_hidden',
        'message', 'Slot obrigatÃ³rio "' || s.label || '" estÃ¡ escondido por uma regra hide_slot'
      ));
    END LOOP;

    FOR r IN
      SELECT * FROM public.product_config_rules
      WHERE template_id = v_template_id AND is_active = true
        AND target_action = 'set_default'
        AND target_value IS NOT NULL
    LOOP
      DECLARE
        v_def_id uuid;
        v_exists boolean := false;
        v_enabled boolean := false;
      BEGIN
        BEGIN
          v_def_id := (r.target_value->>'option_id')::uuid;
        EXCEPTION WHEN OTHERS THEN
          v_def_id := NULL;
        END;
        IF v_def_id IS NULL THEN
          CONTINUE;
        END IF;
        SELECT true, is_enabled INTO v_exists, v_enabled
        FROM public.product_config_slot_options
        WHERE id = v_def_id;
        IF NOT COALESCE(v_exists, false) THEN
          v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
            'rule_id', r.id, 'code', 'default_option_missing',
            'message', 'Regra set_default aponta para opÃ§Ã£o inexistente'
          ));
        ELSIF NOT COALESCE(v_enabled, false) THEN
          v_struct_errors := v_struct_errors || jsonb_build_array(jsonb_build_object(
            'rule_id', r.id, 'code', 'default_option_disabled',
            'message', 'Regra set_default aponta para opÃ§Ã£o desativada'
          ));
        END IF;
      END;
    END LOOP;
  END IF;

  IF v_mode = 'runtime' THEN
    FOR s IN
      SELECT id, label, slot_type FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids)
        AND NOT (id = ANY(v_hidden_set))
        AND (required = true OR id = ANY(v_required_set))
    LOOP
      IF NOT (p_selection ? s.id::text) OR p_selection->(s.id::text) IS NULL
         OR jsonb_typeof(p_selection->(s.id::text)) = 'null' THEN
        v_errors := v_errors || jsonb_build_array(jsonb_build_object(
          'slot_id', s.id, 'code', 'required_missing',
          'message', 'Slot obrigatÃ³rio "' || s.label || '" nÃ£o preenchido'
        ));
      END IF;
    END LOOP;

    FOR s IN
      SELECT id, slot_type, label, min_quantity, max_quantity FROM public.product_config_slots
      WHERE id = ANY(v_slot_ids) AND NOT (id = ANY(v_hidden_set))
    LOOP
      IF p_selection ? s.id::text THEN
        DECLARE
          v_sel jsonb := p_selection->(s.id::text);
          v_opt_id uuid;
          v_qty numeric;
          v_eff_arr uuid[];
        BEGIN
          SELECT COALESCE(array_agg((x)::uuid), ARRAY[]::uuid[]) INTO v_eff_arr
          FROM jsonb_array_elements_text(COALESCE(v_effective->(s.id::text), '[]'::jsonb)) x;

          IF s.slot_type IN ('attribute_value', 'component_product') THEN
            BEGIN
              v_opt_id := (v_sel->>'option_id')::uuid;
            EXCEPTION WHEN OTHERS THEN v_opt_id := NULL;
            END;
            IF v_opt_id IS NOT NULL AND NOT (v_opt_id = ANY(v_eff_arr)) THEN
              v_errors := v_errors || jsonb_build_array(jsonb_build_object(
                'slot_id', s.id, 'code', 'option_not_allowed',
                'message', 'OpÃ§Ã£o selecionada nÃ£o estÃ¡ permitida em "' || s.label || '"'
              ));
            END IF;
          END IF;

          IF s.slot_type IN ('quantity', 'measure') THEN
            BEGIN
              v_qty := (v_sel->>'quantity')::numeric;
            EXCEPTION WHEN OTHERS THEN v_qty := NULL;
            END;
            IF v_qty IS NOT NULL THEN
              IF s.min_quantity IS NOT NULL AND v_qty < s.min_quantity THEN
                v_errors := v_errors || jsonb_build_array(jsonb_build_object(
                  'slot_id', s.id, 'code', 'qty_below_min',
                  'message', 'Quantidade abaixo do mÃ­nimo em "' || s.label || '"'
                ));
              END IF;
              IF s.max_quantity IS NOT NULL AND v_qty > s.max_quantity THEN
                v_errors := v_errors || jsonb_build_array(jsonb_build_object(
                  'slot_id', s.id, 'code', 'qty_above_max',
                  'message', 'Quantidade acima do mÃ¡ximo em "' || s.label || '"'
                ));
              END IF;
            END IF;
          END IF;
        END;
      END IF;
    END LOOP;
  END IF;

  RETURN jsonb_build_object(
    'mode', v_mode,
    'valid', (jsonb_array_length(v_errors) = 0 AND jsonb_array_length(v_struct_errors) = 0),
    'errors', CASE WHEN v_mode = 'runtime' THEN v_errors ELSE '[]'::jsonb END,
    'warnings', CASE WHEN v_mode = 'runtime' THEN v_warnings ELSE '[]'::jsonb END,
    'structural_errors', CASE WHEN v_mode = 'template_check' THEN v_struct_errors ELSE '[]'::jsonb END,
    'structural_warnings', CASE WHEN v_mode = 'template_check' THEN v_struct_warnings ELSE '[]'::jsonb END,
    'effective_options_per_slot', v_effective,
    'hidden_slots', v_hidden_slots,
    'required_slots', v_required_slots
  );
END;
$$;


--
-- Name: validate_scoped_api_token("text"); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."validate_scoped_api_token"("_token_key" "text") RETURNS TABLE("token_id" "uuid", "organization_id" "uuid", "business_area_id" "uuid", "scopes" "text"[])
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
BEGIN
  UPDATE scoped_api_tokens
  SET last_used_at = now(), usage_count = usage_count + 1
  WHERE token_key = _token_key AND is_active = true AND (expires_at IS NULL OR expires_at > now());

  RETURN QUERY
  SELECT sat.id, sat.organization_id, sat.business_area_id, sat.scopes
  FROM scoped_api_tokens sat
  WHERE sat.token_key = _token_key
    AND sat.is_active = true
    AND (sat.expires_at IS NULL OR sat.expires_at > now());
END;
$$;


--
-- Name: validate_user_role_not_template(); Type: FUNCTION; Schema: public; Owner: -
--

CREATE FUNCTION "public"."validate_user_role_not_template"() RETURNS "trigger"
    LANGUAGE "plpgsql" SECURITY DEFINER
    SET "search_path" TO 'public'
    AS $$
DECLARE
  v_role roles%ROWTYPE;
BEGIN
  SELECT * INTO v_role FROM roles WHERE id = NEW.role_id;
  
  IF NOT FOUND THEN
    RAISE EXCEPTION 'Role nÃ£o encontrado';
  END IF;
  
  -- Templates nÃ£o podem ser atribuÃ­dos directamente
  IF v_role.is_template THEN
    RAISE EXCEPTION 'NÃ£o Ã© possÃ­vel atribuir um template de role directamente. Use um role de empresa ou tenant.';
  END IF;
  
  -- SystemAdmin global role (no empresa_id, no tenant_id) is allowed
  IF v_role.nome = 'SystemAdmin' AND v_role.empresa_id IS NULL THEN
    RETURN NEW;
  END IF;
  
  -- TenantAdmin with tenant_id (no empresa_id) is allowed
  IF v_role.nome = 'TenantAdmin' AND v_role.tenant_id IS NOT NULL AND v_role.empresa_id IS NULL THEN
    RETURN NEW;
  END IF;
  
  -- All other roles must have empresa_id
  IF v_role.empresa_id IS NULL THEN
    RAISE EXCEPTION 'Apenas roles de empresa podem ser atribuÃ­dos (excepto SystemAdmin e TenantAdmin com tenant_id).';
  END IF;
  
  RETURN NEW;
END;
$$;


