--
-- Name: channel_spend_entries; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE "public"."channel_spend_entries" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "channel_id" "uuid" NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "amount" numeric DEFAULT 0 NOT NULL,
    "currency" "text" DEFAULT 'EUR'::"text" NOT NULL,
    "entry_type" "text" DEFAULT 'one_time'::"text" NOT NULL,
    "interval_count" integer,
    "interval_unit" "text",
    "starts_on" "date" DEFAULT CURRENT_DATE NOT NULL,
    "ends_on" "date",
    "source" "text" DEFAULT 'manual'::"text" NOT NULL,
    "external_ref" "text",
    "notes" "text",
    "created_by" "uuid",
    CONSTRAINT "channel_spend_entries_amount_check" CHECK (("amount" >= (0)::numeric)),
    CONSTRAINT "channel_spend_entries_cadence_check" CHECK (((("entry_type" = 'one_time'::"text") AND ("interval_count" IS NULL) AND ("interval_unit" IS NULL) AND ("ends_on" IS NULL)) OR (("entry_type" = 'recurring'::"text") AND ("interval_count" IS NOT NULL) AND ("interval_unit" IS NOT NULL)))),
    CONSTRAINT "channel_spend_entries_entry_type_check" CHECK (("entry_type" = ANY (ARRAY['one_time'::"text", 'recurring'::"text"]))),
    CONSTRAINT "channel_spend_entries_interval_count_check" CHECK ((("interval_count" IS NULL) OR ("interval_count" > 0))),
    CONSTRAINT "channel_spend_entries_interval_unit_check" CHECK ((("interval_unit" IS NULL) OR ("interval_unit" = ANY (ARRAY['day'::"text", 'week'::"text", 'month'::"text"]))))
);


