    "proposal_id" "uuid",
    "request_date" timestamp with time zone,
    "delivered_at" timestamp with time zone,
    "delivery_time_hours" numeric GENERATED ALWAYS AS (
CASE
    WHEN (("delivered_at" IS NOT NULL) AND ("request_date" IS NOT NULL)) THEN (EXTRACT(epoch FROM ("delivered_at" - "request_date")) / (3600)::numeric)
    ELSE NULL::numeric
END) STORED,
    "deal_id" "uuid",
    "organization_id" "uuid",
    "entity_id" "uuid",
