CREATE TABLE "public"."service_fee_types" (
    "id" "uuid" DEFAULT "gen_random_uuid"() NOT NULL,
    "name" "text" NOT NULL,
    "description" "text",
    "calculation_type" "text" NOT NULL,
    "percentage" numeric(5,2),
    "fixed_amount" numeric(12,2),
    "is_active" boolean DEFAULT true NOT NULL,
    "created_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "created_by" "uuid" NOT NULL,
    "updated_at" timestamp with time zone DEFAULT "now"() NOT NULL,
    "organization_id" "uuid",
    "service_id" "uuid",
    "application_mode" "text" DEFAULT 'SUBTOTAL'::"text" NOT NULL,
    "apply_vat" boolean DEFAULT true NOT NULL,
    "vat_rate" numeric DEFAULT 23 NOT NULL,
    CONSTRAINT "calculation_data_check" CHECK (((("calculation_type" = 'PERCENTAGE'::"text") AND ("percentage" IS NOT NULL) AND ("fixed_amount" IS NULL)) OR (("calculation_type" = 'FIXED'::"text") AND ("fixed_amount" IS NOT NULL) AND ("percentage" IS NULL)))),
    CONSTRAINT "service_fee_types_application_mode_check" CHECK (("application_mode" = ANY (ARRAY['SUBTOTAL'::"text", 'LINE_PERCENTAGE'::"text"]))),
    CONSTRAINT "service_fee_types_calculation_type_check" CHECK (("calculation_type" = ANY (ARRAY['PERCENTAGE'::"text", 'FIXED'::"text"]))),
    CONSTRAINT "valid_fixed_amount" CHECK ((("fixed_amount" IS NULL) OR ("fixed_amount" >= (0)::numeric))),
    CONSTRAINT "valid_percentage" CHECK ((("percentage" IS NULL) OR (("percentage" >= (0)::numeric) AND ("percentage" <= (100)::numeric))))
);


