--
-- Name: v_channel_lead_facts; Type: VIEW; Schema: public; Owner: -
--

CREATE VIEW "public"."v_channel_lead_facts" WITH ("security_invoker"='true') AS
 WITH "dedup" AS (
         SELECT "cl"."channel_id",
            "cl"."campaign_id",
            COALESCE("cl"."anew_lead_id", "cl"."id") AS "lead_key",
            "cl"."anew_lead_id",
            "cl"."created_at" AS "touch_date",
            "cl"."source",
            "cl"."medium",
            "al"."converted_to_client_id",
            "al"."status" AS "lead_status",
            "row_number"() OVER (PARTITION BY COALESCE("cl"."anew_lead_id", "cl"."id"), "cl"."channel_id" ORDER BY "cl"."created_at" DESC, "cl"."id" DESC) AS "rn"
           FROM ("public"."campaign_leads" "cl"
             LEFT JOIN "public"."anew_leads" "al" ON (("al"."id" = "cl"."anew_lead_id")))
          WHERE ("cl"."channel_id" IS NOT NULL)
        )
 SELECT "channel_id",
    "campaign_id",
    "lead_key",
    "anew_lead_id",
    "touch_date",
    "source",
    "medium",
    ("converted_to_client_id" IS NOT NULL) AS "is_converted",
    "converted_to_client_id",
    "lead_status"
   FROM "dedup"
  WHERE ("rn" = 1);


