--
-- Name: notifications Active members can insert notifications; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Active members can insert notifications" ON "public"."notifications" FOR INSERT TO "authenticated" WITH CHECK ((EXISTS ( SELECT 1
   FROM ("public"."anew_memberships" "m"
     JOIN "public"."anew_users" "u" ON (("u"."id" = "m"."user_id")))
  WHERE (("u"."auth_user_id" = "auth"."uid"()) AND ("m"."status" = 'active'::"text")))));


--
-- Name: api_keys Admins can manage API keys; Type: POLICY; Schema: public; Owner: -
--

CREATE POLICY "Admins can manage API keys" ON "public"."api_keys" TO "authenticated" USING ((("organization_id" IN ( SELECT "m"."organization_id"
   FROM ("public"."anew_memberships" "m"
     JOIN "public"."anew_users" "u" ON (("u"."id" = "m"."user_id")))
  WHERE (("u"."auth_user_id" = "auth"."uid"()) AND ("m"."status" = 'active'::"text")))) AND "public"."has_anew_permission"("auth"."uid"(), 'settings.manage'::"text"))) WITH CHECK ((("organization_id" IN ( SELECT "m"."organization_id"
   FROM ("public"."anew_memberships" "m"
     JOIN "public"."anew_users" "u" ON (("u"."id" = "m"."user_id")))
  WHERE (("u"."auth_user_id" = "auth"."uid"()) AND ("m"."status" = 'active'::"text")))) AND "public"."has_anew_permission"("auth"."uid"(), 'settings.manage'::"text")));


